const auditData = [{"q": "What is the primary purpose of conducting an audit of financial statements?", "options": ["To detect all frauds and errors.", "To prepare the financial statements for the company.", "To enhance the confidence of intended users (e.g., banks, shareholders).", "To guarantee the future viability of the entity."], "ans": 2, "exp": "The purpose of an audit is to enhance the confidence of users like banks and investors so they can trust the financial statements."}, {"q": "A company holds inventory in a third-party warehouse. The auditor verifies the inventory exists but fails to verify if the company actually owns it. Which assertion is at risk?", "options": ["Existence", "Rights and Obligations", "Valuation", "Completeness"], "ans": 1, "exp": "Existence and Rights are two different things. An asset may physically exist (e.g., in a warehouse), but the company might not have the ownership rights."}, {"q": "In the audit of PTCL\u2019s submarine cables, why does the auditor not perform a physical count?", "options": ["It is too expensive.", "The cables are intangible assets.", "Verification is done using system reports (IDN) or insurance contracts.", "Management's written representation is sufficient."], "ans": 2, "exp": "Auditors use techniques like reviewing system reports (IDN) or insurance contracts because physical verification of submarine cables is not feasible."}, {"q": "Management claims inventory is worth Rs. 100, but the auditor finds it is damaged and worth only Rs. 50. This is a risk related to which assertion?", "options": ["Rights and Obligations", "Completeness", "Existence", "Valuation"], "ans": 3, "exp": "Valuation ensures the asset is recorded at the correct value. If inventory is overstated compared to its actual worth, it is a valuation misstatement."}, {"q": "Which of the following is considered the most reliable form of audit evidence for verifying a receivable balance?", "options": ["Sales invoice generated by the client.", "Gate pass generated by the warehouse.", "External confirmation received directly from the customer.", "Management representation letter."], "ans": 2, "exp": "External confirmation is highly reliable evidence because it comes from an independent third party."}, {"q": "An auditor observes that a telecom company is depreciating its 4G towers over 10 years, despite news that 5G will roll out in 2 years. What is the primary audit risk?", "options": ["Understatement of Assets.", "Overstatement of Depreciation Expense.", "Overstatement of Assets and Understatement of Depreciation.", "Misappropriation of cash."], "ans": 2, "exp": "If 4G equipment becomes obsolete due to 5G, the useful life should be revised downwards. Using a longer life overstates the asset value and understates the depreciation expense."}, {"q": "In a highly regulated industry like Pharmaceuticals, if a company fails to record a penalty from DRAP, which assertion is primarily violated?", "options": ["Existence of Assets.", "Completeness of Liabilities/Expenses.", "Rights to sell drugs.", "Presentation of Equity."], "ans": 1, "exp": "The risk is that the company conceals the penalty, leading to an understatement (incompleteness) of expenses and liabilities."}, {"q": "When assessing contingent liabilities regarding a legal penalty, when should the amount be recorded as an expense?", "options": ["When management says they might lose.", "When the lawyer says there is a >50% chance of losing.", "When the lawyer says there is a <50% chance of losing.", "When the penalty notice is first received."], "ans": 1, "exp": "If there is a greater than 50% chance of losing the case based on legal opinion, it must be recorded as an expense/liability. Otherwise, it is only disclosed."}, {"q": "An auditor notices that Inventory Days have increased from 25 to 58 days while sales have slowed. What does this indicate?", "options": ["The company is stocking up for a massive sale.", "Inventory is moving fast.", "Risk of inventory obsolescence or damage.", "Understatement of inventory."], "ans": 2, "exp": "A significant increase in inventory days indicates stock is not selling, raising the risk that the inventory is obsolete, damaged, or overstated."}, {"q": "If a company operates in a flood-affected area, what is the specific impact on the \"Receivables\" account?", "options": ["Receivables will definitely be paid early.", "Receivables may be overstated due to doubtful recoverability.", "Receivables will be converted to bad debts immediately.", "No impact on receivables."], "ans": 1, "exp": "Floods affect the customers' ability to pay, creating a risk that receivables are not recoverable (overstated) and provision for bad debts is understated."}, {"q": "An export company records a sale using the average exchange rate for the year. The auditor flags this because:", "options": ["Average rates are never allowed.", "Sales should be recorded at the spot rate on the transaction date.", "Sales should be recorded at the year-end rate.", "It creates a tax liability."], "ans": 1, "exp": "Transactions should be recorded at the exchange rate prevailing on the date of the transaction. Using an average rate when rates fluctuate is incorrect."}, {"q": "According to IAS 38, which phase of internal project costs must always be expensed?", "options": ["Development Phase.", "Research Phase.", "Testing Phase.", "Pilot Production Phase."], "ans": 1, "exp": "Research costs are always expensed because the result is uncertain. Development costs can be capitalized only if specific criteria are met."}, {"q": "A company has a Foreign Currency bank account. At year-end, the PKR has depreciated against the USD. How should this be treated?", "options": ["No change required.", "The bank balance should be revalued, and an FX gain recorded.", "The bank balance should be revalued, and an FX loss recorded.", "It should be treated as a contingent asset."], "ans": 1, "exp": "If the reporting currency (PKR) depreciates, the value of the USD held in the bank increases in PKR terms, resulting in an exchange gain."}, {"q": "A company has shown negative operating cash flows for three consecutive years. This is a primary indicator of:", "options": ["High profitability.", "Impairment of Assets (PPE).", "Efficient tax planning.", "Successful R&D."], "ans": 1, "exp": "Continuous negative cash flows from operations are a strong internal indicator that the PPE is not generating recoverable cash and may be impaired."}, {"q": "If a company is assessed as \"Not a Going Concern,\" how should the financial statements be prepared?", "options": ["Historical Cost basis.", "Break-up / Liquidation basis (NRV).", "Fair Value through OCI.", "Amortized Cost basis."], "ans": 1, "exp": "If the going concern assumption fails, assets must be valued at what they would fetch in liquidation (NRV) and non-current assets are classified as current."}, {"q": "Who is primarily responsible for assessing the company's ability to continue as a going concern?", "options": ["The External Auditor.", "The Government.", "The Management.", "The Shareholders."], "ans": 2, "exp": "Management is responsible for making the assessment. The auditor's role is to evaluate management's assessment."}, {"q": "In the PIBTL case, the company breached a debt covenant (Interest Cover Ratio). What is the immediate audit risk?", "options": ["The bank may seize assets or demand immediate repayment, threatening Going Concern.", "The company will have to pay less interest.", "The auditor must resign immediately.", "Inventory will be impaired."], "ans": 0, "exp": "Breaching a debt covenant allows the bank to trigger default clauses, which can lead to asset seizure and threaten the company's survival (Going Concern risk)."}, {"q": "Management increases the price of toys by 15%, but revenue increases by 50% in a competitive market. What should the auditor suspect?", "options": ["The product is viral.", "Risk of fake revenue recording.", "Understatement of expenses.", "Efficient marketing."], "ans": 1, "exp": "An unusual spike in revenue that contradicts economic logic (price up usually means quantity down or stable) suggests the risk of inflated or fake sales."}, {"q": "Why might a retail company with high cash sales (like Khaadi) be a high-risk audit client?", "options": ["Cash is difficult to count.", "Cash is susceptible to misappropriation/theft before being deposited.", "Retail companies do not maintain ledgers.", "Banks do not accept cash deposits."], "ans": 1, "exp": "High cash volumes create a risk that cash is stolen (misappropriated) before it is recorded or deposited, affecting the existence assertion."}, {"q": "A company has a control where a credit limit is set for customers. However, the Sales Director can override this limit to meet targets. What type of issue is this?", "options": ["The control is missing.", "The control design is ineffective due to conflict of interest.", "The control is perfect.", "The control is automated."], "ans": 1, "exp": "Even if the control exists, allowing a person with a conflict of interest (Sales Director wanting higher sales) to override it makes the design ineffective."}, {"q": "An auditor visits a warehouse and sees expired goods mixed with fresh stock. Which assertions are at risk?", "options": ["Rights & Obligations.", "Existence & Valuation.", "Completeness & Rights.", "Presentation & Disclosure."], "ans": 1, "exp": "Poor inventory management (mixing stock) raises risks about whether good inventory actually exists as recorded and whether it is valued correctly (NRV issues)."}, {"q": "\"Channel Stuffing\" refers to:", "options": ["Packing more goods into a shipping container.", "Recording sales for orders booked early without actual delivery/need.", "Selling goods at a discount.", "Writing off bad debts."], "ans": 1, "exp": "Channel stuffing involves booking revenue for orders that are not yet delivered or are pushed onto customers to meet targets, indicating fake revenue risk."}, {"q": "What is the main purpose of a \"Receivable Aging Report\" for an auditor?", "options": ["To check the names of customers.", "To calculate the total sales.", "To identify old balances that may not be recoverable (Bad Debt Risk).", "To verify the bank balance."], "ans": 2, "exp": "Aging reports help categorize receivables by time overdue, highlighting old balances that are risky and may need provisioning."}, {"q": "An auditor performs a \"Cut-off Test\" for sales. What are they checking?", "options": ["That sales are recorded in the correct accounting period.", "That sales are profitable.", "That the customer has paid cash.", "That the inventory count is correct."], "ans": 0, "exp": "Cut-off testing ensures that transactions occurring near year-end are recorded in the correct financial year."}, {"q": "When auditing a telecom company selling prepaid cards, when should revenue be recognized?", "options": ["When the card is printed.", "When the card is sold to the customer.", "When the customer uses the balance (Performance Obligation fulfilled).", "When the cash is deposited in the bank."], "ans": 2, "exp": "Revenue is recognized only when the performance obligation is satisfied (i.e., the customer uses the service), not just when the cash is received."}, {"q": "Why would an auditor request a \"Legal Confirmation Letter\" from the client's lawyer?", "options": ["To check the lawyer's fees.", "To identify unrecorded litigation and assess the outcome of pending cases.", "To confirm the company's incorporation date.", "To verify the bank balance."], "ans": 1, "exp": "Legal confirmations help the auditor identify completeness of liabilities regarding lawsuits and assess the probability of penalties."}, {"q": "Analytical procedures involve analyzing relationships between:", "options": ["Only financial data.", "Only non-financial data.", "Both financial and non-financial data.", "Only bank statements."], "ans": 2, "exp": "Analytical procedures analyze plausible relationships among both financial (e.g., sales $) and non-financial data (e.g., number of employees, units sold)."}, {"q": "Sales have increased by 20%, but the commission expense has decreased by 10%. What does this suggest?", "options": ["The sales team is working for free.", "Understatement of commission expense.", "Overstatement of commission expense.", "The company changed its bank."], "ans": 1, "exp": "Logically, commission is a % of sales. If sales go up, commission should go up. A decrease suggests the expense is understated or policies changed without documentation."}, {"q": "A company hired 800 new employees, but the payroll expense remained flat. What is the risk?", "options": ["Employees are volunteers.", "Payroll expense is overstated.", "Risk of \"Ghost Employees\" or unrecorded payroll expense.", "Efficient HR management."], "ans": 2, "exp": "A mismatch between hiring data (non-financial) and payroll expense (financial) suggests fake employees or understatement of expenses."}, {"q": "An auditor sees 800 laptops capitalized on Dec 28th. What procedure should be performed to verify the capitalization date?", "options": ["Check the purchase order only.", "Verify Gate Pass, Vendor Delivery Note, and Employee Acknowledgement.", "Ask the CFO.", "Depreciation calculation check."], "ans": 1, "exp": "To ensure the asset was actually available for use on that date (and not just booked to start depreciation early/late), the auditor verifies physical delivery and receipt documents."}, {"q": "If a company capitalizes an asset that is still in the warehouse and not issued for use, what is the impact?", "options": ["Depreciation is understated.", "Depreciation is overstated (charged too early).", "Inventory is overstated.", "No impact."], "ans": 1, "exp": "Depreciation should only begin when the asset is available for use. Capitalizing unissued inventory leads to early depreciation and incorrect asset classification."}, {"q": "XYZ Ltd has a subsidiary, ABC Bank, which has negative equity due to bad loans. XYZ has not written down its investment. What is the risk?", "options": ["Understatement of Assets.", "Overstatement of Investment (Impairment not recorded).", "Understatement of Liabilities.", "Going concern of XYZ."], "ans": 1, "exp": "If a subsidiary is in financial distress (negative equity), the parent's investment is likely impaired. Failing to record this overstates the investment asset."}, {"q": "How do you value an investment in an unlisted subsidiary where no market price is available?", "options": ["Historical Cost only.", "Value in Use (Discounted Cash Flows).", "Liquidation value.", "Guesswork."], "ans": 1, "exp": "For unlisted entities, auditors use the Value in Use model, projecting future cash flows and discounting them to find the recoverable amount."}, {"q": "In an NGO audit, what is the primary risk associated with \"Collection Boxes\"?", "options": ["Valuation of the box material.", "Completeness of income (Cash misappropriation).", "Presentation of the box.", "Rights to the box."], "ans": 1, "exp": "Cash boxes are insecure, and there is no trail of how much was actually put in vs. what was recorded, leading to a completeness/misappropriation risk."}, {"q": "If a donor gives money specifically for building a school, but the NGO uses it for salaries, which assertion is violated?", "options": ["Existence.", "Cut-off.", "Presentation & Disclosure (Restricted Fund breach).", "Accuracy."], "ans": 2, "exp": "Misusing restricted funds violates the donor's conditions. This must be disclosed properly, and the funds should be presented as restricted, not general."}, {"q": "An NGO receives donated computers (In-kind donation). They record them at an inflated price to show higher assets. Which assertion is at risk?", "options": ["Completeness.", "Valuation.", "Cut-off.", "Rights."], "ans": 1, "exp": "Recording non-cash assets at higher than their fair value overstates assets and revenue, violating the valuation assertion."}, {"q": "Most loans in Pakistan are based on a \"Floating Rate.\" What does this mean?", "options": ["The interest rate never changes.", "The interest rate is fixed by the auditor.", "The rate resets periodically based on a benchmark (e.g., KIBOR) + Spread.", "The bank decides the rate daily."], "ans": 2, "exp": "Floating rates adjust periodically (e.g., every 6 months) based on a benchmark like KIBOR plus a fixed spread."}, {"q": "Why does a bank charge a higher \"Spread\" (e.g., KIBOR + 4%) to certain customers?", "options": ["Because the customer is loyal.", "Because the customer is considered high risk.", "Because the government requires it.", "To lower the bank's profit."], "ans": 1, "exp": "The spread represents the bank's margin of safety. A riskier borrower pays a higher spread."}, {"q": "If a company breaches a \"Debt Covenant,\" what happens to the loan classification?", "options": ["It remains Non-Current.", "It becomes Equity.", "It must be reclassified as a Current Liability.", "It is written off."], "ans": 2, "exp": "A breach usually makes the loan payable on demand. Therefore, it must be classified as a Current Liability instead of Non-Current."}, {"q": "A competitor launches a cheaper product. Your client's sales volume remains the same, but margins drop significantly. What is the likely cause?", "options": ["Client increased prices.", "Client reduced prices to compete (NRV risk).", "Cost of goods sold decreased.", "Fake revenue."], "ans": 1, "exp": "To maintain sales volume against a cheaper competitor, the client likely lowered prices, squeezing margins and creating a risk that NRV is lower than cost."}, {"q": "An auditor finds that \"CWIP\" (Capital Work in Progress) includes items that are 10 months old, while the standard completion time is 3 months. What is the risk?", "options": ["Understatement of CWIP.", "Delayed capitalization (Asset actually in use but not depreciated).", "Overstatement of Depreciation.", "Going concern."], "ans": 1, "exp": "Keeping assets in CWIP prevents depreciation from starting. Old CWIP items suggest the asset is finished and in use, but management is delaying capitalization to avoid depreciation expense."}, {"q": "A toy company recalls a \"Fighter Toy\" due to safety issues. Which financial statement line item is MOST impacted?", "options": ["Share Capital.", "Provision for Sales Returns / Refunds.", "Rent Expense.", "Interest Income."], "ans": 1, "exp": "A product recall means customers will return goods. The company must record a provision for the expected returns and refunds."}, {"q": "If a company buys inventory in bulk at year-end to get a discount, what must the auditor verify to ensure it's not just \"overstatement\"?", "options": ["That the inventory is actually new and not obsolete stock mixed in.", "That the warehouse is painted.", "That the CEO approved it.", "That the supplier is local."], "ans": 0, "exp": "The auditor must check inventory aging to ensure the \"bulk buy\" explanation isn't masking the fact that the inventory is actually old/obsolete stock that isn't selling."}, {"q": "What is the \"Spread\" in a bank loan context?", "options": ["The fee for processing.", "The margin added to KIBOR to cover the bank's risk and profit.", "The length of the loan.", "The penalty for late payment."], "ans": 1, "exp": "The spread (e.g., +2%) is the bank's margin over the government borrowing rate (KIBOR)."}, {"q": "An NGO's admin expenses are 25% of donations, but the law allows only 10%. What is the risk?", "options": ["Going Concern (Loss of tax exemption).", "Overstatement of Admin Expense.", "Understatement of Income.", "Impairment of Assets."], "ans": 0, "exp": "Violating regulatory limits on expenses can lead to the revocation of the NGO's license or tax exemption, threatening its ability to operate (Going Concern)."}, {"q": "When auditing cash, why is a \"Surprise Count\" necessary?", "options": ["To catch staff sleeping.", "To ensure the cash recorded in books physically exists at that specific moment.", "To calculate the total sales for the year.", "To check the quality of notes."], "ans": 1, "exp": "A surprise count prevents staff from temporarily \"borrowing\" and replacing cash. It verifies the Existence assertion."}, {"q": "Why does a \"Conflict of Interest\" weaken internal controls?", "options": ["It makes people work harder.", "It allows an individual to bypass controls for personal gain (e.g., Sales Director approving bad credit to hit targets).", "It increases documentation.", "It has no impact."], "ans": 1, "exp": "If the person authorizing the transaction benefits from it (e.g., sales director approving credit), they are likely to ignore risks, making the control ineffective."}, {"q": "An auditor reviews the \"Minutes of Board Meetings.\" This is an example of which risk assessment procedure?", "options": ["Inquiry.", "Observation.", "Inspection.", "Analytical Procedure."], "ans": 2, "exp": "Reading and reviewing documents like minutes or internal audit reports falls under Inspection."}, {"q": "If an auditor discovers a \"Material Misstatement\" that management refuses to correct, what should they do?", "options": ["Resign immediately.", "Ignore it if it's not fraud.", "Report it to the Board, and if unresolved, modify the Audit Opinion.", "Call the police."], "ans": 2, "exp": "The standard process is to ask management to correct it. If they refuse, escalate to the Board/Audit Committee. If still unresolved, qualify the audit report.\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: General Internal Control Concepts (1-10)"}, {"q": "Scenario: At ABC Ltd, the CEO often bypasses established procurement procedures to award contracts to his brother\u2019s company. Question: What inherent limitation of internal control is highlighted here?", "options": ["Human Error", "Management Override", "Collusion", "Cost vs Benefit"], "ans": 1, "exp": "Management override occurs when someone with authority uses their power to bypass controls for personal gain or fraud."}, {"q": "Scenario: Two warehouse employees agree to steal inventory. One throws the goods over the fence, and the other marks them as \"Damaged\" in the system to hide the theft. Question: Why did the internal control system fail to prevent this?", "options": ["Because of Management Override", "Because of Collusion", "Because controls are too expensive", "Because of a software glitch"], "ans": 1, "exp": "Segregation of duties fails when two or more employees conspire (collude) to bypass the control."}, {"q": "Scenario: The auditor is reviewing the \"Tone at the Top\" of XYZ Corp. They notice that the Board of Directors rarely meets and shows little interest in financial reporting. Question: Which component of Internal Control is weak?", "options": ["Control Activities", "Control Environment", "Monitoring", "Information System"], "ans": 1, "exp": "The Control Environment reflects the attitude, awareness, and actions of governance regarding internal controls."}, {"q": "Scenario: A junior accountant made a mistake in calculating depreciation because he was tired and overworked. Question: This is an example of:", "options": ["Fraud", "Management Override", "Human Error", "Collusion"], "ans": 2, "exp": "Simple mistakes due to fatigue or misunderstanding are \"Human Errors,\" which are an inherent limitation of controls."}, {"q": "Scenario: The auditor asks the Finance Director to describe the sales process. The Director explains the process flow from order to cash. Question: The auditor documents this using a diagram with symbols and flowlines. What is this method called?", "options": ["Narrative Note", "Internal Control Questionnaire (ICQ)", "Flowchart", "Walkthrough"], "ans": 2, "exp": "A Flowchart is a visual diagram showing the sequence of operations and document flow."}, {"q": "Scenario: During a \"Walkthrough\" test, the auditor traces a single purchase transaction from the requisition slip to the final payment. Question: What is the primary objective of this test?", "options": ["To test the operating effectiveness of controls", "To confirm the auditor's understanding of the system", "To detect all frauds in purchases", "To count the inventory"], "ans": 1, "exp": "A Walkthrough confirms that the system processes transactions in the way the auditor has understood and documented."}, {"q": "Scenario: XYZ Ltd has a policy that all cheques above $5,000 must be signed by two directors. Question: What type of control activity is this?", "options": ["Performance Review", "Information Processing", "Authorization", "Physical Control"], "ans": 2, "exp": "This is an Authorization control ensuring high-value payments are approved by senior management."}, {"q": "Scenario: The auditor finds that the cost of installing a biometric security system for a small petty cash box exceeds the maximum amount of cash held in the box. Question: Why might management decide NOT to install the system?", "options": ["Management is negligent", "Reasonable Assurance (Cost vs Benefit)", "The auditor advised against it", "Controls are illegal"], "ans": 1, "exp": "Internal control provides reasonable, not absolute, assurance. The cost of the control should not exceed the benefit (value of assets protected)."}, {"q": "Scenario: An auditor finds a control is designed effectively. Question: What is the next logical step?", "options": ["Report it to shareholders", "Test the \"Operating Effectiveness\" of the control", "Ignore the control and do substantive testing", "Assume the financial statements are correct"], "ans": 1, "exp": "Once design is confirmed, the auditor tests if the control actually worked effectively throughout the period."}, {"q": "Scenario: Management reviews actual sales performance against the budget every month and investigates variances. Question: What type of control is this?", "options": ["Preventive Control", "Physical Control", "Performance Review (Monitoring)", "IT General Control"], "ans": 2, "exp": "Comparing actuals vs budgets is a performance review to monitor business results and control effectiveness.\n\ud83d\udd35 Section 2: Sales & Receivables Cycle (11-25)"}, {"q": "Scenario: A salesperson at TechStore can sell goods on credit to any customer without approval. Question: What is the major risk in this scenario?", "options": ["Inventory will be understated", "Bad debts will increase due to sales to poor credit risk customers", "Sales will decrease", "Suppliers will not be paid"], "ans": 1, "exp": "Without a credit check and authorized limit, the company risks selling to customers who cannot pay."}, {"q": "Scenario: While auditing invoices, you notice Invoice #502 is missing from the sequence (Invoice #501 and #503 are present). Question: What assertion is at risk?", "options": ["Accuracy", "Completeness", "Valuation", "Rights"], "ans": 1, "exp": "A gap in sequence suggests a transaction might have occurred but was not recorded (Incomplete records)."}, {"q": "Scenario: Goods are dispatched from the warehouse, but the \"Goods Dispatch Note\" (GDN) is not sent to the billing department immediately. Question: What is the financial statement impact?", "options": ["Inventory is stolen", "Revenue is not recorded (Understatement of Sales)", "Accounts Payable is overstated", "Cash is overstated"], "ans": 1, "exp": "Billing is triggered by the GDN. If the billing department doesn't get the GDN, they won't raise an invoice, and revenue won't be booked."}, {"q": "Scenario: The Sales Manager authorizes the issuance of Credit Notes for sales returns. Question: Why is this a control weakness?", "options": ["The Sales Manager is too busy", "Segregation of Duties issue (Conflict of Interest - he can hide fake sales)", "Credit notes should never be issued", "It slows down the process"], "ans": 1, "exp": "A Sales Manager wants high sales. If he authorizes returns, he could have created fake sales earlier to hit a bonus target and now reverses them via credit notes."}, {"q": "Scenario: A customer claims they never ordered the goods billed to them. The company cannot produce a \"Customer Order\" form. Question: Which control objective failed?", "options": ["Validity/Occurrence of Sales", "Arithmetic Accuracy", "Posting and summarization", "Timeliness"], "ans": 0, "exp": "A valid sale must be supported by a customer order. Without it, the sale may be fictitious or unauthorized."}, {"q": "Scenario: The pricing in the sales system allows any sales clerk to manually edit the unit price on an invoice. Question: What is the risk?", "options": ["Customers will be angry", "Unauthorized discounts may be given, leading to revenue loss", "Inventory will be lost", "Suppliers will overcharge"], "ans": 1, "exp": "Prices should come automatically from the Master File. Allowing manual edits lets staff give unauthorized discounts to friends."}, {"q": "Scenario: Monthly customer statements are sent to all debtors. Customer X complains that an invoice on the statement was already paid. Question: What function does the monthly statement serve here?", "options": ["It is a marketing tool", "It acts as a detective control to identify recording errors or disputes", "It authorizes the credit limit", "It writes off the debt"], "ans": 1, "exp": "Statements allow customers to reconcile their accounts with the company, highlighting errors or missing payments."}, {"q": "Scenario: The \"Aged Receivables Report\" shows several balances outstanding for 120+ days. No one has contacted these customers. Question: What control is missing?", "options": ["Credit Limit Authorization", "Debt Recovery / Follow-up Procedure", "Bank Reconciliation", "Inventory Count"], "ans": 1, "exp": "Identifying old debt is useless without a procedure to chase (follow up) the payment."}, {"q": "Scenario: The auditor observes that the \"Gate Security\" does not check vehicles leaving the premises. Question: What is the primary risk?", "options": ["Unauthorized shipment or theft of inventory", "Overstatement of sales", "Understatement of cash", "Wrong pricing"], "ans": 0, "exp": "Gate guards should verify that all goods leaving have a valid GDN to prevent theft."}, {"q": "Scenario: Cash received from customers is recorded by Mr. A, and Mr. A also takes the cash to the bank. Question: What fraud scheme is possible here?", "options": ["Channel Stuffing", "Teeming and Lading (Lapping)", "Overvaluation", "Payroll Fraud"], "ans": 1, "exp": "Lapping involves stealing cash from Customer A and using Customer B\u2019s payment to cover A\u2019s balance. Segregation of duties prevents this."}, {"q": "Scenario: To meet yearly targets, the Sales Director records sales on 30th December for goods that will be manufactured and shipped in January. Question: Which assertion is violated?", "options": ["Accuracy", "Cut-off", "Classification", "Presentation"], "ans": 1, "exp": "Cut-off requires transactions to be recorded in the correct period. Booking January sales in December is a Cut-off error."}, {"q": "Scenario: An auditor finds a \"Sales Invoice\" matched with a \"GDN\" but cannot find the \"Customer Order.\" Question: The sale might be:", "options": ["Underpriced", "Fictitious or unordered by the customer", "Foreign", "Tax-exempt"], "ans": 1, "exp": "Goods shipped without an order implies the company might be forcing goods on customers (push sales) or making mistakes."}, {"q": "Scenario: Access to the \"Credit Limit Master File\" is open to all finance staff. Question: What is the IT Control weakness?", "options": ["Lack of Backups", "Lack of Access Controls", "Hardware failure", "Phishing"], "ans": 1, "exp": "Only authorized credit managers should be able to change credit limits. Open access allows manipulation."}, {"q": "Scenario: A company writes off a bad debt of $10,000. The specific authorization comes from the Salesman who made the sale. Question: Is this control effective?", "options": ["Yes, the salesman knows the customer best.", "No, authorization should come from Senior Management independent of sales.", "Yes, it speeds up the process.", "No, the auditor should authorize it."], "ans": 1, "exp": "Salesmen have a conflict of interest. Only independent senior management should authorize asset write-offs."}, {"q": "Scenario: Revenue is recorded when the \"Sales Order\" is received, not when goods are dispatched. Question: What is the impact on Financial Statements?", "options": ["Revenue is recorded too early (Overstated)", "Revenue is recorded too late (Understated)", "Inventory is overstated", "Liabilities are overstated"], "ans": 0, "exp": "Revenue should be recognized upon satisfaction of performance obligation (delivery). Recording at order stage is premature.\n\ud83d\udfe0 Section 3: Purchases & Payables Cycle (26-40)"}, {"q": "Scenario: The Purchasing Manager orders goods from a company owned by his wife without disclosing this relationship. Question: Which control is missing?", "options": ["Competitive Bidding", "Conflict of Interest Disclosure / Related Party Policy", "Bank Reconciliation", "Inventory Count"], "ans": 1, "exp": "A policy should require employees to disclose related party interests to prevent self-dealing."}, {"q": "Scenario: An invoice arrives from a supplier. The accounts clerk enters it into the system immediately without checking anything else. Question: What should the clerk have checked first?", "options": ["The bank balance", "The Three-Way Match (PO + GRN + Invoice)", "The sales forecast", "The tax rate"], "ans": 1, "exp": "Never pay or record an invoice without checking: Did we order it? (PO) and Did we receive it? (GRN)."}, {"q": "Scenario: Goods arrive at the warehouse, but the warehouse manager does not issue a \"Goods Received Note\" (GRN). Question: What is the risk to the financial statements?", "options": ["Liability (Payables) will be understated", "Liability will be overstated", "Expenses will be overstated", "Cash will be understated"], "ans": 0, "exp": "The liability is accrued based on the GRN. If the GRN is missing, finance doesn't know the company owes money."}, {"q": "Scenario: A company does not use \"Sequential Numbering\" for its Purchase Orders. Question: What is the auditor's concern?", "options": ["It is hard to read.", "It is difficult to identify if a PO is missing or if unauthorized POs were created.", "Suppliers will be confused.", "It increases printing costs."], "ans": 1, "exp": "Sequential numbering allows the auditor to test for completeness (gaps) and occurrence (duplicates)."}, {"q": "Scenario: Checks for payment to suppliers are signed by the same person who approves the Purchase Order. Question: What segregation of duty is missing?", "options": ["Authorization (Ordering) vs Custody (Assets)", "Authorization (Ordering) vs Payment Authorization (Treasury)", "Recording vs Reporting", "Sales vs Purchases"], "ans": 1, "exp": "The person buying the goods shouldn't be the one signing the check, otherwise they can buy personal items and pay for them."}, {"q": "Scenario: To prevent paying a supplier invoice twice, what should the accounts department do after payment?", "options": ["Shred the invoice", "Stamp the invoice as \"PAID\"", "Send the invoice back to the supplier", "Photocopy the invoice"], "ans": 1, "exp": "Stamping \"PAID\" ensures the document cannot be presented for payment a second time."}, {"q": "Scenario: A supplier sends a monthly statement showing a balance of $10,000. The company\u2019s ledger shows $8,000. Question: What procedure identifies this difference?", "options": ["Bank Reconciliation", "Supplier Statement Reconciliation", "Sales Reconciliation", "Cash Count"], "ans": 1, "exp": "Reconciling the supplier's view with the company's view helps find missing invoices or disputed payments."}, {"q": "Scenario: The \"Approved Supplier List\" is maintained by the Purchasing Clerk. Question: What is the fraud risk?", "options": ["The clerk can add a fake supplier and make payments to himself.", "The clerk will delete all suppliers.", "Suppliers will charge less.", "Inventory will be higher."], "ans": 0, "exp": "Master data (like supplier lists) should only be updated by a senior independent person, not the buyer."}, {"q": "Scenario: High-value purchases (e.g., over $50,000) are made without obtaining competitive quotes. Question: What is the business risk?", "options": ["The company may be paying inflated prices (Not getting value for money).", "The goods will be delivered too fast.", "The supplier will be angry.", "The inventory will spoil."], "ans": 0, "exp": "Competitive bidding ensures the company gets the best price and quality."}, {"q": "Scenario: Blank cheque books are left on the accountant's desk overnight. Question: What physical control is missing?", "options": ["Authorization", "Segregation of Duties", "Custody / Physical Safeguards (Safe storage)", "Reconciliation"], "ans": 2, "exp": "Valuable items like cheques must be locked in a safe to prevent theft."}, {"q": "Scenario: Goods are returned to a supplier due to defects. The company waits for the supplier to send a document before reducing the payable. Question: What document should the company issue immediately to track this return?", "options": ["Credit Note", "Debit Note / Goods Return Note", "Invoice", "Check"], "ans": 1, "exp": "The company issues a Debit Note to formally notify the supplier: \"We are debiting (reducing) what we owe you.\""}, {"q": "Scenario: An auditor finds a payment made to a vendor named \"Generic Services,\" but there is no address or tax ID on the invoice. Question: This is a red flag for:", "options": ["A Shell Company Scheme (Fake Vendor)", "Efficient Procurement", "A Discount", "Tax Evasion"], "ans": 0, "exp": "Fake vendors often have vague names and missing details."}, {"q": "Scenario: The \"Cheque Signatory\" signs cheques without reviewing the supporting PO and Invoice. Question: Is this control effective?", "options": ["Yes, it saves time.", "No, the signature becomes a rubber stamp and fails to verify validity.", "Yes, because the clerk already checked it.", "No, because cheques should be digital."], "ans": 1, "exp": "The signatory is the final check. If they sign blindly, the control is useless."}, {"q": "Scenario: The \"Goods Received Note\" (GRN) is not signed by the warehouse receiver. Question: What is the risk?", "options": ["The supplier will not pay.", "There is no evidence that goods were actually counted and checked for quality.", "The invoice will be wrong.", "The tax calculation will be wrong."], "ans": 1, "exp": "A signature provides accountability that someone actually checked the goods."}, {"q": "Scenario: Purchase requisitions for specialized equipment are authorized by the Receptionist. Question: What is the weakness?", "options": ["Lack of Segregation.", "Lack of Appropriate Authorization Levels.", "Lack of Documentation.", "Lack of Monitoring."], "ans": 1, "exp": "Authorization limits should match the level of responsibility. A receptionist shouldn't authorize capital expenditure.\n\ud83d\udfe3 Section 4: Payroll Cycle (41-50)"}, {"q": "Scenario: The Production Manager has the authority to add new employees to the payroll system and also distributes the pay cheques. Question: What is the major fraud risk?", "options": ["He might underpay staff.", "He might create \"Ghost Employees\" and keep their salary.", "He might hire too many people.", "He might pay taxes late."], "ans": 1, "exp": "Having the power to create a fake person (record) and receive their money (custody) is a classic Ghost Employee scheme."}, {"q": "Scenario: Employees record their own hours on timesheets, which go directly to payroll without supervisor signature. Question: What is the risk?", "options": ["Employees are paid for hours they didn't work.", "Employees are paid too little.", "Payroll is processed too slowly.", "Tax is calculated wrongly."], "ans": 0, "exp": "Supervisor approval is needed to confirm the work was actually done."}, {"q": "Scenario: Payroll is paid in cash. The cash is put into envelopes by the same clerk who calculates the net pay. Question: What control should be introduced?", "options": ["Pay by Bank Transfer.", "Use bigger envelopes.", "Let the clerk sign the envelopes.", "Stop paying salaries."], "ans": 0, "exp": "Bank transfers create an external audit trail and remove the risk of cash theft."}, {"q": "Scenario: An employee leaves the company, but their name is not removed from the payroll master file. Question: Who is responsible for notifying payroll about leavers?", "options": ["The Bank", "Human Resources (HR)", "The Employee", "The Auditor"], "ans": 1, "exp": "HR manages the start and exit of staff. They must notify payroll immediately to stop payments."}, {"q": "Scenario: The auditor compares the current month's total payroll expense with the previous month and investigates a 20% increase. Question: What audit procedure is this?", "options": ["Test of Control", "Analytical Procedure", "Observation", "Inquiry"], "ans": 1, "exp": "Comparing trends and investigating fluctuations is an Analytical Procedure."}, {"q": "Scenario: A \"Surprise Payroll Count\" is planned. The auditor attends the pay-out. Question: What should the auditor ask employees to do?", "options": ["Count the money.", "Show photo identification (ID) before receiving the packet.", "Sign a blank paper.", "Donate to charity."], "ans": 1, "exp": "Checking ID proves that the person collecting the salary is the real employee, not a fraudster collecting for a ghost."}, {"q": "Scenario: Unclaimed cash wages are kept in the payroll clerk\u2019s drawer for \"safekeeping.\" Question: What is the correct procedure?", "options": ["Split it among other staff.", "Record it in a register and deposit it back into the bank immediately.", "Buy lunch for the office.", "Send it to the employee's home by post."], "ans": 1, "exp": "Unclaimed cash is highly vulnerable to theft and must be re-banked."}, {"q": "Scenario: Changes to salary rates (e.g., annual raise) are made based on verbal instructions from managers. Question: What documentation is required?", "options": ["An email from the employee.", "An authorized \"Change of Status\" form signed by HR/Management.", "A sticky note.", "A bank statement."], "ans": 1, "exp": "Changes to master data (pay rates) require formal written authorization."}, {"q": "Scenario: Tax deductions are calculated manually by the payroll clerk. Question: How can the company ensure accuracy?", "options": ["Ask the employee to check it.", "Use computerized payroll software with automatic tax updates.", "Guess the amount.", "Pay no tax."], "ans": 1, "exp": "Automated systems reduce calculation errors and ensure compliance with complex tax tables."}, {"q": "Scenario: The Payroll Bank Account is reconciled once a year. Question: How often should it be reconciled?", "options": ["Weekly or Monthly.", "Daily.", "Never.", "Every 5 years."], "ans": 0, "exp": "Regular (monthly) reconciliation identifies errors or fraudulent payments quickly.\n\ud83d\udfe4 Section 5: Inventory & Cash (51-60)"}, {"q": "Scenario: During a stock count, the auditor notices items marked \"Sold\" but still sitting in the warehouse. Question: These items should be:", "options": ["Included in inventory.", "Excluded from inventory (Third Party Stock).", "Thrown away.", "Counted twice."], "ans": 1, "exp": "If goods are sold, title has passed. Even if physical custody is with the company, they are not the company's assets (Existence vs Rights)."}, {"q": "Scenario: The warehouse continues to receive and dispatch goods while the stock count is happening. Question: What problem does this cause?", "options": ["It speeds up the count.", "Cut-off errors (Risk of double counting or missing items).", "It saves money.", "It helps customers."], "ans": 1, "exp": "Movement during a count makes it hard to know what was \"in stock\" at the specific count time. Movement should be frozen."}, {"q": "Scenario: The petty cash box has a float of $500. The custodian borrows $50 for lunch and leaves a generic \"IOU\" note. Question: Is this allowed?", "options": ["Yes, if he pays it back.", "No, petty cash is for business expenses only, supported by vouchers.", "Yes, if the manager knows.", "Yes, it's a perk."], "ans": 1, "exp": "Petty cash funds are strictly for business. Borrowing allows unauthorized use of company funds."}, {"q": "Scenario: A company uses a \"Perpetual Inventory System\" but never performs a physical count. Question: What is the risk?", "options": ["The computer records will drift away from physical reality (Phantom Inventory).", "The computer is always right.", "Inventory will be accurate.", "Sales will increase."], "ans": 0, "exp": "Theft, breakage, and data entry errors create differences. Physical counts (Cycle counts) are needed to correct the system."}, {"q": "Scenario: Two employees hold keys to the safe. Both keys are needed to open it. Question: What is this control called?", "options": ["Segregation of Duties.", "Dual Control.", "Physical Access.", "Authorization."], "ans": 1, "exp": "Dual control ensures that no single person can access the asset alone."}, {"q": "Scenario: Bank reconciliations are performed, but old \"unpresented cheques\" (outstanding for >6 months) are never investigated. Question: What is the risk?", "options": ["The bank balance is wrong.", "Liabilities might be understated (if cheques are written back) or fraud is hidden.", "The bank will charge a fee.", "Cash is overstated."], "ans": 1, "exp": "Old items on a reconciliation indicate errors, lost cheques, or stale transactions that need cleaning up."}, {"q": "Scenario: Inventory is stacked so high that the counters cannot check the top boxes. They estimate the quantity. Question: What should the auditor do?", "options": ["Accept the estimate.", "Ask for the boxes to be moved so they can be properly counted.", "Ignore the top boxes.", "Multiply the bottom row by 10."], "ans": 1, "exp": "Audit evidence must be reliable. Guessing or estimating without seeing is not sufficient evidence."}, {"q": "Scenario: Cash collected from sales is used to pay for petty cash expenses directly before banking. Question: Why is this a bad practice?", "options": ["It saves a trip to the bank.", "It breaks the audit trail (Banking Intact).", "It is efficient.", "It increases cash flow."], "ans": 1, "exp": "\"Banking Intact\" means depositing 100% of receipts. Using receipts for expenses makes it hard to verify total revenue."}, {"q": "Scenario: High-value electronic components are stored on open shelves near the loading bay. Question: What control should be implemented?", "options": ["Move them to a locked, restricted-access cage.", "Put a sign saying \"Do Not Steal\".", "Lower the price.", "Stop selling them."], "ans": 0, "exp": "High-risk/high-value inventory requires enhanced physical security."}, {"q": "Scenario: An auditor performs a \"Cut-off\" test by looking at the last 5 GDNs before year-end and the first 5 after. Question: What are they checking?", "options": ["That goods dispatched before year-end are recorded as Sales in the correct year.", "That inventory is safe.", "That the GDNs are signed.", "That the truck driver has a license."], "ans": 0, "exp": "Cut-off testing ensures transactions are recorded in the period they occurred.\n\u26ab Section 6: IT & General Controls (61-70)"}, {"q": "Scenario: All employees use the same login ID \"USER1\" to access the accounting system. Question: What characteristic of information security is lost?", "options": ["Availability.", "Accountability / Non-Repudiation.", "Speed.", "Backup."], "ans": 1, "exp": "If everyone shares an ID, you cannot trace a specific error or fraud to a specific person."}, {"q": "Scenario: The system automatically checks that the \"Date\" field only accepts valid dates (DD/MM/YYYY). Question: What type of control is this?", "options": ["Physical Control.", "IT General Control.", "Application Control (Input Validation).", "Detective Control."], "ans": 2, "exp": "Application controls work within specific software to ensure data integrity (e.g., format checks)."}, {"q": "Scenario: The server room is unlocked, and the temperature is very high. Question: What \"IT General Control\" (ITGC) is failing?", "options": ["Physical and Environmental Security.", "Change Management.", "Backups.", "Input Control."], "ans": 0, "exp": "Servers must be physically secured and kept cool to prevent hardware failure or tampering."}, {"q": "Scenario: A programmer makes a change to the live accounting code without testing it first. Question: What process is missing?", "options": ["Change Management / Change Control.", "Password protection.", "Anti-virus.", "Firewall."], "ans": 0, "exp": "Changes to systems must be tested in a separate environment and authorized before going \"Live.\""}, {"q": "Scenario: The system forces users to change their passwords every 90 days. Question: This is an example of:", "options": ["Logical Access Control.", "Physical Access Control.", "Input Control.", "Output Control."], "ans": 0, "exp": "Logical access controls (passwords) restrict access to system data."}, {"q": "Scenario: The system creates a \" Exception Report\" showing all invoices over $10,000. No one reviews it. Question: Is the control effective?", "options": ["Yes, the system produced the report.", "No, a control is only effective if the information is acted upon.", "Yes, it saves paper.", "No, the limit is too high."], "ans": 1, "exp": "Producing a report is useless if management doesn't review and resolve the exceptions."}, {"q": "Scenario: Data backups are taken daily but are stored on top of the server in the same room. Question: What is the risk?", "options": ["Data is safe.", "If there is a fire in that room, both the server and the backup are destroyed.", "It is easy to reach.", "The backup is too fast."], "ans": 1, "exp": "Off-site storage is essential. If the primary site is destroyed (fire/flood), the backup must be safe elsewhere."}, {"q": "Scenario: When entering a Customer ID, the system displays the Customer Name to verify it\u2019s the right person. Question: What is this control called?", "options": ["Check Digit.", "Check Sum.", "Range Check.", "Validity Check (or feedback check)."], "ans": 3, "exp": "The system validates the ID by showing associated data, helping the user catch mistakes."}, {"q": "Scenario: An auditor tries to enter a sales order for a customer who has exceeded their credit limit. The system blocks the transaction. Question: This is a:", "options": ["Preventive Application Control.", "Detective Control.", "Manual Control.", "General Control."], "ans": 0, "exp": "The system prevents the bad transaction from happening automatically."}, {"q": "Scenario: A laptop containing payroll data is stolen. The data cannot be read because it is scrambled. Question: What control protected the data?", "options": ["Firewall.", "Encryption.", "Antivirus.", "GPS."], "ans": 1, "exp": "Encryption makes data unreadable to unauthorized users, protecting confidentiality even if the device is lost.\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Opinion Decisions (Misstatement vs Scope Limitation)"}, {"q": "Scenario: The auditor identifies that the company has not depreciated its building worth $10 million. The profit is $2 million, and total assets are $50 million. Management refuses to correct it. Question: The misstatement is material but NOT pervasive. What opinion should the auditor express?", "options": ["Unmodified Opinion with EOM", "Qualified Opinion (\"Except for\")", "Adverse Opinion", "Disclaimer of Opinion"], "ans": 1, "exp": "The error is material (affects profit significantly) but confined to one account (building/depreciation), so it is not pervasive. Qualified is appropriate."}, {"q": "Scenario: The management refuses to allow the auditor to send confirmation letters to debtors. Debtors represent 70% of the total assets. No alternative procedures were possible. Question: What is the impact on the audit opinion?", "options": ["Qualified Opinion due to Scope Limitation", "Adverse Opinion due to Misstatement", "Disclaimer of Opinion due to Scope Limitation", "Unmodified Opinion with KAM"], "ans": 2, "exp": "This is a Scope Limitation (inability to obtain evidence). Since debtors are 70% of assets, the issue is Pervasive. Hence, Disclaimer."}, {"q": "Scenario: The company failed to consolidate a subsidiary that constitutes 60% of the group\u2019s net assets and profits. Management argues it\u2019s a temporary investment. Question: What opinion is required?", "options": ["Qualified Opinion", "Adverse Opinion", "Disclaimer of Opinion", "Emphasis of Matter"], "ans": 1, "exp": "Failure to consolidate a major subsidiary makes the financial statements fundamentally misleading (Pervasive Misstatement). Adverse opinion is required."}, {"q": "Scenario: A fire destroyed the inventory records for the first 3 months of the year. Sales for those months were 5% of the total yearly sales. Question: The auditor could not verify the inventory for that period.", "options": ["Disclaimer of Opinion", "Qualified Opinion due to Scope Limitation", "Adverse Opinion", "Unmodified Opinion"], "ans": 1, "exp": "The limitation exists, but 5% is material yet not pervasive. It doesn't render the whole FS meaningless."}, {"q": "Scenario: The client has capitalized \"Research Costs\" of $5 million as Intangible Assets. Total assets are $100 million, and Pre-tax profit is $50 million. Question: This is a breach of IAS 38. The amount is material.", "options": ["Adverse Opinion", "Qualified Opinion", "EOM Paragraph", "Disclaimer"], "ans": 1, "exp": "It is a misstatement (non-compliance with IAS 38). $5m on $100m assets is material but likely not pervasive (it doesn't overshadow the entire FS)."}, {"q": "Scenario: The auditor was appointed after the year-end inventory count. The inventory balance is material, and the auditor cannot verify it by alternative means. Inventory is 10% of total assets. Question: What opinion?", "options": ["Unmodified", "Disclaimer", "Qualified Opinion (Scope Limitation)", "Adverse"], "ans": 2, "exp": "Inability to verify inventory is a Scope Limitation. Since it's 10% (Material but not Pervasive), a Qualified opinion is issued."}, {"q": "Scenario: The company did not disclose a significant related party transaction with the CEO\u2019s brother. Question: Disclosure is required by IAS 24.", "options": ["Qualified Opinion (Misstatement of Disclosure)", "Adverse Opinion", "EOM Paragraph", "Key Audit Matter"], "ans": 0, "exp": "Missing disclosure is a misstatement. If it's specific to one transaction, it's usually Qualified."}, {"q": "Scenario: Management refuses to provide a \"Written Representation\" regarding their responsibility for the financial statements. Question: What is the immediate audit consequence?", "options": ["Qualified Opinion", "Adverse Opinion", "Disclaimer of Opinion (or Withdrawal)", "Report to Police"], "ans": 2, "exp": "Refusal to acknowledge fundamental responsibilities creates a Pervasive Scope Limitation. The auditor usually disclaims or withdraws."}, {"q": "Scenario: The financial statements show a profit of $1 million. The auditor finds unrecorded liabilities of $1.5 million. If corrected, the company would show a loss. Question: Is this Pervasive? What opinion?", "options": ["Not Pervasive; Qualified Opinion", "Pervasive; Adverse Opinion", "Pervasive; Disclaimer", "Not Pervasive; EOM"], "ans": 1, "exp": "Turning a profit into a loss is a classic indicator of Pervasiveness. The FS are misleading; hence, Adverse Opinion."}, {"q": "Scenario: The auditor is unable to verify the carrying value of a foreign investment due to government restrictions. The investment is 5% of total assets. Question:", "options": ["Unmodified Opinion", "Disclaimer", "Qualified Opinion (Scope Limitation)", "Adverse Opinion"], "ans": 2, "exp": "Scope limitation is restricted to a specific asset (5%), so it is material but not pervasive."}, {"q": "Scenario: The company uses \"Cash Basis\" accounting, while the law requires \"Accrual Basis\". Question: This affects all headers (Assets, Liabilities, Income, Expense).", "options": ["Qualified Opinion", "Adverse Opinion", "Disclaimer of Opinion", "Unmodified with EOM"], "ans": 1, "exp": "Using the wrong basis of accounting affects the entire financial statements (Pervasive Misstatement)."}, {"q": "Scenario: The auditor disagrees with the useful life of a machine. The difference in depreciation is $50,000 (Profit is $10 million). Question: The amount is immaterial.", "options": ["Unmodified Opinion", "Qualified Opinion", "EOM", "KAM"], "ans": 0, "exp": "Immaterial misstatements do not modify the opinion. They are added to the list of uncorrected misstatements."}, {"q": "Scenario: Management prevents the auditor from observing the physical inventory count. Inventory is 60% of current assets. Question:", "options": ["Qualified Opinion", "Adverse Opinion", "Disclaimer of Opinion", "Withdraw"], "ans": 2, "exp": "A deliberate scope limitation by management on a major asset (60%) is Pervasive. Disclaimer is appropriate."}, {"q": "Scenario: The client has not impaired a Goodwill balance of $20 million. Total Equity is $25 million. Question:", "options": ["Qualified Opinion", "Adverse Opinion", "Disclaimer", "EOM"], "ans": 1, "exp": "The error ($20m) represents nearly 80% of Equity. This is Pervasive. The FS does not present a true and fair view.*"}, {"q": "Scenario: Several small errors were found. Individually they are immaterial, but in aggregate, they exceed the materiality level. Question: Management refuses to correct them.", "options": ["Unmodified Opinion", "Qualified Opinion", "EOM", "Note to Accounts"], "ans": 1, "exp": "Materiality applies to the aggregate of uncorrected misstatements. If the total is material, the opinion must be modified.\n\ud83d\udfe1 Section 2: Structure & Basis for Opinion Paragraph"}, {"q": "Scenario: The auditor issues a Disclaimer of Opinion. Question: How does the \"Auditor\u2019s Responsibility\" section change?", "options": ["It remains the same.", "It describes the audit evidence obtained.", "It states \"We were able to obtain...\".", "It states \"Because of the matter described... we were not able to obtain sufficient appropriate audit evidence to provide a basis for an audit opinion.\""], "ans": 3, "exp": "In a Disclaimer, the auditor explicitly states they could NOT obtain evidence."}, {"q": "Scenario: An Adverse Opinion is issued. Question: Where is the reason for the adverse opinion described?", "options": ["In the Opinion Paragraph itself.", "In the \"Basis for Adverse Opinion\" paragraph.", "In the Notes to the Accounts.", "In the Emphasis of Matter paragraph."], "ans": 1, "exp": "The \"Opinion\" paragraph states the verdict (Adverse), and the \"Basis for Opinion\" paragraph explains the 'Why'."}, {"q": "Scenario: For a Qualified Opinion due to misstatement, the opinion paragraph uses the phrase:", "options": ["\"The financial statements do not give a true and fair view.\"", "\"Except for the effects of the matter described...\"", "\"We do not express an opinion.\"", "\"Subject to the matter described...\""], "ans": 1, "exp": "\"Except for\" is the specific terminology for a Qualified Opinion."}, {"q": "Scenario: The auditor issues a Disclaimer of Opinion. Question: Should the \"Key Audit Matters\" (KAM) section be included?", "options": ["Yes, always.", "No, prohibited by ISA 705.", "Only if management agrees.", "Yes, but only for listed companies."], "ans": 1, "exp": "If you disclaim an opinion on the whole FS, you cannot selectively highlight \"Key Matters\". KAM is prohibited in a Disclaimer."}, {"q": "Scenario: Which paragraph comes immediately after the \"Opinion\" paragraph?", "options": ["Key Audit Matters", "Basis for Opinion", "Going Concern", "Responsibilities of Management"], "ans": 1, "exp": "The structure is fixed: Opinion first, then Basis for Opinion."}, {"q": "Scenario: In the \"Basis for Opinion\" paragraph for a Qualified Opinion, the auditor must include:", "options": ["A statement that they are independent.", "A description of the misstatement.", "A statement that evidence obtained is sufficient.", "All of the above."], "ans": 3, "exp": "Even for a modified opinion, the basis paragraph must still affirm independence, the standards followed, and the description of the issue."}, {"q": "Scenario: The auditor issues an Adverse Opinion. Question: Does the Opinion Paragraph start with \"We have audited...\"?", "options": ["Yes", "No, it starts with \"We were engaged to audit...\"", "No, it starts with \"We reviewed...\"", "No, it starts with \"We compiled...\""], "ans": 0, "exp": "\"We have audited\" is used for Unmodified, Qualified, and Adverse. \"We were engaged to audit\" is ONLY for Disclaimer (Scope Limitation)."}, {"q": "Scenario: When there is a Scope Limitation (Disclaimer), the auditor omits which phrase from the Auditor\u2019s Responsibility section?", "options": ["\"Our responsibility is to express an opinion...\"", "\"Our responsibility is to conduct the audit in accordance with ISAs...\"", "\"We are independent...\"", "None of the above"], "ans": 1, "exp": "Since the audit was NOT fully conducted in accordance with ISAs (due to limitation), this statement is modified or removed in a Disclaimer."}, {"q": "Scenario: If a material misstatement relates to specific amounts in the FS, the Basis for Opinion paragraph should:", "options": ["Only describe it in words.", "Quantify the financial effect (e.g., \"Profit is overstated by $X\") unless impracticable.", "Refer to the Director\u2019s report.", "Ignore the amount."], "ans": 1, "exp": "The auditor must quantify the impact of the misstatement so users know the magnitude."}, {"q": "Scenario: The title of the opinion paragraph for a clean report is \"Opinion\". What is it for a Qualified report?", "options": ["\"Bad Opinion\"", "\"Qualified Opinion\"", "\"Modified Opinion\"", "\"Except For Opinion\""], "ans": 1, "exp": "The heading must clearly state the type of modification, i.e., \"Qualified Opinion\".\n\ud83d\udfe0 Section 3: Going Concern (GC) Scenarios"}, {"q": "Scenario: The company has severe cash flow issues. Management has a valid plan (e.g., bank loan approved), and they have disclosed the uncertainty in the notes. Question: The GC assumption is appropriate, but a Material Uncertainty (MUG) exists.", "options": ["Qualified Opinion", "Adverse Opinion", "Unmodified Opinion + Material Uncertainty Related to Going Concern (MUG) section", "EOM Paragraph"], "ans": 2, "exp": "If MUG exists and is disclosed, the opinion is Unmodified, but a dedicated \"MUG\" section is added (NOT EOM)."}, {"q": "Scenario: Same situation as above (Material Uncertainty exists), but Management Refuses to disclose it in the notes. Question:", "options": ["Unmodified Opinion + MUG section", "Qualified or Adverse Opinion (Misstatement of Disclosure)", "Disclaimer", "EOM"], "ans": 1, "exp": "Failure to disclose the uncertainty is a material (and likely pervasive) misstatement. Adverse is common here."}, {"q": "Scenario: The company is NOT a Going Concern. Management prepared accounts on a \"Liquidation Basis\" (Break-up value). This basis is appropriate. Question:", "options": ["Unmodified Opinion (possibly with EOM)", "Adverse Opinion", "Qualified Opinion", "Disclaimer"], "ans": 0, "exp": "If the company is dying and uses the correct \"Death\" (Liquidation) accounting, the FS are true and fair. Unmodified."}, {"q": "Scenario: The company is NOT a Going Concern (factory burned down, no insurance). Management still prepared accounts on a \"Going Concern Basis\" (Historical Cost). Question:", "options": ["Unmodified with MUG", "Adverse Opinion", "Qualified Opinion", "EOM"], "ans": 1, "exp": "Using the Going Concern basis when the company is not a GC is a Pervasive Misstatement. The whole basis of the FS is wrong."}, {"q": "Scenario: There are multiple significant uncertainties (lawsuits, debt default, market collapse). The auditor feels unable to form an opinion on the GC status due to lack of evidence or clarity. Question:", "options": ["MUG Section", "Disclaimer of Opinion", "Adverse Opinion", "Qualified Opinion"], "ans": 1, "exp": "In rare cases involving multiple massive uncertainties where evidence is impossible to get, the auditor may Disclaim."}, {"q": "Scenario: Management\u2019s assessment of Going Concern covers only 9 months from the year-end. Question: What should the auditor request?", "options": ["Nothing, 9 months is enough.", "Request extension to at least 12 months from the reporting date.", "Qualify the report immediately.", "Audit only 9 months."], "ans": 1, "exp": "ISA 570 requires management to assess GC for at least 12 months from the reporting date."}, {"q": "Scenario: The MUG section in the audit report should:", "options": ["Be placed in the EOM paragraph.", "Cross-reference to the note in the FS where the uncertainty is disclosed.", "Modify the opinion.", "State that the company will definitely close."], "ans": 1, "exp": "The MUG section draws attention to the note in the financial statements."}, {"q": "Scenario: A company breaches a loan covenant. The bank has waived the breach for 12 months. Question: Is there a Material Uncertainty?", "options": ["Yes, always.", "No, the waiver mitigates the risk.", "Yes, waivers are not reliable.", "The auditor should ignore it."], "ans": 1, "exp": "If the waiver is legally binding for 12 months, the immediate threat is removed, so GC may be appropriate without MUG (depending on other factors)."}, {"q": "Scenario: A manufacturing company lost its only major customer. No new contracts are in sight. Management has no plan. Question:", "options": ["Unmodified", "Material Uncertainty Exists", "Going Concern Assumption is Inappropriate", "EOM"], "ans": 2, "exp": "Without a customer or plan, the entity cannot survive. The GC assumption is invalid."}, {"q": "Scenario: The auditor concludes that the use of the going concern assumption is appropriate, and no material uncertainty exists. Question: What audit report is issued?", "options": ["Unmodified (Standard)", "Unmodified with EOM", "Unmodified with MUG", "Disclaimer"], "ans": 0, "exp": "This is the standard clean scenario.\n\ud83d\udd35 Section 4: Key Audit Matters (KAM) vs EOM vs OM"}, {"q": "Scenario: A listed company has a significant Goodwill balance. The valuation involves complex management estimates and high auditor judgment. Question: How should this be communicated?", "options": ["EOM Paragraph", "Qualified Opinion", "Key Audit Matter (KAM)", "OM Paragraph"], "ans": 2, "exp": "KAMs are for matters of \"most significance\" involving high risk or judgment (Valuation)."}, {"q": "Scenario: A major fire destroyed the company's warehouse after the reporting date. This is a non-adjusting event but is correctly disclosed in the notes. Question: It is fundamental to users' understanding.", "options": ["KAM", "Emphasis of Matter (EOM)", "Qualified Opinion", "Other Matter (OM)"], "ans": 1, "exp": "EOM is for correctly disclosed matters that are \"Fundamental to users' understanding\" (like major catastrophes)."}, {"q": "Scenario: The prior year's financial statements were audited by a different audit firm. Question: Where does the auditor mention this?", "options": ["KAM", "EOM", "Other Matter (OM) Paragraph", "Basis for Opinion"], "ans": 2, "exp": "OM is for matters NOT disclosed in the FS but relevant to the audit process (like predecessor auditor)."}, {"q": "Scenario: The company is facing a major lawsuit. The outcome is uncertain, but it is appropriately disclosed in Note 10. Question: The auditor wants to draw attention to this note.", "options": ["Qualified Opinion", "KAM", "EOM", "Adverse"], "ans": 2, "exp": "Litigation is a classic EOM scenario (if correctly disclosed). It draws attention to the note."}, {"q": "Scenario: Can a Modified Opinion (e.g., Qualification regarding Inventory) be included in the KAM section?", "options": ["Yes, it is the most key matter.", "No, modifications go in the \"Basis for Opinion\" section, not KAM.", "Yes, if management agrees.", "Only for banks."], "ans": 1, "exp": "KAM is for \"other\" significant matters. The reason for a bad opinion goes in the Basis paragraph, not KAM."}, {"q": "Scenario: Can the auditor use the EOM paragraph to fix a missing disclosure in the Financial Statements?", "options": ["Yes, the auditor can disclose it there.", "No, EOM can only refer to information already in the FS.", "Yes, if it is material.", "Yes, if it is pervasive."], "ans": 1, "exp": "EOM is strictly a \"Pointer\". It says \"Look at Note X\". If Note X doesn't exist, you cannot use EOM; you must Qualify."}, {"q": "Scenario: Which of the following is mandatory for Listed Companies?", "options": ["EOM", "OM", "KAM", "Disclaimer"], "ans": 2, "exp": "ISA 701 makes KAM mandatory for listed entities."}, {"q": "Scenario: The auditor identifies a fraud risk in Revenue Recognition. This required significant audit effort. Question: Assuming no material misstatement found, where is this reported?", "options": ["EOM", "KAM", "OM", "Management Letter only"], "ans": 1, "exp": "High risk areas requiring significant effort are typical KAMs."}, {"q": "Scenario: A company changed its accounting policy for Inventory valuation (FIFO to Weighted Average). This is properly disclosed and justified. Question:", "options": ["Qualified Opinion", "EOM (Consistency of FS)", "OM", "Adverse"], "ans": 1, "exp": "A material change in accounting policy is often highlighted via EOM."}, {"q": "Scenario: The auditor's report includes a statement restricting the use of the report to specific users (e.g., \"For the Board only\"). Question: Where is this restriction placed?", "options": ["Opinion Paragraph", "EOM", "Other Matter (OM)", "KAM"], "ans": 2, "exp": "Restrictions on distribution/use relate to the audit engagement, not the numbers, so it goes in OM.\n\ud83d\udfe3 Section 5: Drafting & Reporting Nuances"}, {"q": "Scenario: \"We have audited...\" vs \"We were engaged to audit...\" Question: Which opinion uses the latter?", "options": ["Unmodified", "Qualified", "Adverse", "Disclaimer"], "ans": 3, "exp": "Disclaimer means no audit was effectively completed, so we were only \"engaged\" to try."}, {"q": "Scenario: When issuing an Adverse Opinion, does the auditor include the \"Key Audit Matters\" section?", "options": ["Yes, always.", "No, usually KAM is not included (unless specific laws require).", "Yes, to explain the adverse nature.", "No, because the company is closing."], "ans": 1, "exp": "Similar to Disclaimer, if the FS are bad (Adverse), communicating \"Key Matters\" is usually less relevant or confusing. However, unlike Disclaimer, it's not strictly prohibited, but generally avoided or modified."}, {"q": "Scenario: An auditor finds a material misstatement. Management corrects it. Question: Does this corrected error appear in the Audit Report?", "options": ["Yes, as a Qualified Opinion.", "Yes, as a KAM (if it was a significant risk area).", "No, corrected errors are never mentioned.", "Yes, in EOM."], "ans": 1, "exp": "If it was a high-risk area (KAM), the auditor might describe the risk and how it was addressed (including the correction), but the Opinion is Unmodified."}, {"q": "Scenario: What is the order of paragraphs in a standard audit report?", "options": ["Basis for Opinion -> Opinion -> KAM", "Opinion -> Basis for Opinion -> KAM", "KAM -> Opinion -> Basis for Opinion", "Opinion -> KAM -> Basis for Opinion"], "ans": 1, "exp": "ISA 700 (Revised) mandates: Opinion first, then Basis, then KAM (for listed)."}, {"q": "Scenario: The auditor wants to highlight that the prior year figures were unaudited. Question: Which paragraph?", "options": ["EOM", "KAM", "Other Matter (OM)", "Basis for Opinion"], "ans": 2, "exp": "This relates to the auditor's responsibility/scope regarding comparative figures, not the content of the current FS."}, {"q": "Scenario: \"In our opinion, except for the possible effects of the matter described...\" Question: This phrase is used for:", "options": ["Qualified Opinion (Misstatement)", "Qualified Opinion (Scope Limitation)", "Adverse Opinion", "Disclaimer"], "ans": 1, "exp": "\"Possible effects\" implies we don't know the amount (Scope Limitation). If we knew the amount (Misstatement), we would say \"Except for the effects\"."}, {"q": "Scenario: \"In our opinion, because of the significance of the matter...\" Question: This phrase is used for:", "options": ["Qualified Opinion", "Adverse Opinion", "Disclaimer", "Unmodified"], "ans": 1, "exp": "\"Because of the significance\" (and concluding \"do not give a true and fair view\") is the Adverse phrasing."}, {"q": "Scenario: If the auditor includes an EOM paragraph, must they explicitly state that \"Our opinion is not modified in respect of this matter\"?", "options": ["No, it's implied.", "Yes, it is mandatory.", "Only for listed companies.", "Only if the client asks."], "ans": 1, "exp": "To avoid confusing the user (thinking it's a qualification), the auditor MUST state that the opinion is not modified."}, {"q": "Scenario: Can an auditor have both a Qualified Opinion and an Emphasis of Matter in the same report?", "options": ["No, never.", "Yes, for different issues.", "Yes, for the same issue.", "Only in the US."], "ans": 1, "exp": "You can qualify for Inventory (Misstatement) and add an EOM for a Lawsuit (Disclosed correctly)."}, {"q": "Scenario: What happens if the Directors' Report contradicts the Financial Statements? Question: The FS are correct, but the Director's report contains a material error. Management refuses to fix the Director's report.", "options": ["Qualified Opinion on FS.", "Adverse Opinion on FS.", "Other Information (OI) Section reporting.", "Disclaimer."], "ans": 2, "exp": "The error is in \"Other Information\", not the FS. The auditor reports this inconsistency in the \"Other Information\" section, but the Audit Opinion remains Unmodified.\n\ud83d\udfe4 Section 6: Mixed & Tricky Cases"}, {"q": "Scenario: A retailer has huge cash sales but no internal controls over cash. The auditor cannot verify the completeness of revenue. Question: Revenue is 100% of P&L.", "options": ["Qualified Opinion", "Disclaimer of Opinion", "Adverse Opinion", "Unmodified"], "ans": 1, "exp": "Scope limitation on 100% of revenue is Pervasive. The auditor cannot form an opinion."}, {"q": "Scenario: The company changed its useful life estimate for cars from 5 years to 3 years. The auditor agrees this is realistic. Question:", "options": ["Unmodified Opinion", "Unmodified + EOM", "Qualified Opinion", "KAM"], "ans": 0, "exp": "A change in estimate (if reasonable and disclosed) is normal business. No modification or EOM is needed unless it's exceptionally fundamental (rare)."}, {"q": "Scenario: The client refuses to pay audit fees for the last year. Question:", "options": ["Qualify the report.", "Assess \"Self-Interest Threat\" to independence.", "Issue Adverse opinion.", "Sue the client."], "ans": 1, "exp": "Unpaid fees create an independence issue (Ethical risk), not an audit opinion issue directly (unless independence is compromised, then resign)."}, {"q": "Scenario: Inventory is understated by $100k (Material). Receivables are overstated by $100k (Material). Net Asset impact is Zero. Question:", "options": ["Unmodified (errors cancel out).", "Qualified Opinion.", "EOM.", "Note only."], "ans": 1, "exp": "Misstatements in individual line items are material even if they offset. The FS are still misleading regarding the composition of assets."}, {"q": "Scenario: The company has a negative equity of $5m. The parent company has provided a \"Letter of Support\" guaranteeing payments. The auditor verified the parent's ability to pay. Question:", "options": ["Material Uncertainty (MUG) exists.", "Unmodified Opinion (No MUG).", "Qualified Opinion.", "Disclaimer."], "ans": 1, "exp": "A valid Letter of Support from a wealthy parent resolves the uncertainty. The GC assumption is safe."}, {"q": "Scenario: A bank confirmation shows a loan of $1m, but the ledger shows $0. Management says \"It's an error by the bank.\" Auditor finds no evidence of repayment. Question: Management refuses to correct.", "options": ["Qualified or Adverse (depending on materiality).", "Disclaimer.", "EOM.", "KAM."], "ans": 0, "exp": "This is a factual misstatement (Unrecorded Liability)."}, {"q": "Scenario: The auditor was unable to attend the inventory count at a foreign branch (10% of assets) due to a flight ban. The auditor hired a local external auditor to attend and report back. Question:", "options": ["Scope Limitation (Qualified).", "Unmodified Opinion.", "Disclaimer.", "OM Paragraph."], "ans": 1, "exp": "The auditor obtained sufficient evidence using \"Alternative Procedures\" (hiring a local auditor). No limitation exists."}, {"q": "Scenario: During the audit, the auditor found fraud committed by the CFO. It is immaterial in amount but significant in nature. Question: Management refuses to act.", "options": ["Unmodified (Immaterial).", "Qualified Opinion (Qualitative Materiality).", "Withdraw from engagement (Integrity issue).", "EOM."], "ans": 2, "exp": "Fraud by senior management raises questions about integrity and the reliability of ALL representations. Withdrawal is often the only path."}, {"q": "Scenario: A company accounts for a lease as an Operating Lease (Expense) but IFRS 16 requires it to be a Finance Lease (Asset/Liability). Question:", "options": ["EOM.", "Qualified or Adverse Opinion (Misstatement).", "Disclaimer.", "KAM."], "ans": 1, "exp": "Non-compliance with accounting standards (IFRS 16) is a Misstatement."}, {"q": "Scenario: The financial statements do not disclose the \"Ultimate Controlling Party\". Question:", "options": ["Unmodified.", "Qualified Opinion (Disclosure Misstatement).", "EOM.", "OM."], "ans": 1, "exp": "IAS 24 requires this disclosure. Missing it is a material misstatement."}, {"q": "Scenario: A construction company recognizes revenue based on \"% of completion\". The auditor cannot verify the % completion because the engineer's certificate is missing. Question: Revenue is the largest figure in the FS.", "options": ["Qualified.", "Disclaimer of Opinion.", "Adverse.", "Unmodified."], "ans": 1, "exp": "Inability to verify the core revenue recognition method is a Pervasive Scope Limitation."}, {"q": "Scenario: The auditor is being sued by the client for negligence in the previous year. Question:", "options": ["Continue Audit.", "Resign due to lack of independence (Intimidation/Adversarial threat).", "Issue Adverse Opinion.", "Charge higher fees."], "ans": 1, "exp": "Litigation between client and auditor destroys independence."}, {"q": "Scenario: A cyber-attack destroyed the accounting records. Backup failed. Management reconstructed accounts using estimates. Question: Auditor cannot verify the estimates.", "options": ["Unmodified with EOM.", "Disclaimer of Opinion.", "Adverse Opinion.", "Qualified."], "ans": 1, "exp": "Without records, evidence is impossible to get. Pervasive Scope Limitation."}, {"q": "Scenario: The company has booked a \"Provision for Restructuring\" but has not yet announced the plan to employees (as required by IAS 37). Question:", "options": ["Unmodified.", "Qualified Opinion (Overstated Liability).", "EOM.", "Disclaimer."], "ans": 1, "exp": "IAS 37 says no provision without a constructive obligation (communication). The liability is overstated."}, {"q": "Scenario: Which of the following is NOT a modification of the audit opinion?", "options": ["Qualified Opinion.", "Emphasis of Matter (EOM).", "Adverse Opinion.", "Disclaimer of Opinion."], "ans": 1, "exp": "EOM is an \"Additional Communication\", NOT a modification. The opinion remains clean (Unmodified).\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Concept & Definitions"}, {"q": "Scenario: The auditor of ABC Ltd determines that a misstatement of $50,000 would change the decision of a primary user (e.g., a bank giving a loan). A misstatement of $40,000 would not. Question: The amount of $50,000 represents:", "options": ["Performance Materiality", "Overall Materiality", "Trivial Amount", "Audit Fee"], "ans": 1, "exp": "Overall Materiality is the threshold above which misstatements are expected to influence the economic decisions of users."}, {"q": "Scenario: An error of $500 is found in the \"Petty Cash\" book. The total assets of the company are $100 million. Question: How should the auditor treat this error?", "options": ["It is material because all errors must be corrected.", "It is likely immaterial (trivial) and may be ignored if below the clearly trivial threshold.", "It requires a qualified opinion.", "It is a fraud risk."], "ans": 1, "exp": "Materiality is relative. A $500 error in a $100m company is likely below the \"Clearly Trivial\" threshold and doesn't impact user decisions."}, {"q": "Scenario: The auditor identifies a fraud of $1,000 committed by the CFO. The overall materiality is $1 million. Question: Is this misstatement material?", "options": ["No, because $1,000 is much less than $1 million.", "Yes, because of its \"Nature\" (Qualitative Materiality).", "No, because it doesn't affect profit significantly.", "Yes, but only if the CFO agrees."], "ans": 1, "exp": "Materiality has two aspects: Size (Quantitative) and Nature (Qualitative). Fraud by senior management is always material due to its nature, regardless of the amount."}, {"q": "Scenario: Which of the following is NOT a primary factor when determining materiality?", "options": ["The needs of the financial statement users.", "The size of the entity.", "The audit fee agreed with the client.", "The nature of the entity's business."], "ans": 2, "exp": "Audit fees are a commercial arrangement and should never influence the auditor's judgment on materiality.\n\ud83d\udd35 Section 2: Calculation & Benchmarks"}, {"q": "Scenario: XYZ Ltd is a profit-oriented manufacturing company. It has been profitable for the last 5 years. Question: What is the most appropriate benchmark for determining Overall Materiality?", "options": ["Total Assets", "Profit Before Tax", "Total Revenue", "Net Assets"], "ans": 1, "exp": "For a profit-oriented entity, \"Profit Before Tax\" is usually the most relevant benchmark for users (investors/shareholders)."}, {"q": "Scenario: A start-up company is yet to generate revenue or profit. It is funded by heavy external investment and holds significant cash and equipment. Question: What is the best benchmark for materiality?", "options": ["Profit Before Tax", "Total Revenue", "Total Assets or Net Assets", "5% of Profit"], "ans": 2, "exp": "Since there is no profit or revenue, users (investors) focus on the assets and how the funding is utilized."}, {"q": "Scenario: The auditor decides to use \"Total Revenue\" as the benchmark for a retail company with very low profit margins (high volume, low margin). Question: Why might Revenue be better than Profit here?", "options": ["Revenue is easier to calculate.", "Profit is volatile and may fluctuate close to zero, making it an unstable benchmark.", "Revenue is always higher.", "IAS 320 mandates it."], "ans": 1, "exp": "When profit is volatile or abnormally low, it becomes a poor benchmark (a small error could look huge). Revenue is more stable."}, {"q": "Scenario: The auditor sets Overall Materiality at $100,000. He sets Performance Materiality at $75,000. Question: Why is Performance Materiality lower?", "options": ["To create a buffer for undetected and uncorrected misstatements.", "To increase the audit fee.", "Because the client requested it.", "Because the intern calculated it."], "ans": 0, "exp": "Performance Materiality (the \"Haircut\") reduces the risk that the aggregate of small, undetected errors exceeds the overall materiality.\n\ud83d\udfe0 Section 3: Performance & Specific Materiality"}, {"q": "Scenario: The auditor is checking \"Directors' Remuneration\". The total amount is $50,000. Overall Materiality is $1 million. Question: Does the auditor need to audit this $50,000?", "options": ["No, it is immaterial.", "Yes, using \"Specific Materiality\" because it is a sensitive disclosure required by law.", "Only if the directors ask for it.", "No, unless there is fraud."], "ans": 1, "exp": "Some items (like related party transactions or director pay) are material by \"Nature\" or law, even if the amount is small. A lower \"Specific Materiality\" is applied."}, {"q": "Scenario: A company has high \"Inherent Risk\" and weak internal controls. Question: How should this affect Performance Materiality?", "options": ["Set it closer to Overall Materiality (e.g., 90%).", "Set it lower (e.g., 50-60% of Overall Materiality) to create a larger safety buffer.", "Keep it the same.", "Ignore Performance Materiality."], "ans": 1, "exp": "High risk means a higher chance of errors. The auditor needs a bigger cushion (lower performance materiality) to ensure the total error doesn't breach the limit."}, {"q": "Scenario: During the audit, the company sells a major division, reducing its size significantly. Question: What should the auditor do regarding materiality?", "options": ["Keep the original materiality.", "Revise the materiality downward to reflect the smaller size.", "Revise the materiality upward.", "Withdraw from the audit."], "ans": 1, "exp": "Materiality is not fixed. If the entity's circumstances change (e.g., shrinks), materiality must be revised (lowered) to remain relevant."}, {"q": "Scenario: The auditor finds 10 small errors of $10,000 each. Overall Materiality is $150,000. Performance Materiality is $90,000. Question: The total error is $100,000.", "options": ["The FS are materially misstated because Total ($100k) > Performance Materiality ($90k).", "The FS are NOT misstated because Total ($100k) < Overall Materiality ($150k).", "The auditor should ignore them.", "The auditor should resign."], "ans": 1, "exp": "The final comparison for the audit opinion is against \"Overall Materiality\". However, since it exceeded Performance Materiality during testing, the auditor likely had to do more work to ensure no other errors existed.\n\ud83d\udfe3 Section 4: Practical Application & Revisions"}, {"q": "Scenario: A company is close to breaching a loan covenant (e.g., maintain a current ratio of 2:1). Question: How does this affect materiality judgment?", "options": ["Materiality should be increased.", "Even a small misstatement that triggers a breach becomes material.", "Materiality is irrelevant.", "Use Total Assets as a benchmark."], "ans": 1, "exp": "This is a qualitative factor. A small error that changes a ratio from \"Compliant\" to \"Breach\" is material because it changes the bank's decision (call the loan)."}, {"q": "Scenario: The auditor uses a benchmark of 5% of Profit Before Tax. The Draft Profit was $2m (Materiality = $100k). Adjustments reduced the Final Profit to $1m. Question: What must the auditor do?", "options": ["Keep Materiality at $100k.", "Recalculate Materiality based on the new profit ($50k) and reassess audit procedures.", "Issue a qualified opinion.", "Ignore the change."], "ans": 1, "exp": "Materiality must be revised as the numbers change. If profit drops, materiality drops, and the auditor may need to test more items."}, {"q": "Scenario: Which of the following items usually requires a \"Specific Materiality\" level lower than Overall Materiality?", "options": ["Repairs and Maintenance expense.", "Related Party Transactions.", "Electricity Bills.", "Depreciation."], "ans": 1, "exp": "Related Party Transactions are sensitive and high-risk for users, requiring a more detailed (lower threshold) check."}, {"q": "Scenario: Performance Materiality is primarily used for:", "options": ["Reporting to shareholders.", "Determining the nature, timing, and extent of audit procedures (Scope of testing).", "Calculating tax.", "Signing the audit report."], "ans": 1, "exp": "Performance Materiality is a working tool. It helps the auditor decide which balances to select for testing."}, {"q": "Scenario: An auditor ignores a misstatement of $5 because it is \"Clearly Trivial\". Question: Is this correct?", "options": ["No, all errors must be corrected.", "Yes, clearly trivial amounts are inconsequential individually and in aggregate.", "No, it might be fraud.", "Yes, but only if the client approves."], "ans": 1, "exp": "\"Clearly Trivial\" is a very low threshold below which auditors stop tracking errors to save efficiency. It is acceptable."}, {"q": "Scenario: A non-profit charity organization's primary objective is to spend donations on specific causes. Question: What is the most relevant benchmark?", "options": ["Profit Before Tax.", "Total Expenses or Total Donations/Revenue.", "Accounts Payable.", "Inventory."], "ans": 1, "exp": "For NPOs, users care about how money is spent (Expenses) or raised (Donations), not profit."}, {"q": "Scenario: The phrase \"Materiality is a matter of professional judgment\" means:", "options": ["There are no rules, the auditor can do whatever they want.", "Materiality depends on the auditor's perception of users' needs in the specific circumstances.", "Materiality is decided by the Court.", "Materiality is decided by the Client."], "ans": 1, "exp": "Judgment is required to interpret what users need and what fits the specific entity context."}, {"q": "Scenario: If the auditor sets Materiality too high (e.g., $10m instead of $1m):", "options": ["The audit will be more efficient and safer.", "Audit Risk increases (High detection risk), as material misstatements below $10m will be missed.", "The client will be unhappy.", "The audit fee will increase."], "ans": 1, "exp": "Setting materiality too high means you test less. You might miss errors (e.g., a $5m error) that users would actually care about.\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Adjusting vs. Non-Adjusting Events"}, {"q": "Scenario: A company\u2019s warehouse was destroyed by a fire on 15 January 2024. The financial year-end is 31 December 2023. The inventory loss is material. Question: How should this be treated in the financial statements for the year ended 31 December 2023?", "options": ["Adjusting Event \u2013 Write down inventory to zero in 2023 accounts.", "Non-Adjusting Event \u2013 Disclose the nature and estimated financial effect in the notes.", "Non-Adjusting Event \u2013 Do nothing as it happened next year.", "Adjusting Event \u2013 Create a provision for fire loss."], "ans": 1, "exp": "The condition (fire) did NOT exist at the reporting date (31 Dec). It is a non-adjusting event. Since it is material, it must be disclosed.*"}, {"q": "Scenario: On 31 December 2023, a customer owed $50,000. On 20 January 2024, the customer was declared bankrupt. The liquidation notice states the bankruptcy was due to a long-term decline in financial health over the last 2 years. Question: Treatment in 2023 Financial Statements?", "options": ["Adjusting Event \u2013 Write off the bad debt in 2023.", "Non-Adjusting Event \u2013 Disclose in 2023 notes.", "Record the bad debt in 2024 only.", "Treat as a contingent liability."], "ans": 0, "exp": "The bankruptcy confirms a condition (customer's poor financial health) that already existed at the reporting date. Therefore, it is an adjusting event.*"}, {"q": "Scenario: A lawsuit was filed against the company in 2022 for patent infringement. On 31 December 2023, the company recorded a provision of $1 million. On 15 February 2024 (before audit report), the court settled the case for $1.5 million. Question: How should the $0.5 million difference be treated?", "options": ["Adjusting Event \u2013 Increase the provision in 2023 accounts to $1.5 million.", "Non-Adjusting Event \u2013 Disclose the settlement in notes.", "Record the extra $0.5 million as an expense in 2024.", "Ignore as the difference is immaterial."], "ans": 0, "exp": "The court ruling provides additional evidence about a condition (the lawsuit) that existed at the reporting date. The provision must be adjusted.*"}, {"q": "Scenario: The Board of Directors proposes a final dividend of $2 per share on 15 January 2024 (Year-end 31 Dec 2023). Question: Should this be recorded as a liability in the 2023 Balance Sheet?", "options": ["Yes, it is an adjusting event because the profit was earned in 2023.", "No, dividends declared after the reporting period are Non-Adjusting events (IAS 10). They are disclosed only.", "Yes, if the shareholders approve it before the audit report.", "Yes, as a provision."], "ans": 1, "exp": "IAS 10 specifically states that dividends declared after the reporting period are non-adjusting events because no obligation existed at the reporting date.*"}, {"q": "Scenario: Inventory costing $100,000 was held at year-end (31 Dec). On 10 January, it was sold for $80,000 due to water damage that occurred in November. Question: Treatment?", "options": ["Adjusting Event \u2013 Write down inventory by $20,000 in 2023.", "Non-Adjusting Event \u2013 Disclose in notes.", "Adjusting Event \u2013 Write down by $20,000 only if the auditor saw the water damage.", "Record loss in 2024."], "ans": 0, "exp": "The sale provides evidence of the Net Realizable Value (NRV) at the reporting date. Since the damage happened in November (before year-end), the lower value existed at year-end.*"}, {"q": "Scenario: A fraud committed by the cashier during 2023 was discovered on 5 February 2024. Question: Treatment?", "options": ["Non-Adjusting \u2013 Disclose in 2023.", "Adjusting \u2013 The fraud occurred during 2023, so the loss existed at the reporting date.", "Adjusting \u2013 Only if the cashier confesses.", "Record in 2024."], "ans": 1, "exp": "Discovery of fraud or errors that show the financial statements were incorrect at the reporting date is an adjusting event.*"}, {"q": "Scenario: On 20 January 2024, the government announced a new tax law increasing the corporate tax rate retrospectively from 1 January 2024. Question: Treatment in 31 Dec 2023 accounts?", "options": ["Adjusting \u2013 Recalculate deferred tax at the new rate.", "Non-Adjusting \u2013 The law was enacted after year-end. Disclose the impact.", "Adjusting \u2013 Because it affects future tax payments.", "Ignore."], "ans": 1, "exp": "Changes in tax rates enacted after the reporting period are non-adjusting events. The current tax liability for 2023 is based on 2023 laws.*"}, {"q": "Scenario: A company buys an investment property on 15 January 2024. The price was negotiated in December 2023. Question: Treatment in 2023 FS?", "options": ["Adjusting \u2013 Record the asset because negotiation happened in 2023.", "Non-Adjusting \u2013 Asset was acquired after year-end. Disclose if material.", "Adjusting \u2013 Record a provision for the purchase price.", "Contingent Liability."], "ans": 1, "exp": "The transaction (transfer of control/risks) occurred after year-end. Negotiation does not equal a transaction. It is a non-adjusting event (major asset purchase).*"}, {"q": "Scenario: On 5 January 2024, a major debtor pays the full amount outstanding at 31 December 2023. Question: What does this indicate to the auditor?", "options": ["It is an adjusting event confirming the recoverability (Good Debt) at year-end.", "It is a non-adjusting event.", "It is irrelevant.", "It confirms the debt was bad."], "ans": 0, "exp": "Receipt of cash after year-end confirms that the receivable existed and was valid/recoverable at year-end. It supports the valuation assertion.*"}, {"q": "Scenario: On 10 February 2024, the company announces a major restructuring plan involving closing a division. No plan existed at 31 Dec 2023. Question:", "options": ["Adjusting \u2013 Create a restructuring provision in 2023.", "Non-Adjusting \u2013 Disclose the nature and estimate of costs in 2023 notes.", "Adjusting \u2013 Impair all assets of that division.", "Ignore."], "ans": 1, "exp": "Since the obligation/decision did not exist at the reporting date, no provision can be recognized in 2023. It is a material non-adjusting event.*\n\ud83d\udd35 Section 2: Auditor's Responsibility (Phases)"}, {"q": "Scenario: What is the auditor\u2019s duty regarding subsequent events occurring between the Financial Statement date and the Date of the Auditor\u2019s Report?", "options": ["Passive Duty \u2013 Only act if informed by management.", "Active Duty \u2013 Perform procedures to identify all material subsequent events.", "No Duty.", "Duty only for fraud."], "ans": 1, "exp": "The auditor has an active duty to perform audit procedures (e.g., reading minutes, inquiring legal counsel) up to the date of the audit report.*"}, {"q": "Scenario: The auditor signed the report on 15 March. On 20 March (before FS are issued), the auditor learns of a fire that destroyed a major factory on 25 February. Question: Does the auditor have a responsibility to act?", "options": ["No, the report is already signed.", "Yes, usually management informs the auditor. If the auditor knows, they must discuss with management and amend the FS/Report if necessary.", "Yes, the auditor must perform active search procedures again.", "No, because it is a non-adjusting event."], "ans": 1, "exp": "After the report date but before FS issue, the auditor has no active duty to search. However, if they become aware of a fact that may affect the FS, they must act (Passive Duty).*"}, {"q": "Scenario: The financial statements were issued on 30 March. On 10 April, the auditor discovers a material fraud that existed at the year-end. Question: What should the auditor do?", "options": ["Nothing, the audit is over.", "Discuss with management and determine if the FS need revision.", "Issue a new audit report immediately without talking to management.", "Resign."], "ans": 1, "exp": "Even after issue, if a fact is discovered that existed at the report date and would have changed the opinion, the auditor must discuss with management and take action (e.g., reissue FS).*"}, {"q": "Scenario: Management refuses to amend the financial statements for a material adjusting event discovered before the audit report is signed. Question: What kind of opinion should the auditor issue?", "options": ["Unmodified.", "Qualified or Adverse Opinion.", "Emphasis of Matter.", "Disclaimer."], "ans": 1, "exp": "If management refuses to correct a material misstatement (adjusting event), the auditor must modify the opinion (Qualified or Adverse).*"}, {"q": "Scenario: Which of the following is NOT a standard audit procedure to identify subsequent events?", "options": ["Reviewing management procedures for identifying SEs.", "Reading minutes of board meetings held after year-end.", "Inquiring of the entity's lawyers.", "Recalculating depreciation for the previous year."], "ans": 3, "exp": "Recalculating depreciation for the previous year is a standard substantive test for that year, not a procedure to identify subsequent events.*"}, {"q": "Scenario: The auditor's report is dated 1 March. Management amends the FS on 10 March due to a subsequent event. Question: How does this affect the audit report date?", "options": ["The date remains 1 March.", "The auditor must perform procedures on the amendment and extend the report date to 10 March (or later).", "The auditor issues a dual-dated report.", "Both B and C are possible options."], "ans": 3, "exp": "The auditor cannot date the report earlier than the date on which they have obtained evidence. If FS are amended, the auditor updates the date or uses dual dating.*"}, {"q": "Scenario: What is \"Dual Dating\" in an audit report?", "options": ["Signing with two different pens.", "Dating the report generally on 1 March, but dating a specific Note regarding a subsequent event on 10 March.", "Two partners signing the report.", "Dating the report on the first and last day of the audit."], "ans": 1, "exp": "Dual dating limits the auditor's active responsibility for the specific subsequent event to the later date, while keeping the responsibility for the rest of the audit at the original date.*"}, {"q": "Scenario: A material bad debt is confirmed after the FS are issued. Management agrees to recall and reissue the FS. Question: What must the auditor do regarding the new audit report?", "options": ["Issue a new report with an Emphasis of Matter (EOM) paragraph referring to the reissue note.", "Issue the exact same report as before.", "Issue a Qualified opinion.", "Refuse to sign."], "ans": 0, "exp": "When FS are reissued, the auditor issues a new report and includes an EOM (or OM) paragraph drawing attention to the note explaining the revision.*"}, {"q": "Scenario: The management refuses to recall FS containing a material error discovered after issuance. The auditor believes action is necessary. Question: What is the auditor's last resort?", "options": ["Seek legal advice and take steps to prevent reliance on the auditor's report (e.g., speaking at the AGM or advertising).", "Call the police.", "Sue the management.", "Do nothing."], "ans": 0, "exp": "If management refuses to act, the auditor must take steps to warn users not to rely on the erroneous report, usually after seeking legal advice.*"}, {"q": "Scenario: During the \"Active Duty\" period, the auditor reads the company's latest interim financial statements (e.g., Jan-Feb accounts). Question: Why?", "options": ["To check if the accountant is working.", "To identify trends or significant changes that might indicate subsequent events (e.g., loss of sales, new liabilities).", "To audit the interim accounts.", "It is not required."], "ans": 1, "exp": "Reviewing interim accounts is a standard procedure to identify potential subsequent events affecting the year-end position.*\n\ud83d\udfe0 Section 3: Going Concern & Subsequent Events"}, {"q": "Scenario: A fire destroys the company\u2019s only production plant on 15 January 2024 (After year-end). The company has no insurance and cannot continue operations. Question: How does this affect the 2023 Financial Statements?", "options": ["Non-Adjusting Event \u2013 Disclose only.", "Adjusting Event \u2013 Because the Going Concern assumption is no longer valid.", "Ignore.", "Write off the asset only."], "ans": 1, "exp": "Exception Rule: If a non-adjusting event (fire) causes the Going Concern assumption to fail, it becomes an Adjusting Event. The FS must be prepared on a breakup basis.*"}, {"q": "Scenario: On 20 February 2024, the exchange rate collapses, making the company\u2019s foreign currency loan repayable immediately (covenant breach). The company does not have the cash to pay. Question:", "options": ["Non-Adjusting \u2013 Disclose exchange loss.", "Adjusting \u2013 The company is no longer a going concern.", "Adjusting \u2013 Only for the loan value.", "Ignore."], "ans": 1, "exp": "If a subsequent event (FX crash + breach) triggers a Going Concern crisis, the FS basis changes. It overrides the \"Non-Adjusting\" nature of the event.*"}, {"q": "Scenario: Management decides to liquidate the company on 10 March 2024 (before audit report). Question:", "options": ["Prepare 2023 FS on Going Concern basis but disclose the liquidation.", "Prepare 2023 FS on Liquidation (Break-up) basis.", "Prepare 2023 FS normally.", "Adjust only the assets to be sold."], "ans": 1, "exp": "If management intends to liquidate, the Going Concern assumption is invalid. The FS must be adjusted to the liquidation basis.*"}, {"q": "Scenario: A major customer cancels a contract on 5 February 2024. This customer represented 90% of revenue. Question:", "options": ["Non-Adjusting \u2013 Disclose loss of contract.", "Adjusting \u2013 Prepare FS on non-going concern basis.", "Adjusting \u2013 Write off receivables only.", "Non-Adjusting \u2013 Do nothing."], "ans": 1, "exp": "Loss of a key customer that threatens survival affects the Going Concern assumption, making it an adjusting event (requiring a change in accounting basis).*"}, {"q": "Scenario: The auditor identifies a material uncertainty regarding Going Concern due to a subsequent event (e.g., loss of a supplier). Management has disclosed this uncertainty adequately. Question: What opinion?", "options": ["Unmodified Opinion + Material Uncertainty Related to Going Concern section.", "Qualified Opinion.", "Adverse Opinion.", "Disclaimer."], "ans": 0, "exp": "If the GC assumption is still appropriate but uncertainty exists and is disclosed, the auditor adds a dedicated section (MUG) but does not modify the opinion.*\n\ud83d\udfe3 Section 4: Specific Procedures & Evidence"}, {"q": "Scenario: Why does the auditor inquire of management as to whether any subsequent events have occurred?", "options": ["Because management is responsible for identifying and recording them.", "Because the auditor is lazy.", "To test management's honesty.", "It is the only procedure required."], "ans": 0, "exp": "Management has the primary responsibility to identify SEs. The auditor inquires to ensure management has a process in place.*"}, {"q": "Scenario: Which document is most likely to provide evidence of subsequent litigation settlements?", "options": ["Bank Statement.", "Minutes of Board/Audit Committee meetings held after year-end.", "Sales Invoices.", "Fixed Asset Register."], "ans": 1, "exp": "Board minutes discuss significant strategic and legal issues, including lawsuit settlements.*"}, {"q": "Scenario: The auditor reviews the \"Cash Book\" for payments made after year-end. What are they looking for?", "options": ["Payments for personal expenses.", "Payments that relate to unrecorded liabilities at year-end (Completeness of Liabilities).", "Future sales.", "Salary payments."], "ans": 1, "exp": "Reviewing post-year-end payments helps identify liabilities that existed at year-end but were not recorded (Adjusting event).*"}, {"q": "Scenario: The auditor requests a \"Written Representation\" from management regarding subsequent events. What does this confirm?", "options": ["That no fraud occurred.", "That all subsequent events requiring adjustment or disclosure have been identified and treated.", "That the auditor is released from liability.", "That the inventory is safe."], "ans": 1, "exp": "Written representations provide evidence that management has fulfilled its responsibility to identify and report SEs.*"}, {"q": "Scenario: The auditor checks the \"Sales Price\" of inventory sold after year-end. This is a procedure to verify:", "options": ["Sales Occurrence.", "Inventory Net Realizable Value (NRV) at year-end.", "Cash existence.", "Depreciation."], "ans": 1, "exp": "Subsequent sales price is the best evidence of the NRV of inventory held at the reporting date (Adjusting event).*\n\ud83d\udfe4 Section 5: Mixed Scenarios"}, {"q": "Scenario: On 28 February 2024, a thief stole cash from the safe. The theft happened that morning. Question: Treatment in 2023 accounts?", "options": ["Adjusting \u2013 Reduce cash balance.", "Non-Adjusting \u2013 The cash existed at 31 Dec 2023. Disclose theft if material.", "Adjusting \u2013 It is fraud.", "Ignore."], "ans": 1, "exp": "The theft is a new event in 2024. At 31 Dec 2023, the cash was safe. It is non-adjusting.*"}, {"q": "Scenario: A cheque received from a customer on 28 December 2023 was dishonored (bounced) on 5 January 2024. Question:", "options": ["Non-Adjusting.", "Adjusting \u2013 Reverse the bank receipt and reinstate the receivable.", "Ignore.", "Write off as bad debt."], "ans": 1, "exp": "The dishonor confirms that the cash was effectively not received at year-end. The entry must be reversed.*"}, {"q": "Scenario: The company guarantees a loan for a subsidiary. The subsidiary defaults on 15 February 2024 (financial trouble existed in 2023). Question:", "options": ["Adjusting \u2013 Provide for the liability under the guarantee.", "Non-Adjusting.", "Contingent Liability only.", "Ignore."], "ans": 0, "exp": "The default confirms the probable outflow of resources for a condition (subsidiary's distress) that existed at year-end.*"}, {"q": "Scenario: A property valuation report received on 20 January 2024 shows the property value at 31 December 2023 was lower than the carrying amount. Question:", "options": ["Adjusting \u2013 Impair the property.", "Non-Adjusting \u2013 Report received later.", "Ignore.", "Disclose only."], "ans": 0, "exp": "The report provides evidence of the value at the reporting date. It is purely confirming a fact about 31 Dec.*"}, {"q": "Scenario: The company issues new shares on 1 February 2024 to raise cash. Question:", "options": ["Adjusting \u2013 Increase Share Capital.", "Non-Adjusting \u2013 Disclose (Material change in capital structure).", "Ignore.", "Adjusting \u2013 Going concern support."], "ans": 1, "exp": "Issuing shares is a significant non-adjusting event. It changes the financial position after year-end.*"}, {"q": "Scenario: The auditor is appointed after the year-end. They cannot verify the inventory opening balance or year-end balance properly. Question: Is this a Subsequent Event issue?", "options": ["Yes.", "No, this is a Scope Limitation issue on existence/valuation.", "Yes, because they were appointed late.", "No, it is a Going Concern issue."], "ans": 1, "exp": "This is a classic Scope Limitation (Audit Report Chapter), not primarily a subsequent event issue, though subsequent sales might help verify value.*"}, {"q": "Scenario: A customer returns goods on 10 January 2024 that were sold on 28 December 2023 due to defects. Question:", "options": ["Non-Adjusting \u2013 Sales return in 2024.", "Adjusting \u2013 Record Sales Return in 2023.", "Ignore.", "Record as warranty expense."], "ans": 1, "exp": "The defect existed at the time of sale (Dec 2023). The return confirms the sale was reversed. It is an adjusting event.*"}, {"q": "Scenario: The government waives a loan on 15 January 2024. The company was in breach of conditions at 31 Dec 2023. Question:", "options": ["Adjusting \u2013 Reclassify loan as non-current (if waiver is for >12 months).", "Non-Adjusting \u2013 Waiver received after year-end. Loan remains Current Liability at 31 Dec.", "Adjusting \u2013 Write off loan.", "Ignore."], "ans": 1, "exp": "At 31 Dec, the breach existed, so the bank could demand payment. The waiver came later. It is usually Non-Adjusting (Loan stays Current), but disclosure is critical.*"}, {"q": "Scenario: Auditor discovers a calculation error in the bonus accrual for 2023 on 5 February 2024. Question:", "options": ["Adjusting \u2013 Correct the error.", "Non-Adjusting.", "Ignore if immaterial.", "A and C."], "ans": 3, "exp": "Errors are adjusting events. However, if it is immaterial, the auditor might aggregate it with other errors rather than forcing an adjustment immediately.*"}, {"q": "Scenario: Which standard governs Subsequent Events?", "options": ["IAS 37.", "ISA 560 & IAS 10.", "ISA 700.", "IFRS 15."], "ans": 1, "exp": "IAS 10 (Accounting Standard) defines the treatment, and ISA 560 (Audit Standard) defines the auditor's responsibilities.*\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Trade Receivables (Debtors)"}, {"q": "Scenario: Debtors' turnover days have increased from 45 to 90 days. The auditor suspects that some debts might not be recoverable. Question: Which assertion is primarily at risk?", "options": ["Existence", "Valuation & Allocation", "Rights and Obligations", "Completeness"], "ans": 1, "exp": "If debtors are not paying on time, the recoverable amount (Valuation) is doubtful, requiring a provision for bad debts."}, {"q": "Scenario: The auditor sends a positive confirmation request to a major customer, but receives no reply after two reminders. Question: What is the best alternative procedure?", "options": ["Assume the balance is correct.", "Check \"Cash received after year-end\" from that customer.", "Write off the debt.", "Ask management to sign a representation letter."], "ans": 1, "exp": "Checking post-year-end cash receipts proves that the debt existed and was valid/recoverable at year-end."}, {"q": "Scenario: A company records sales when the \"Sales Order\" is received, not when goods are dispatched. Question: Which assertion is violated?", "options": ["Completeness", "Occurrence (Cut-off issue)", "Valuation", "Classification"], "ans": 1, "exp": "Revenue should occur when the performance obligation is satisfied (dispatch). Booking at order stage violates Occurrence/Cut-off."}, {"q": "Scenario: The auditor selects a sample of shipping documents (GDNs) and traces them to the Sales Ledger. Question: This test primarily verifies:", "options": ["Existence (Did the sale happen?)", "Completeness (Are all sales recorded?)", "Valuation", "Rights"], "ans": 1, "exp": "Tracing FROM source documents (GDN) TO the ledger tests if everything that happened was recorded (Completeness)."}, {"q": "Scenario: To verify the \"Cut-off\" assertion for sales, the auditor should select transactions from:", "options": ["The middle of the year.", "A few days before and after the year-end.", "The start of the year.", "The largest invoices only."], "ans": 1, "exp": "Cut-off tests focus on the boundary (year-end) to ensure transactions are in the correct period."}, {"q": "Scenario: A debtor confirms a balance of $80,000, but the company\u2019s ledger shows $100,000. The difference is due to a cheque sent by the debtor on 29 Dec but received by the company on 4 Jan. Question: Is this a misstatement?", "options": ["Yes, the company overstated debtors.", "No, this is a timing difference (Cash in Transit).", "Yes, the debtor is lying.", "No, write off the difference."], "ans": 1, "exp": "The debtor paid in Dec, so they say $80k. The company got cash in Jan, so they show $100k at Dec 31. This is a valid timing difference."}, {"q": "Scenario: The auditor reviews the \"Aged Receivables Report\" and discusses old balances with the Credit Controller. Question: What is the objective?", "options": ["To check if debtors exist.", "To assess the adequacy of the provision for bad debts (Valuation).", "To check arithmetic accuracy.", "To verify sales."], "ans": 1, "exp": "Old debts suggest recoverability issues. This procedure targets Valuation."}, {"q": "Scenario: Which document provides the best evidence that a receivable \"Exists\"?", "options": ["Sales Invoice.", "External Confirmation (Direct response).", "Management Representation.", "Sales Order."], "ans": 1, "exp": "Third-party confirmation is more reliable than internal documents."}, {"q": "Scenario: A customer claims they returned goods on 30 Dec, but the company issued a Credit Note on 5 Jan. Question: The company recorded the return in Jan.", "options": ["Correct treatment.", "Incorrect. Adjusting event. Sales return should be recorded in Dec (Cut-off error).", "Ignore.", "Disclose only."], "ans": 1, "exp": "The return happened in Dec. The credit note is just paper. The return must be booked in the correct period (Dec)."}, {"q": "Scenario: The auditor compares the total balance of the Sales Ledger Control Account with the list of individual debtors. Question: This tests:", "options": ["Accuracy and Valuation.", "Existence.", "Rights.", "Presentation."], "ans": 0, "exp": "Agreeing the total to the individual list checks arithmetic accuracy.\n\ud83d\udd35 Section 2: Trade Payables (Creditors) & Purchases"}, {"q": "Scenario: The auditor wants to test for \"Unrecorded Liabilities\" (Completeness of Payables). Question: What is the best procedure?", "options": ["Select a sample from the Payables Ledger and vouch to invoices.", "Review payments made after year-end and trace to the year-end ledger.", "Check large invoices.", "Ask management."], "ans": 1, "exp": "If a company hides a liability, it won't be in the ledger. But they will pay it eventually. Checking post-year-end payments finds these hidden items."}, {"q": "Scenario: The auditor selects a sample of \"Goods Received Notes\" (GRNs) issued just before year-end and checks if they are included in Trade Payables. Question: This tests:", "options": ["Existence.", "Cut-off and Completeness.", "Valuation.", "Rights."], "ans": 1, "exp": "Goods received = Liability. Checking GRN -> Ledger ensures the liability was recorded in the correct period (Cut-off/Completeness)."}, {"q": "Scenario: Supplier statements show a balance higher than the company\u2019s ledger. The difference is due to \"Goods in Transit\" (Title passed to company, but goods not yet arrived). Question: Should the company record the liability?", "options": ["No, goods haven't arrived.", "Yes, if the terms are FOB Shipping Point (Risk passed on dispatch).", "Only when invoice arrives.", "Never."], "ans": 1, "exp": "If risk/rewards passed, the liability (and inventory) must be recorded even if goods are in transit."}, {"q": "Scenario: Why is \"External Confirmation\" less common for Payables than Receivables?", "options": ["Suppliers rarely reply.", "The main risk in Payables is \"Understatement\" (Completeness), and confirmations test \"Existence\".", "It is too expensive.", "Suppliers lie."], "ans": 1, "exp": "Companies try to hide liabilities (Understatement). Confirmation proves something exists (Overstatement). So, searching for unrecorded liabilities is more important than confirming what's already there."}, {"q": "Scenario: To verify the \"Rights and Obligations\" of payables, the auditor checks:", "options": ["Supplier Invoices.", "Cash paid.", "GRNs.", "Sales invoices."], "ans": 0, "exp": "The invoice is the legal demand for payment, proving the obligation."}, {"q": "Scenario: A large purchase was recorded on 2 Jan. The GRN shows the goods were received on 31 Dec. Question:", "options": ["Payables are understated at year-end (Cut-off error).", "Payables are overstated.", "Correct.", "Ignore."], "ans": 0, "exp": "Goods received in Dec = Liability in Dec. Recording in Jan is a Cut-off error."}, {"q": "Scenario: The auditor calculates the \"Payables Turnover Ratio\" and compares it to the prior year. Question: This is an example of:", "options": ["Test of Detail.", "Substantive Analytical Procedure.", "Test of Control.", "Inquiry."], "ans": 1, "exp": "Ratio analysis is an Analytical Procedure."}, {"q": "Scenario: A supplier balance is in foreign currency. The auditor checks the exchange rate used at year-end. Question: This tests:", "options": ["Existence.", "Valuation.", "Cut-off.", "Rights."], "ans": 1, "exp": "Converting FX balances at the correct closing rate is a Valuation issue."}, {"q": "Scenario: Zero-balance accounts in the Payables Ledger should be:", "options": ["Ignored.", "Selected for confirmation/review (Risk of unrecorded liability).", "Deleted.", "Assumed correct."], "ans": 1, "exp": "A zero balance might mean \"We hid the invoice,\" so active suppliers with zero balances are risky."}, {"q": "Scenario: The auditor vouches a sample of recorded payables to Supplier Invoices and GRNs. Question: This tests:", "options": ["Completeness.", "Existence (Did the purchase really happen?).", "Presentation.", "Disclosure."], "ans": 1, "exp": "Ledger -> Source Document verifies Existence/Occurrence.\n\ud83d\udfe0 Section 3: Inventory (Stock)"}, {"q": "Scenario: The primary objective of attending the physical stock count is to verify:", "options": ["Valuation.", "Existence and Condition.", "Rights.", "Ownership."], "ans": 1, "exp": "Counting proves it's there (Existence) and seeing it proves it's not broken (Condition/Valuation)."}, {"q": "Scenario: During the count, the auditor observes \"slow-moving\" or dusty items. Question: This observation provides evidence for:", "options": ["Existence.", "Valuation (NRV risk).", "Rights.", "Completeness."], "ans": 1, "exp": "Dusty/old items may be obsolete, meaning Net Realizable Value < Cost."}, {"q": "Scenario: The auditor records the serial numbers of the last 5 GRNs and first 5 GDNs during the count. Question: Why?", "options": ["To check Cut-off.", "To check Existence.", "To check Rights.", "For fun."], "ans": 0, "exp": "Noting the last document number ensures that pre-year-end movements are in this year and post-year-end are in next year."}, {"q": "Scenario: Inventory is held by a third party (Public Warehouse). Question: How does the auditor verify it?", "options": ["Count it personally (if material) or Request External Confirmation.", "Ignore it.", "Ask management.", "Check sales invoices."], "ans": 0, "exp": "Confirming with the third party is the standard procedure. If very material, a visit might be needed."}, {"q": "Scenario: The company values inventory using FIFO. The auditor checks the math. Question: This tests:", "options": ["Existence.", "Valuation and Allocation.", "Rights.", "Completeness."], "ans": 1, "exp": "Cost formulas (FIFO/Weighted Avg) relate to the value assigned to the stock."}, {"q": "Scenario: A manufacturing company includes \"Production Overheads\" in inventory cost. The auditor checks the allocation basis. Question:", "options": ["Valuation.", "Existence.", "Rights.", "Cut-off."], "ans": 0, "exp": "Ensuring overheads are absorbed correctly (IAS 2) is a valuation test."}, {"q": "Scenario: During the count, the auditor sees stock marked \"Sold - Awaiting Delivery\". Question: This stock should be:", "options": ["Included in the count.", "Excluded from the count (Title passed to customer).", "Counted as damaged.", "Donated."], "ans": 1, "exp": "If sold, it's not the company's asset anymore (Rights assertion), even if it's still in the warehouse."}, {"q": "Scenario: Inventory turnover ratio has slowed down significantly (Stock is sitting longer). Question: What is the risk?", "options": ["Inventory is understated.", "Inventory is overstated (Obsolete stock needs write-down).", "Sales are overstated.", "Cash is overstated."], "ans": 1, "exp": "Slow turnover usually indicates obsolescence, meaning Inventory Cost > NRV."}, {"q": "Scenario: The auditor checks the \"Purchase Invoices\" for items in inventory. Question: This tests:", "options": ["Existence.", "Cost (Valuation).", "Cut-off.", "Completeness."], "ans": 1, "exp": "Vouching to invoices verifies the \"Cost\" component of valuation."}, {"q": "Scenario: Management estimates the \"Work in Progress\" (WIP) % of completion. Question: The auditor challenges the estimate by comparing it to subsequent completion costs.", "options": ["Existence.", "Valuation (Accuracy of Estimate).", "Rights.", "Completeness."], "ans": 1, "exp": "Accounting estimates (like % completion) are valuation risks.\n\ud83d\udfe3 Section 4: Tangible Non-Current Assets (PPE)"}, {"q": "Scenario: To verify the \"Existence\" of a new machine, the auditor should:", "options": ["Check the Invoice.", "Physically inspect the machine on the factory floor.", "Check the Board Minutes.", "Ask the CFO."], "ans": 1, "exp": "Physical inspection is the best evidence for existence."}, {"q": "Scenario: To verify \"Rights and Obligations\" (Ownership) of a building, the auditor checks:", "options": ["Physical existence.", "Title Deeds / Registry Documents.", "Depreciation schedule.", "Repairs expense."], "ans": 1, "exp": "Only legal documents (Title Deeds) prove ownership."}, {"q": "Scenario: The company capitalized \"Repairs and Maintenance\" cost as an Asset. Question: Which assertion is violated?", "options": ["Existence.", "Classification (or Valuation).", "Completeness.", "Rights."], "ans": 1, "exp": "Expenses should not be assets. This is a classification/valuation error."}, {"q": "Scenario: The auditor recalculates the depreciation expense. Question: This tests:", "options": ["Existence.", "Valuation and Allocation.", "Rights.", "Cut-off."], "ans": 1, "exp": "Checking the math of depreciation ensures the asset's carrying value is correct."}, {"q": "Scenario: A machine is idle and covered in dust. Question: What should the auditor check?", "options": ["Impairment (Valuation).", "Existence.", "Rights.", "Ownership."], "ans": 0, "exp": "Idle assets may be impaired (Value in Use is low)."}, {"q": "Scenario: The auditor reviews the \"Repairs and Maintenance\" account in the P&L. Question: Why?", "options": ["To find unrecorded liabilities.", "To check for capital items wrongly expensed (Completeness of Assets).", "To verify cash.", "To reduce tax."], "ans": 1, "exp": "Companies sometimes expense assets to reduce profit/tax. Reviewing R&M ensures assets are not hidden there."}, {"q": "Scenario: A company revalues its Land & Buildings. The auditor hires an expert valuer. Question: This relates to:", "options": ["Existence.", "Valuation.", "Cut-off.", "Rights."], "ans": 1, "exp": "Revaluation is purely about getting the correct Fair Value."}, {"q": "Scenario: An asset was sold during the year. The auditor checks the calculation of \"Profit/Loss on Disposal\". Question:", "options": ["Valuation / Accuracy.", "Existence.", "Rights.", "Cut-off."], "ans": 0, "exp": "Verifying the P&L on disposal ensures the transaction is recorded accurately."}, {"q": "Scenario: The \"Fixed Asset Register\" (FAR) lists assets that cannot be found on the floor. Question:", "options": ["Assets are understated.", "Assets are overstated (Existence failure).", "Depreciation is too high.", "Correct."], "ans": 1, "exp": "If it's in the book but not on the floor, the asset balance is overstated."}, {"q": "Scenario: Self-constructed assets (e.g., a factory built by the company). The auditor checks labor and material costs capitalized. Question:", "options": ["Valuation.", "Existence.", "Rights.", "Completeness."], "ans": 0, "exp": "Verifying the cost build-up ensures the asset is valued correctly.\n\ud83d\udfe4 Section 5: Cash & Bank"}, {"q": "Scenario: The primary test for \"Bank Balance\" is:", "options": ["Physical Count.", "Bank Confirmation Letter directly from the bank.", "Checking the Cheque Book.", "Asking the cashier."], "ans": 1, "exp": "Direct confirmation from the bank verifies balance, loans, and rights."}, {"q": "Scenario: The \"Bank Reconciliation Statement\" includes \"Unpresented Cheques\" (Cheques written but not yet cleared). Question: The auditor checks if these cleared after year-end. Why?", "options": ["To verify they were valid payments (Existence/Cut-off).", "To cancel them.", "To write new cheques.", "To blame the bank."], "ans": 0, "exp": "If a cheque clears later, it proves it was a real liability at year-end."}, {"q": "Scenario: The bank letter shows a loan that is not in the ledger. Question:", "options": ["Completeness of Liabilities.", "Existence of Cash.", "Valuation.", "Rights."], "ans": 0, "exp": "The company missed recording a loan (Unrecorded Liability)."}, {"q": "Scenario: Cash count at year-end. The auditor finds \"IOUs\" (Borrowing slips) in the cash box. Question:", "options": ["Count them as cash.", "Exclude them; they are receivables/advances, not cash.", "Burn them.", "Ignore."], "ans": 1, "exp": "IOUs are not cash; they are debts owed by employees."}, {"q": "Scenario: \"Teeming and Lading\" (Lapping) risk. Question: The auditor compares the dates in the Cash Book vs Bank Statement.", "options": ["Cut-off/Timing.", "Valuation.", "Rights.", "Classification."], "ans": 0, "exp": "Delays in depositing cash might indicate fraud.\n\u26ab Section 6: Liabilities & Equity"}, {"q": "Scenario: To verify \"Share Capital\", the auditor checks:", "options": ["Board Minutes and CR2/Company Registry return.", "Sales Invoices.", "Fixed Assets.", "Bank Statement only."], "ans": 0, "exp": "Share issues must be authorized (Board) and filed with the regulator."}, {"q": "Scenario: The auditor reviews \"Legal Expense\" account. Question: Why?", "options": ["To verify lawyer fees.", "To identify potential litigation/contingent liabilities (Completeness).", "To save money.", "To check bank."], "ans": 1, "exp": "Payments to lawyers suggest legal cases. The auditor checks if a provision/contingency is needed."}, {"q": "Scenario: A loan has a covenant (e.g., maintain 2:1 current ratio). Question: The auditor calculates the ratio.", "options": ["Valuation.", "Compliance (Presentation/Disclosure of current vs non-current).", "Existence.", "Rights."], "ans": 1, "exp": "If the covenant is breached, the loan becomes Current. This is a presentation/classification issue."}, {"q": "Scenario: Accruals (e.g., electricity). Auditor compares this year vs last year. Question:", "options": ["Test of Detail.", "Substantive Analytical Procedure.", "Test of Control.", "Inquiry."], "ans": 1, "exp": "Comparison/Trend analysis is analytical."}, {"q": "Scenario: Warranty Provision. The auditor reviews the history of returns. Question:", "options": ["Valuation (Reasonableness of Estimate).", "Existence.", "Rights.", "Cut-off."], "ans": 0, "exp": "Provisions are estimates. Checking history helps verify if the amount is reasonable.\n\ud83d\udd34 Section 7: Audit Evidence & General Concepts"}, {"q": "Scenario: Which is the most reliable evidence?", "options": ["Auditor\u2019s direct observation.", "Invoice copy.", "Management representation.", "Client spreadsheet."], "ans": 0, "exp": "Direct knowledge (seeing it yourself) is stronger than documents or hearsay."}, {"q": "Scenario: Which is least reliable?", "options": ["Oral representation by management.", "Bank Confirmation.", "Supplier Statement.", "Physical Inspection."], "ans": 0, "exp": "Oral evidence is weak and must be documented/corroborated."}, {"q": "Scenario: \"Vouching\" means going from:", "options": ["Ledger to Source Document (Testing Existence).", "Source Document to Ledger (Testing Completeness).", "Bank to Cash.", "Start to Finish."], "ans": 0, "exp": "Vouching \"back\" checks if the recorded item is real."}, {"q": "Scenario: \"Tracing\" means going from:", "options": ["Ledger to Source.", "Source Document to Ledger (Testing Completeness).", "Top to Bottom.", "Asset to Liability."], "ans": 1, "exp": "Tracing \"forward\" checks if the real event was recorded."}, {"q": "Scenario: Analytical procedures are required at which stages?", "options": ["Planning and Completion.", "Execution only.", "Reporting only.", "Never."], "ans": 0, "exp": "Planning (Risk Assessment) and Completion (Overall Review) are mandatory stages for AP."}, {"q": "Scenario: Using the work of an Expert (e.g., Diamond Valuer). Question: Who is responsible for the audit opinion?", "options": ["The Expert.", "The Auditor.", "Management.", "Jointly."], "ans": 1, "exp": "The auditor is solely responsible. They must check the expert's competence."}, {"q": "Scenario: Management refuses to give a Representation Letter. Question:", "options": ["Unmodified.", "Disclaimer (Scope Limitation).", "Qualified.", "EOM."], "ans": 1, "exp": "Refusal creates a pervasive doubt on all evidence."}, {"q": "Scenario: \"Positive Confirmation\" means:", "options": ["Reply only if you disagree.", "Reply in all cases (Agree or Disagree).", "Reply if you are happy.", "Send cash."], "ans": 1, "exp": "Positive means \"Please reply regardless\". Negative means \"Reply only if wrong\"."}, {"q": "Scenario: \"Negative Confirmation\" is used when:", "options": ["Risk is low, balances are small, and many.", "Risk is high.", "Balances are large.", "Fraud is suspected."], "ans": 0, "exp": "Negative confirmation is weak, so it's only used for low-risk, small-balance populations (e.g., utility customers).\n\ud83d\udfe0 Section 8: Specific Items (Leases, Intangibles, Related Parties)"}, {"q": "Scenario: IFRS 16 Leases. The auditor checks if \"Right of Use Asset\" and \"Lease Liability\" are recorded. Question: Completeness.", "options": ["Check rent expense account for payments that look like leases.", "Ask the driver.", "Check sales.", "Check bank."], "ans": 0, "exp": "If a lease is off-balance sheet, payments will be hiding in \"Rent Expense\"."}, {"q": "Scenario: Related Party Transactions. Question: Main audit risk?", "options": ["They are illegal.", "They may not be at \"Arm's Length\" or not disclosed.", "They are always cash.", "They are tax-free."], "ans": 1, "exp": "Transactions with friends/family might be at fake prices or hidden."}, {"q": "Scenario: Development Costs (Intangible). Question: The auditor checks \"Technical Feasibility\".", "options": ["Valuation/Existence.", "Cut-off.", "Rights.", "Presentation."], "ans": 0, "exp": "To be an asset, it must work (Feasible). If not, it's an expense."}, {"q": "Scenario: Contingent Liability (Lawsuit). Question: Lawyer says \"Probable\" loss.", "options": ["Disclose only.", "Record Provision.", "Ignore.", "Record Asset."], "ans": 1, "exp": "Probable (>50%) outflow = Provision (Liability)."}, {"q": "Scenario: Lawyer says \"Possible\" loss. Question:", "options": ["Disclose only (Contingent Liability).", "Record Provision.", "Ignore.", "Asset."], "ans": 0, "exp": "Possible (<50%) = Disclosure.\n\ud83d\udd35 Section 9: Advanced Scenarios"}, {"q": "Scenario: Payroll. Auditor compares headcount x average salary to total expense. Question:", "options": ["Test of Control.", "Substantive Analytical Procedure.", "Inquiry.", "Walkthrough."], "ans": 1, "exp": "Developing an expectation and comparing is analytical."}, {"q": "Scenario: Ghost Employees. Question: Best test?", "options": ["Surprise Pay-out (Witnessing distribution).", "Checking the math.", "Asking the manager.", "Reviewing the budget."], "ans": 0, "exp": "Seeing the human receive the cash proves existence."}, {"q": "Scenario: Opening Balances (Initial Audit). Question:", "options": ["Check prior auditor's working papers or audit current year opening entries.", "Ignore.", "Assume correct.", "Disclaim."], "ans": 0, "exp": "Auditor must verify opening balances affect current period."}, {"q": "Scenario: Estimates (Fair Value). Question: Auditor develops their own \"Point Estimate\" to compare with management.", "options": ["Allowed and effective.", "Not allowed.", "Waste of time.", "Illegal."], "ans": 0, "exp": "Independent estimation is a strong verification method."}, {"q": "Scenario: Subsequent Events review is part of:", "options": ["Risk Assessment.", "Substantive Procedures.", "Internal Control.", "Planning."], "ans": 1, "exp": "It is a substantive procedure to ensure FS are adjusted/disclosed."}, {"q": "Scenario: Segment Reporting. Question: Auditor checks if segments meet the 10% threshold.", "options": ["Presentation and Disclosure.", "Existence.", "Valuation.", "Rights."], "ans": 0, "exp": "Ensuring compliance with IFRS 8 (Segments) is a disclosure test."}, {"q": "Scenario: Earnings Per Share (EPS). Question: Recalculating the weighted average shares.", "options": ["Valuation/Accuracy.", "Existence.", "Rights.", "Cut-off."], "ans": 0, "exp": "Math accuracy."}, {"q": "Scenario: Going Concern assessment. Question: Reviewing cash flow forecasts for the next 12 months.", "options": ["Substantive Procedure.", "Test of Control.", "Risk Assessment.", "Compliance."], "ans": 0, "exp": "Verifying the forecast is substantive work on the GC assumption."}, {"q": "Scenario: Letter of Support (Parent to Subsidiary). Question: Auditor checks Parent's financials. Why?", "options": ["To see if Parent can pay (Ability).", "To check Parent's profit.", "To audit Parent.", "Fun."], "ans": 0, "exp": "A guarantee is useless if the guarantor is broke."}, {"q": "Scenario: Inventory \"Cut-off\" is incorrect. Question: Impact?", "options": ["Only Inventory is wrong.", "Inventory and Cost of Sales (Profit) are wrong.", "Only Sales.", "Cash."], "ans": 1, "exp": "Closing Stock affects Cost of Sales. Wrong stock = Wrong Profit.\n\ud83d\udfe3 Section 10: Final Revision Mix"}, {"q": "Scenario: Why trace \"Sales Order -> GDN -> Invoice -> Ledger\"?", "options": ["Completeness.", "Occurrence.", "Valuation.", "Rights."], "ans": 0, "exp": "Forward trace checks completeness."}, {"q": "Scenario: Why vouch \"Ledger -> Invoice -> GDN -> Order\"?", "options": ["Completeness.", "Occurrence (Existence).", "Valuation.", "Rights."], "ans": 1, "exp": "Backward vouch checks occurrence."}, {"q": "Scenario: Bank Confirmation is not received. Question:", "options": ["Qualify immediately.", "Send reminder or verify via online banking (if authorized).", "Disclaimer.", "Ignore."], "ans": 1, "exp": "Try alternative/follow-up first."}, {"q": "Scenario: Receivables Confirmation. Customer says \"I owe $0\". Company says \"$10k\". Reason: \"Goods returned\". Question:", "options": ["Check for Credit Note and GRN (Returns).", "Customer is lying.", "Company is right.", "Write off."], "ans": 0, "exp": "Verify the dispute using documents."}, {"q": "Scenario: Supplier Invoice is missing. Question:", "options": ["Ask for copy.", "Ignore.", "Estimate.", "Resign."], "ans": 0, "exp": "Get evidence."}, {"q": "Scenario: Amortization of Intangibles. Question:", "options": ["Check useful life and method.", "Check physical existence.", "Check bank.", "Check supplier."], "ans": 0, "exp": "Amortization depends on life/method."}, {"q": "Scenario: Capital Work in Progress (CWIP). Question: Auditor checks if assets are completed but still in CWIP.", "options": ["Depreciation risk (Understated).", "Overstated.", "Existence.", "Rights."], "ans": 0, "exp": "If completed but left in CWIP, depreciation isn't charged. Profit overstated."}, {"q": "Scenario: Foreign Currency Transaction. Question: Check Spot Rate on transaction date.", "options": ["Valuation/Accuracy.", "Existence.", "Cut-off.", "Rights."], "ans": 0, "exp": "Using correct rate is accuracy."}, {"q": "Scenario: Directors' Bonus. Question: Check Board Approval.", "options": ["Occurrence/Authorization.", "Valuation.", "Cut-off.", "Existence."], "ans": 0, "exp": "Remuneration needs approval."}, {"q": "Scenario: Tax Provision. Question: Auditor sends letter to Tax Consultant.", "options": ["Completeness/Valuation of Liability.", "Existence.", "Rights.", "Cut-off."], "ans": 0, "exp": "Expert confirms status of tax disputes."}, {"q": "Scenario: Suspense Account. Question:", "options": ["Must be cleared to zero.", "Can remain.", "Asset.", "Liability."], "ans": 0, "exp": "Suspense means \"Unknown error\". Must be investigated and cleared."}, {"q": "Scenario: Journal Entries testing. Question: Focus on?", "options": ["Routine entries.", "Non-routine, round-sum, or unusual time entries (Fraud risk).", "Small entries.", "Payroll."], "ans": 1, "exp": "Fraud usually happens via manual, unusual journals."}, {"q": "Scenario: \"Pop-up\" shops revenue. Question: Hard to verify.", "options": ["Cash counts and reconciliations.", "Invoices.", "GDNs.", "Orders."], "ans": 0, "exp": "Cash businesses need cash verification."}, {"q": "Scenario: Cost of Sales. Question: Gross Margin Analysis.", "options": ["Analytical Procedure.", "Test of Detail.", "Inquiry.", "Observation."], "ans": 0, "exp": "Margin analysis is key for CoS."}, {"q": "Scenario: Which assertion pertains to \"Assets, Liabilities, and Equity\" balances?", "options": ["Existence, Rights, Completeness, Valuation.", "Occurrence, Completeness, Accuracy, Cut-off.", "Presentation only.", "Disclosure only."], "ans": 0, "exp": "Balance sheet assertions."}, {"q": "Scenario: Which assertion pertains to \"Transactions\" (P&L)?", "options": ["Occurrence, Completeness, Accuracy, Cut-off, Classification.", "Existence, Rights.", "Valuation.", "Rights."], "ans": 0, "exp": "P&L assertions."}, {"q": "Scenario: Obsolete Inventory. Question: NRV test.", "options": ["Compare Cost vs Selling Price after year-end.", "Check Purchase Invoice.", "Check Supplier.", "Count stock."], "ans": 0, "exp": "Selling price is the proof of value."}, {"q": "Scenario: Consignment Stock (Held by agent). Question:", "options": ["Confirm with agent.", "Ignore.", "Count at HQ.", "Write off."], "ans": 0, "exp": "Confirm with holder."}, {"q": "Scenario: Advance payments to suppliers. Question:", "options": ["Current Asset (Prepayment).", "Expense.", "Liability.", "Revenue."], "ans": 0, "exp": "Right to receive goods."}, {"q": "Scenario: Deferred Tax. Question: Check enacted tax rates.", "options": ["Valuation.", "Existence.", "Rights.", "Cut-off."], "ans": 0, "exp": "Rate determines value."}, {"q": "Scenario: Pension Liability. Question: Actuary Report.", "options": ["Valuation.", "Existence.", "Rights.", "Cut-off."], "ans": 0, "exp": "Complex estimate needs expert."}, {"q": "Scenario: VAT/GST Liability. Question: Re-perform calculation (Output - Input).", "options": ["Valuation/Accuracy.", "Existence.", "Rights.", "Cut-off."], "ans": 0, "exp": "Math check."}, {"q": "Scenario: Bad Debt Provision is 1% of Sales. Historically it was 5%. Question:", "options": ["Understated Provision (Risk).", "Accurate.", "Overstated.", "Good performance."], "ans": 0, "exp": "Deviation from history suggests manipulation."}, {"q": "Scenario: Comparing \"Budget vs Actual\" expenses. Question:", "options": ["Analytical Procedure.", "Test of Detail.", "Control.", "Inquiry."], "ans": 0, "exp": "Variance analysis."}, {"q": "Scenario: Final Review of Financial Statements. Question:", "options": ["Ensure compliance with IFRS and Companies Act.", "Check spelling.", "Check font.", "Print."], "ans": 0, "exp": "Presentation & Disclosure check.\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Sampling Methods & Techniques"}, {"q": "Scenario: The auditor wants to select a sample of invoices. He calculates an interval (Total Items / Sample Size) and selects every 20th invoice starting from a random point. Question: Which sampling method is this?", "options": ["Random Sampling", "Systematic Sampling", "Haphazard Sampling", "Block Sampling"], "ans": 1, "exp": "Systematic selection involves a constant interval between selections (e.g., every nth item)."}, {"q": "Scenario: The auditor selects all sales invoices issued in the first week of January and the last week of December to check Cut-off. Question: This is an example of:", "options": ["Random Sampling", "Systematic Sampling", "Block Sampling", "Stratified Sampling"], "ans": 2, "exp": "Selecting a contiguous sequence of items (a block of time) is Block Sampling. It is often used for Cut-off testing."}, {"q": "Scenario: To ensure every item in the population has an equal chance of selection, the auditor uses a random number generator. Question: This method is:", "options": ["Haphazard Sampling", "Random Sampling", "Systematic Sampling", "Judgmental Sampling"], "ans": 1, "exp": "Random sampling eliminates bias by giving every item an equal probability of selection."}, {"q": "Scenario: An auditor closes his eyes and points at the ledger to pick items without any structured technique. Question: What is this called?", "options": ["Random Sampling", "Haphazard Sampling", "Systematic Sampling", "Statistical Sampling"], "ans": 1, "exp": "Haphazard sampling is the selection of items without any conscious bias or structured technique. It is non-statistical."}, {"q": "Scenario: The auditor suspects that \"Farmers' Loans\" in a bank are high risk. Instead of sampling, he tests 100% of the loans given to farmers. Question: Is this Audit Sampling?", "options": ["Yes, because he selected a specific group.", "No, testing 100% of a specific group (or the whole population) is NOT sampling.", "Yes, it is Stratified Sampling.", "No, it is a Test of Control."], "ans": 1, "exp": "Audit Sampling requires testing less than 100% of the population such that all items have a chance of selection. Testing a specific group 100% is \"Selecting Specific Items,\" not sampling."}, {"q": "Scenario: The auditor divides the inventory list into \"High Value\" (>$10k) and \"Low Value\" (<$10k) items. He tests 100% of the High Value items and samples the Low Value ones. Question: What is this technique called?", "options": ["Systematic Selection", "Stratification", "Value Weighted Selection", "Block Selection"], "ans": 1, "exp": "Stratification involves dividing a population into sub-populations (strata) based on characteristics like value, reducing variability."}, {"q": "Scenario: Which sampling method is necessary if the auditor wants to use \"Statistical Sampling\"?", "options": ["Haphazard Selection", "Block Selection", "Random Selection", "Judgmental Selection"], "ans": 2, "exp": "Statistical sampling requires a random selection method and the use of probability theory to evaluate results.\n\ud83d\udd35 Section 2: Factors Affecting Sample Size"}, {"q": "Scenario: The auditor decides to increase his \"Reliance on Internal Controls\". Question: How does this affect the Sample Size for Tests of Controls?", "options": ["Sample Size Increases", "Sample Size Decreases", "No Effect", "Sample Size becomes zero"], "ans": 0, "exp": "If you want to rely MORE on controls (high assurance), you need MORE evidence to prove they work, so sample size increases."}, {"q": "Scenario: The auditor increases the \"Tolerable Rate of Deviation\" (TRD) from 5% to 10%. Question: What happens to the sample size?", "options": ["Increases", "Decreases", "Remains same", "Doubles"], "ans": 1, "exp": "If you are willing to accept more errors (higher tolerance), you don't need to be as precise, so you can test fewer items."}, {"q": "Scenario: The auditor expects the population to have a high error rate (Expected Rate of Deviation increases). Question: How does this affect sample size?", "options": ["Increases", "Decreases", "No Effect", "Depends on population size"], "ans": 0, "exp": "If you expect many errors, you need a larger sample to find them and measure the true error rate accurately."}, {"q": "Scenario: The number of invoices in the population increases from 5,000 to 500,000. Question: What is the effect on sample size?", "options": ["Significant Increase", "Significant Decrease", "Negligible / No Effect", "It doubles"], "ans": 2, "exp": "For large populations, the actual size of the population has very little effect on the sample size required for statistical validity."}, {"q": "Scenario: The auditor wants a higher \"Confidence Level\" (e.g., 95% instead of 90%). Question: The sample size will:", "options": ["Decrease", "Increase", "Stay the same", "Be 100%"], "ans": 1, "exp": "Higher confidence means lower risk of being wrong, which requires more evidence (larger sample)."}, {"q": "Scenario: In a \"Test of Details\", the auditor assesses the Risk of Material Misstatement (RMM) as High. Question: The sample size for substantive testing should:", "options": ["Decrease", "Increase", "Be zero", "Be 10%"], "ans": 1, "exp": "Higher risk requires more substantive evidence to lower the detection risk."}, {"q": "Scenario: The auditor finds that \"Analytical Procedures\" provided strong assurance. Question: What happens to the sample size for detailed testing?", "options": ["Increases", "Decreases", "No Effect", "Becomes 100%"], "ans": 1, "exp": "If other procedures (like analytics) give comfort, you need less evidence from detailed sampling.\n\ud83d\udfe0 Section 3: Sampling Risk (The Tricky Part)"}, {"q": "Scenario: The auditor concludes that controls are effective based on a sample, but in reality, they are ineffective. Question: This is known as:", "options": ["Risk of Under-Reliance (Type I Error)", "Risk of Over-Reliance (Type II Error)", "Non-Sampling Risk", "Inherent Risk"], "ans": 1, "exp": "Over-reliance is dangerous because the auditor relies on bad controls, reducing substantive testing, which leads to an incorrect audit opinion (Effectiveness issue)."}, {"q": "Scenario: The auditor concludes that controls are ineffective based on a sample, but in reality, they are working fine. Question: This leads to:", "options": ["An incorrect audit opinion.", "Increased audit efficiency.", "Additional unnecessary work (Inefficiency).", "Audit failure."], "ans": 2, "exp": "This is Under-Reliance. The auditor will do extra substantive work unnecessarily, wasting time (Efficiency issue), but the opinion will likely still be correct."}, {"q": "Scenario: Which type of Sampling Risk affects the Audit Effectiveness (i.e., risk of giving the wrong opinion)?", "options": ["Risk of Incorrect Rejection (Under-Reliance)", "Risk of Incorrect Acceptance (Over-Reliance)", "Inherent Risk", "Business Risk"], "ans": 1, "exp": "Incorrect Acceptance (saying it's good when it's bad) is the most dangerous risk because it leads to passing a misstated FS."}, {"q": "Scenario: The auditor makes a mistake by misinterpreting a document (Human Error). Question: Is this Sampling Risk?", "options": ["Yes, it happened during sampling.", "No, this is Non-Sampling Risk.", "Yes, it is Systematic Risk.", "No, it is Control Risk."], "ans": 1, "exp": "Errors not caused by the sample selection (like human error, fatigue, wrong interpretation) are Non-Sampling Risks.\n\ud83d\udfe3 Section 4: Evaluation & Projection"}, {"q": "Scenario: The auditor finds misstatements of $2,000 in a sample of 10%. Question: What is the \"Projected Misstatement\" for the whole population?", "options": ["$2,000", "$20,000", "$200", "$10,000"], "ans": 1, "exp": "If 10% contains $2k error, the 100% likely contains $2k / 10% = $20,000."}, {"q": "Scenario: The \"Projected Misstatement\" is $50,000. The \"Tolerable Misstatement\" is $40,000. Question: What should the auditor conclude?", "options": ["The population is acceptable.", "The population is materially misstated.", "Ignore the difference.", "Decrease sample size."], "ans": 1, "exp": "If the projected error exceeds the tolerable limit, the population is bad/misstated."}, {"q": "Scenario: The auditor finds an \"Anomalous Error\" (a one-off event, e.g., a lightning strike caused a calculation error). Question: How should this be treated in projection?", "options": ["It should be projected to the whole population.", "It should be excluded from the projection but added to the final total of known errors.", "It should be ignored completely.", "It renders the sample invalid."], "ans": 1, "exp": "Anomalies are not representative of the rest of the population, so projecting them would distort the result. They are treated as isolated errors."}, {"q": "Scenario: The Projected Misstatement is very close to the Tolerable Misstatement (e.g., Projected $48k, Tolerable $50k). Question: What is the risk?", "options": ["No risk, it's below the limit.", "High Sampling Risk (The true error might exceed $50k).", "The auditor should accept the population.", "The auditor should stop testing."], "ans": 1, "exp": "If the projection is close to the limit, there is a high chance that the actual error (which we don't know) is slightly higher and breaches the limit. The auditor usually tests more.\n\ud83d\udfe4 Section 5: Definitions & Concepts"}, {"q": "Scenario: \"Sampling Unit\" refers to:", "options": ["The individual items making up the population (e.g., a cheque, an invoice).", "The auditor.", "The sampling method.", "The total population."], "ans": 0, "exp": "The sampling unit is the individual item being selected (e.g., $1 of balance, or 1 Invoice)."}, {"q": "Scenario: What is \"Stratification\"?", "options": ["Selecting every nth item.", "Dividing a population into sub-populations with similar characteristics.", "Selecting items blindly.", "Calculating standard deviation."], "ans": 1, "exp": "Grouping items (e.g., by value) to improve sampling efficiency."}, {"q": "Scenario: Value-Weighted Selection (Monetary Unit Sampling) gives a higher chance of selection to:", "options": ["Smaller value items.", "Larger value items.", "Old items.", "New items."], "ans": 1, "exp": "In MUS, every $1 is a sampling unit. A $10,000 invoice has 10,000 chances to be picked, while a $100 invoice has only 100. It favors high value."}, {"q": "Scenario: \"Tolerable Misstatement\" in substantive sampling is the application of:", "options": ["Performance Materiality.", "Overall Materiality.", "Inherent Risk.", "Control Risk."], "ans": 0, "exp": "Tolerable misstatement is essentially Performance Materiality applied to a specific sampling procedure."}, {"q": "Scenario: If the auditor cannot apply audit procedures to a selected item (e.g., the invoice is lost). Question: How should this item be treated?", "options": ["Select a replacement item.", "Treat it as a deviation/misstatement.", "Ignore it.", "Assume it is correct."], "ans": 1, "exp": "If evidence is missing, you must assume the worst (it's an error) unless you can verify it by alternative means."}, {"q": "Scenario: Why is \"Haphazard Sampling\" not permitted for Statistical Sampling?", "options": ["Because it is too accurate.", "Because it involves human bias and probability theory cannot be applied.", "Because it is too slow.", "Because ISAs ban it."], "ans": 1, "exp": "Statistical sampling relies on mathematical probability. Human bias in Haphazard selection breaks the math."}, {"q": "Scenario: \"Deviation Rate\" applies to:", "options": ["Tests of Controls.", "Tests of Details.", "Analytical Procedures.", "Risk Assessment."], "ans": 0, "exp": "We talk about \"Deviations\" (failures) in controls, and \"Misstatements\" ($ errors) in details."}, {"q": "Scenario: When using Systematic Selection, what is the risk if the population has a pattern (e.g., every 10th item is a supervisor approval)?", "options": ["The sample will be highly representative.", "The sample might be biased (e.g., checking only supervisors).", "The sample size will be too small.", "No risk."], "ans": 1, "exp": "If the selection interval coincides with a pattern in the population, the sample will not be random/representative.\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Fundamental Principles"}, {"q": "Scenario: An auditor discovers that the client is involved in money laundering. The client threatens to sue the auditor for breach of confidentiality if they report it. Question: Which fundamental principle is at risk if the auditor stays silent?", "options": ["Confidentiality", "Professional Behavior (Compliance with laws)", "Objectivity", "Integrity"], "ans": 1, "exp": "\"Professional Behavior\" requires complying with relevant laws. Staying silent on money laundering (non-compliance with law) to protect \"confidentiality\" is a breach of professional behavior and integrity."}, {"q": "Scenario: An auditor markets their services by claiming, \"We are the best auditors in the country and other firms are incompetent.\" Question: This violates:", "options": ["Integrity", "Objectivity", "Professional Behavior", "Confidentiality"], "ans": 2, "exp": "Making exaggerated claims or disparaging other professionals brings discredit to the profession."}, {"q": "Scenario: The CFO of a client asks the auditor to hide a small error because \"it won't affect the opinion anyway, but it will save my bonus.\" The auditor agrees to maintain a good relationship. Question: Primary principle violated?", "options": ["Confidentiality", "Objectivity (and Integrity)", "Professional Competence", "Due Care"], "ans": 1, "exp": "Allowing bias, conflict of interest, or undue influence (CFO's pressure) to override professional judgment is a breach of Objectivity."}, {"q": "Scenario: An auditor accepts an engagement for a specialized insurance company but has no experience in the insurance sector and does not plan to hire an expert. Question: Principle violated?", "options": ["Integrity", "Professional Competence and Due Care", "Objectivity", "Confidentiality"], "ans": 1, "exp": "Accepting work without the necessary skills to perform it diligently violates Professional Competence."}, {"q": "Scenario: The auditor sells the client's data to a marketing firm. Question:", "options": ["Breach of Objectivity", "Breach of Confidentiality", "Breach of Independence", "Breach of Advocacy"], "ans": 1, "exp": "Using client information for personal gain or disclosing it without authority is a clear breach of Confidentiality."}, {"q": "Scenario: When is an auditor allowed to disclose confidential information?", "options": ["When the client gives verbal permission.", "When there is a legal duty or right to disclose (e.g., to a regulator).", "When the auditor needs money.", "When the press asks."], "ans": 1, "exp": "Confidentiality is not absolute. Legal duty or professional right/duty overrides it."}, {"q": "Scenario: An auditor provides tax advice to an audit client that is based on a \"loophole\" that is likely to be challenged by the tax authority. Question:", "options": ["Integrity", "Objectivity", "Professional Behavior & Competence", "None"], "ans": 2, "exp": "Promoting aggressive tax avoidance schemes that have no legal basis affects Professional Behavior and Competence."}, {"q": "Scenario: \"Independence of Mind\" differs from \"Independence of Appearance\" because:", "options": ["Mind is about what others think; Appearance is about actual state of mind.", "Mind is the state of mind (objectivity); Appearance is avoiding facts that make a reasonable third party question integrity.", "Appearance is less important.", "Mind is legal; Appearance is ethical."], "ans": 1, "exp": "You must be independent (Mind) and look independent (Appearance). Both are required.\n\ud83d\udd35 Section 2: Threats & Conceptual Framework"}, {"q": "Scenario: The audit fees from a single listed client represent 20% of the firm's total income for two consecutive years. Question: What is the threat?", "options": ["Advocacy Threat", "Self-Interest Threat (Fear of losing the client)", "Familiarity Threat", "Self-Review Threat"], "ans": 1, "exp": "Over-dependence on one client creates a fear of losing the income, leading to a Self-Interest threat (Intimidation may also apply)."}, {"q": "Scenario: The Audit Partner has been auditing the same listed client for 10 years. He calls the CEO by his nickname and trusts his explanations without testing. Question:", "options": ["Self-Interest Threat", "Familiarity Threat", "Advocacy Threat", "Intimidation Threat"], "ans": 1, "exp": "Long association makes the auditor too sympathetic to the client's interests (Familiarity)."}, {"q": "Scenario: The auditor is asked to promote the shares of the client to potential investors. Question:", "options": ["Advocacy Threat", "Self-Review Threat", "Familiarity Threat", "Intimidation Threat"], "ans": 0, "exp": "Promoting the client's position (Advocacy) makes it hard to be objective later."}, {"q": "Scenario: The client threatens to replace the auditor if they qualify the report. Question:", "options": ["Advocacy Threat", "Self-Interest Threat", "Intimidation Threat", "Self-Review Threat"], "ans": 2, "exp": "Threatening consequences (firing) to influence judgment is Intimidation."}, {"q": "Scenario: A member of the audit team recently was a director at the client company and helped prepare the financial statements being audited. Question:", "options": ["Self-Review Threat", "Advocacy Threat", "Intimidation Threat", "Confidentiality Threat"], "ans": 0, "exp": "Auditing your own work (financials you prepared) is a Self-Review threat."}, {"q": "Scenario: The audit firm enters into a \"Joint Venture\" with the audit client to develop software. Question:", "options": ["Self-Interest & Advocacy", "Familiarity", "Intimidation", "Self-Review"], "ans": 0, "exp": "Business relationships create a mutual financial interest (Self-Interest) and alignment of goals (Advocacy)."}, {"q": "Scenario: The auditor receives a \"Contingent Fee\" (e.g., fee is 1% of Net Profit). Question:", "options": ["Self-Review Threat", "Self-Interest Threat", "Advocacy Threat", "Intimidation Threat"], "ans": 1, "exp": "The auditor benefits if the profit is higher, destroying objectivity (Self-Interest).\n\ud83d\udfe0 Section 3: Financial Interests & Compensation"}, {"q": "Scenario: The Audit Partner holds shares in the audit client. The value is immaterial ($100). Question:", "options": ["Allowed because it is immaterial.", "Not allowed. Direct financial interest creates a significant Self-Interest Threat regardless of materiality.", "Allowed if disclosed.", "Allowed if he doesn't vote."], "ans": 1, "exp": "For Direct financial interests, materiality does NOT matter. It is strictly prohibited."}, {"q": "Scenario: The Audit Partner holds shares in a \"Mutual Fund\", and the Mutual Fund invests in the audit client. Question: This is an \"Indirect\" financial interest.", "options": ["Prohibited always.", "Allowed only if the underlying interest is immaterial to the partner.", "Allowed always.", "Prohibited if the client is listed."], "ans": 1, "exp": "Indirect interests (via Mutual Fund) are allowed ONLY if the interest is immaterial to the individual."}, {"q": "Scenario: An audit team member\u2019s spouse holds shares in the client. Question:", "options": ["Allowed because spouse is a separate person.", "Prohibited (Immediate Family).", "Allowed if spouse does not talk about work.", "Allowed if <5% share."], "ans": 1, "exp": "Immediate family (Spouse/Dependent) interests are treated as the auditor's own interests. Prohibited."}, {"q": "Scenario: An audit manager takes a loan from a bank which is an audit client. The loan is on normal commercial terms. Question:", "options": ["Prohibited.", "Allowed (Self-Interest threat is insignificant).", "Allowed only if <$1,000.", "Prohibited for Managers, allowed for Partners."], "ans": 1, "exp": "Loans from a Bank (client) on normal terms are allowed. Loans from a non-bank client are prohibited."}, {"q": "Scenario: The audit firm has \"Overdue Fees\" from the client for the last two years. Question:", "options": ["No threat.", "Self-Interest Threat (Equivalent to a loan).", "Advocacy Threat.", "Familiarity Threat."], "ans": 1, "exp": "Outstanding fees act like a loan. The auditor might hesitate to qualify the report fearing they won't get paid.\n\ud83d\udfe3 Section 4: Employment & Business Relationships"}, {"q": "Scenario: The Audit Partner leaves the firm and joins the audit client as CFO immediately. Question:", "options": ["No threat.", "Significant Familiarity and Intimidation Threats.", "Allowed if he resigns from the firm first.", "Allowed if the client is private."], "ans": 1, "exp": "Joining a client immediately creates Self-Interest (while auditing), Familiarity, and Intimidation threats."}, {"q": "Scenario: For a \"Public Interest Entity\" (Listed), if a Key Audit Partner joins the client as Director/CFO, what is the mandatory \"Cooling-off Period\"?", "options": ["6 months", "12 months (usually)", "2 years", "5 years"], "ans": 1, "exp": "Typically, a 12-month cooling-off period is required before a key partner can join a listed client in a key role."}, {"q": "Scenario: The client offers a job to a Senior Auditor during the audit. The auditor does not reject it immediately. Question:", "options": ["Self-Interest Threat.", "No threat if he accepts after the audit.", "Advocacy Threat.", "Intimidation."], "ans": 0, "exp": "The desire to get the job (Self-Interest) may cause the auditor to please the client during the current audit."}, {"q": "Scenario: The auditor's father is the Director of the audit client. Question:", "options": ["Allowed if the auditor is junior.", "Prohibited. The auditor must be removed from the team.", "Allowed if disclosed.", "Allowed if the father is non-executive."], "ans": 1, "exp": "Immediate family in a position of influence creates an insurmountable Familiarity/Self-Interest threat. Removal is the only safeguard."}, {"q": "Scenario: An audit team member is temporarily loaned to the client to help with a short-term project (Secondment). Question:", "options": ["Allowed, but he cannot make management decisions.", "Prohibited always.", "Allowed, and he can audit his own work.", "Allowed only for tax work."], "ans": 0, "exp": "Staff loans are allowed if they don't assume management responsibilities and don't audit their own work later.\n\ud83d\udfe4 Section 5: Non-Assurance Services (NAS)"}, {"q": "Scenario: The auditor prepares the accounting records and financial statements for a \"Listed\" audit client. Question:", "options": ["Allowed with safeguards.", "Strictly Prohibited (Self-Review Threat).", "Allowed if separate teams are used.", "Allowed if disclosed."], "ans": 1, "exp": "For listed entities, preparing FS is strictly prohibited (Self-Review cannot be mitigated)."}, {"q": "Scenario: The auditor prepares the tax return for an audit client (calculation based on historical figures). Question:", "options": ["Usually allowed (creates Self-Review but manageable).", "Strictly prohibited.", "Allowed only if the client pays a bonus.", "Prohibited for private companies."], "ans": 0, "exp": "Tax compliance (return filing) is generally allowed as it is based on historical data and tax law, provided management takes responsibility."}, {"q": "Scenario: The auditor performs a valuation of a material asset for the client, which will be included in the Financial Statements. Question:", "options": ["Allowed.", "Prohibited (Self-Review Threat).", "Allowed if separate team.", "Allowed if valuation is simple."], "ans": 1, "exp": "If the valuation is material and subjective, the auditor cannot audit their own valuation (Self-Review)."}, {"q": "Scenario: The auditor acts as an expert witness for the client in a court case. Question:", "options": ["Self-Review Threat.", "Advocacy Threat.", "Familiarity Threat.", "Intimidation Threat."], "ans": 1, "exp": "Defending the client in court aligns the auditor with the client (Advocacy), compromising objectivity."}, {"q": "Scenario: Implementing an IT system for the client that generates the financial data. Question:", "options": ["Allowed.", "Prohibited (Self-Review).", "Allowed if the client pays well.", "Allowed if the system is off-the-shelf."], "ans": 1, "exp": "Designing the system means you are responsible for the data it produces. You cannot audit your own system effectively.\n\u26ab Section 6: Gifts, Hospitality & Long Association"}, {"q": "Scenario: The client offers the audit team tickets to the FIFA World Cup Final (very expensive). Question:", "options": ["Accept it, it's a gift.", "Accept if disclosed.", "Reject (Self-Interest & Familiarity Threat).", "Accept and pay half."], "ans": 2, "exp": "Gifts are allowed only if \"Clearly Trivial\". Expensive tickets create a sense of obligation (Self-Interest/Familiarity)."}, {"q": "Scenario: The client offers a pen and a diary (nominal value) to the audit team. Question:", "options": ["Reject.", "Accept (Clearly Trivial).", "Pay for it.", "Report to Board."], "ans": 1, "exp": "Nominal items do not influence judgment."}, {"q": "Scenario: How long can a \"Key Audit Partner\" serve a Listed Client before mandatory rotation?", "options": ["3 years.", "5 years (in most jurisdictions/ICAP).", "7 years (IESBA standard, but check local laws).", "10 years."], "ans": 1, "exp": "ICAP/Companies Act typically mandates 5 years for engagement partners of listed entities."}, {"q": "Scenario: After rotating off, what is the \"Cooling-off\" period for the Key Audit Partner?", "options": ["1 year.", "2 years (usually).", "5 years.", "6 months."], "ans": 1, "exp": "Usually, a 2-year cooling-off period is required (varies by role, but 2-5 is standard)."}, {"q": "Scenario: The client threatens to sue the auditor for negligence regarding last year's audit. Question: Can the auditor continue this year's audit?", "options": ["Yes, litigation is normal.", "No, \"Threatened Litigation\" creates an Intimidation and Self-Interest threat. Independence is impaired.", "Yes, if they hire a lawyer.", "Yes, if fees are paid."], "ans": 1, "exp": "You cannot audit someone who is suing you (Adversarial relationship).\n\ud83d\udd34 Section 7: Auditor Appointment & Removal"}, {"q": "Scenario: A new auditor is asked to replace the existing auditor. What must the new auditor do before accepting?", "options": ["Ask the client for fees.", "Communicate with the outgoing auditor (Professional Etiquette).", "Start the audit immediately.", "Ignore the old auditor."], "ans": 1, "exp": "Professional competence requires contacting the previous auditor to ask if there are any reasons behind the change (e.g., integrity issues)."}, {"q": "Scenario: The outgoing auditor needs the client's permission to reply to the new auditor. Question: What if the client refuses permission?", "options": ["The new auditor should proceed anyway.", "The new auditor should decline the appointment.", "The outgoing auditor should reply anyway.", "The new auditor should complain to the police."], "ans": 1, "exp": "If a client blocks communication, it suggests they are hiding something. The new auditor should decline."}, {"q": "Scenario: Who appoints the first auditor of a company?", "options": ["Shareholders.", "Directors.", "SECP.", "The Court."], "ans": 1, "exp": "First auditors are usually appointed by Directors. Subsequent ones by Shareholders at AGM."}, {"q": "Scenario: Casual vacancy (e.g., auditor death) is filled by:", "options": ["Shareholders.", "Directors.", "Government.", "Creditors."], "ans": 1, "exp": "Directors fill casual vacancies."}, {"q": "Scenario: An auditor can be removed before their term ends by:", "options": ["Directors.", "Shareholders (via Special Resolution/AGM).", "CEO.", "CFO."], "ans": 1, "exp": "Only shareholders (the owners) can remove the auditor.\n\ud83d\udfe0 Section 8: Mixed & Advanced Scenarios"}, {"q": "Scenario: Client asks the auditor to provide a \"Second Opinion\" on an accounting treatment applied by another firm. Question:", "options": ["Give the opinion immediately.", "Communicate with the existing accountant/auditor to get all facts before giving opinion.", "Refuse.", "Charge double fees."], "ans": 1, "exp": "Giving a second opinion without full facts compromises professional competence. You must talk to the current auditor."}, {"q": "Scenario: The auditor's fee is \"significantly lower\" than the previous auditor (Lowballing). Question:", "options": ["Prohibited.", "Allowed, but must ensure quality is not compromised (Competence & Due Care).", "Allowed, quality doesn't matter.", "Prohibited by law."], "ans": 1, "exp": "Quoting low is allowed, but if it's so low that you can't do a proper audit, it breaches Competence."}, {"q": "Scenario: The audit firm provides \"Recruiting Services\" to the client (interviewing candidates for CFO). Question:", "options": ["Allowed.", "Prohibited (Management Responsibility).", "Allowed if they don't make the final decision.", "Allowed for all roles."], "ans": 2, "exp": "The auditor can interview, but the CLIENT must make the hiring decision. If the auditor decides, it's a management threat."}, {"q": "Scenario: The auditor has a close business relationship with a major shareholder of the client (e.g., they own a hotel together). Question:", "options": ["No threat.", "Self-Interest & Intimidation Threat.", "Advocacy Threat.", "Familiarity Threat."], "ans": 1, "exp": "Commercial dependence on a key owner creates pressure."}, {"q": "Scenario: The auditor discovers fraud. The law requires reporting to the regulator, but the client forbids it. Question:", "options": ["Maintain Confidentiality.", "Report to Regulator (Legal duty overrides confidentiality).", "Resign and stay silent.", "Ask the client again."], "ans": 1, "exp": "Legal duty trumps client confidentiality."}, {"q": "Scenario: Custody of Client Assets (e.g., holding cash or deeds for the client). Question:", "options": ["Allowed.", "Prohibited unless legally permitted, and assets must be kept separate.", "Allowed, can mix with firm's assets.", "Prohibited always."], "ans": 1, "exp": "Holding client assets creates a Self-Interest threat. It is allowed only if strictly regulated and separated."}, {"q": "Scenario: Referral Fees. The auditor pays a commission to someone for referring a client. Question:", "options": ["Prohibited.", "Allowed if disclosed to the client.", "Allowed secretly.", "Allowed only for tax work."], "ans": 1, "exp": "Referral fees create a Self-Interest threat to objectivity. They must be disclosed to the client."}, {"q": "Scenario: An auditor works for two clients who are competitors (Conflict of Interest). Question:", "options": ["Resign from one.", "Disclose to both and use separate engagement teams (Chinese Walls).", "Keep it secret.", "Resign from both."], "ans": 1, "exp": "You can act for competitors if you manage the conflict (disclosure + separate teams)."}, {"q": "Scenario: The client pays fees in advance. Question:", "options": ["Threat.", "No threat (actually better for independence).", "Intimidation.", "Self-Review."], "ans": 1, "exp": "Being paid in advance removes the fear of non-payment."}, {"q": "Scenario: \"Intimidation Threat\" arises when:", "options": ["Auditor is bored.", "Auditor is deterred from acting objectively due to actual or perceived threats.", "Auditor audits his own work.", "Auditor loves the client."], "ans": 1, "exp": "Definition of Intimidation.\n\ud83d\udd35 Section 9: Specific ICAP/Local Context"}, {"q": "Scenario: If a partner's brother holds shares in the client, can the partner do the audit?", "options": ["Yes, brother is not immediate family.", "No, it creates a Self-Interest threat (Close family). Safeguard: Remove partner from team.", "Yes, if shares are immaterial.", "Yes, always."], "ans": 1, "exp": "Close family (siblings) interests create threats. If material, the partner should be removed."}, {"q": "Scenario: Can an auditor accept a loan from a client that is NOT a bank?", "options": ["Yes.", "No (Strictly prohibited).", "Yes, if immaterial.", "Yes, if commercial terms."], "ans": 1, "exp": "Loans from non-bank clients are prohibited."}, {"q": "Scenario: Engagement Quality Control Reviewer (EQCR) eligibility. Question: Can the audit partner become the EQCR immediately after rotation?", "options": ["Yes.", "No, cooling off applies to EQCR role too.", "Yes, if client agrees.", "No, never."], "ans": 1, "exp": "Cooling off applies to the Partner moving to EQCR role."}, {"q": "Scenario: \"Actual or Threatened Litigation\" creates which threats?", "options": ["Self-Interest & Intimidation.", "Self-Review.", "Advocacy.", "Familiarity."], "ans": 0, "exp": "Fear of losing the case or the client."}, {"q": "Scenario: Which safeguard is effective for a Self-Review threat?", "options": ["Using the same team.", "Having a separate professional (not on the team) review the work.", "Disclosing to the client.", "Charging less fees."], "ans": 1, "exp": "Independent review checks if the work was objective."}, {"q": "Scenario: A partner serves on the Board of a Charity (NPO) which is an audit client. The role is honorary (no pay). Question:", "options": ["Allowed.", "Prohibited if he participates in management decisions.", "Prohibited always.", "Allowed if he audits it."], "ans": 1, "exp": "If the role involves management decisions, it's a Self-Review/Self-Interest threat, even if honorary."}, {"q": "Scenario: The client asks the auditor to recruit a CFO. Question: The auditor negotiates the salary and makes the job offer.", "options": ["Allowed.", "Prohibited (Assuming Management Responsibility).", "Allowed if disclosed.", "Allowed if the candidate is good."], "ans": 1, "exp": "Negotiating and hiring is a management decision."}, {"q": "Scenario: Client asks auditor to design internal controls. Question:", "options": ["Prohibited for listed clients (Self-Review).", "Allowed for all.", "Prohibited for all.", "Allowed if no fee."], "ans": 0, "exp": "Designing controls -> Auditing them = Self-Review."}, {"q": "Scenario: Auditor receives shares as inheritance during the audit. Question:", "options": ["Keep them.", "Sell them immediately (or as soon as possible).", "Keep if immaterial.", "Transfer to spouse."], "ans": 1, "exp": "Unsolicited financial interests must be disposed of immediately."}, {"q": "Scenario: Can an auditor be a \"Company Secretary\" for the audit client?", "options": ["Yes.", "No (Breach of Independence/Management Role).", "Yes, if unpaid.", "Yes, for private companies."], "ans": 1, "exp": "Secretary is an officer of the company. You cannot audit a company where you are an officer.\n\ud83d\udfe3 Section 10: Final Revision Mix"}, {"q": "Scenario: Advocacy threat is most likely in:", "options": ["Auditing FS.", "Promoting client's tax scheme in court.", "Calculating tax.", "Reviewing controls."], "ans": 1, "exp": "Defending the client publicly."}, {"q": "Scenario: Self-Interest threat is LEAST likely in:", "options": ["Owning shares.", "Contingent fees.", "Questioning a complex accounting estimate (Professional Skepticism).", "Fear of losing client."], "ans": 2, "exp": "Questioning estimates is good auditing, not a threat."}, {"q": "Scenario: \"Safeguards\" are:", "options": ["Actions to eliminate or reduce threats to an acceptable level.", "Physical guards.", "Insurance policies.", "Laws."], "ans": 0, "exp": "Definition of safeguards."}, {"q": "Scenario: If no safeguard can reduce the threat to an acceptable level, the auditor must:", "options": ["Proceed with caution.", "Decline or withdraw from the engagement.", "Charge higher fees.", "Disclose in notes."], "ans": 1, "exp": "The ultimate safeguard is resignation."}, {"q": "Scenario: \"Public Interest Entity\" (PIE) usually includes:", "options": ["All private companies.", "Listed entities, Banks, Insurance companies.", "Small shops.", "Partnerships."], "ans": 1, "exp": "Entities with significant public relevance."}, {"q": "Scenario: A former partner joins the client. The firm can continue the audit only if:", "options": ["The partner has no significant connection (financial/influence) with the firm anymore.", "The partner is still paid by the firm.", "The partner audits the firm.", "The partner ignores the firm."], "ans": 0, "exp": "Complete severance of ties is required."}, {"q": "Scenario: \"Inducements\" (Bribes). Question:", "options": ["Accept and donate.", "Reject and inform higher management/regulator.", "Accept if small.", "Ignore."], "ans": 1, "exp": "Illegal and unethical."}, {"q": "Scenario: Corporate Finance Services (e.g., structuring a merger for the client). Question:", "options": ["Advocacy and Self-Review threats.", "No threat.", "Familiarity threat.", "Intimidation."], "ans": 0, "exp": "Advising on deals puts the auditor in the role of promoter (Advocacy)."}, {"q": "Scenario: Independence is required for:", "options": ["Assurance Engagements (Audit/Review).", "Tax Compilation only.", "Consulting only.", "Bookkeeping only."], "ans": 0, "exp": "Independence is the cornerstone of Assurance."}, {"q": "Scenario: The overarching requirement of the Code is to:", "options": ["Make money.", "Serve the Public Interest.", "Please the client.", "Follow the boss."], "ans": 1, "exp": "The distinguishing mark of the accountancy profession is the acceptance of responsibility to act in the public interest.\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Fraud Concepts & The Fraud Triangle"}, {"q": "Scenario: The auditor discovers a material misstatement. The Finance Director says, \"I didn't mean to do it, I just didn't understand the standard.\" However, the auditor finds an email showing the Director planned this to meet a bank covenant. Question: The distinguishing factor between Fraud and Error is:", "options": ["The amount involved.", "The intent (Intentional vs Unintentional).", "Whether the auditor found it or management revealed it.", "The type of account affected."], "ans": 1, "exp": "Fraud is intentional; Error is unintentional. The email proves intent."}, {"q": "Scenario: The Sales Manager receives a bonus only if sales increase by 10%. He is struggling to pay his personal mortgage. Question: Which element of the \"Fraud Triangle\" is present?", "options": ["Opportunity.", "Incentive / Pressure.", "Rationalization.", "Capability."], "ans": 1, "exp": "Financial pressure (mortgage) and bonus structure create the \"Incentive\" to commit fraud."}, {"q": "Scenario: The warehouse door is left unlocked at night, and there are no security cameras. Question: Which element of the \"Fraud Triangle\" is this?", "options": ["Incentive.", "Rationalization.", "Opportunity.", "Attitude."], "ans": 2, "exp": "Weak internal controls (no lock/cameras) create the \"Opportunity\" to steal."}, {"q": "Scenario: A cashier steals $500, thinking, \"The company makes millions, they won't miss this small amount, and I am underpaid anyway.\" Question: This thought process is called:", "options": ["Incentive.", "Opportunity.", "Rationalization / Attitude.", "Collusion."], "ans": 2, "exp": "Justifying the dishonest act to oneself is \"Rationalization\"."}, {"q": "Scenario: Management Override of Controls is a major fraud risk. Question: Which fraud risk factor best facilitates management override?", "options": ["High personal debts of the CEO.", "Opportunity (due to their position of authority).", "Lack of ethics.", "Complex accounting standards."], "ans": 1, "exp": "Management is in a unique position to perpetrate fraud because of their ability (Opportunity) to manipulate accounting records and override controls."}, {"q": "Scenario: Which of the following is an example of \"Fraudulent Financial Reporting\"?", "options": ["Stealing inventory.", "An employee using the company car for personal trips.", "Recording fictitious sales to boost profit.", "Stealing petty cash."], "ans": 2, "exp": "This involves manipulating the numbers to mislead users. The others are Misappropriation of Assets."}, {"q": "Scenario: Which of the following is an example of \"Misappropriation of Assets\"?", "options": ["Understating the provision for bad debts.", "Capitalizing repairs expense.", "Creating \"Ghost Employees\" and taking their salary.", "Omitted disclosure of a lawsuit."], "ans": 2, "exp": "Theft of cash (via salary) is asset misappropriation.\n\ud83d\udd35 Section 2: Specific Fraud Schemes"}, {"q": "Scenario: The auditor notices that customer payments are posted to the wrong accounts, and dates are delayed by a few days (e.g., Customer A's payment covers Customer B's debt). Question: This is a red flag for:", "options": ["Kiting.", "Teeming and Lading (Lapping).", "Channel Stuffing.", "Round Tripping."], "ans": 1, "exp": "Lapping involves using one customer's payment to hide the theft of another's."}, {"q": "Scenario: The Payroll expense has increased by 5%, but the number of employees has remained the same. Question: The auditor should suspect:", "options": ["Underpayment of staff.", "Ghost Employees.", "Efficient HR.", "Tax evasion."], "ans": 1, "exp": "If headcount is flat but cost rises (beyond normal inflation), fake employees might be on the payroll."}, {"q": "Scenario: A procurement manager buys goods from a vendor at inflated prices. It is discovered that the vendor is owned by the manager\u2019s wife. Question: This is a:", "options": ["Conflict of Interest / Kickback Scheme.", "Financial Reporting Fraud.", "Tax Fraud.", "Payroll Fraud."], "ans": 0, "exp": "Using the company to benefit a related party is a procurement fraud."}, {"q": "Scenario: \"Channel Stuffing\" involves:", "options": ["Stealing inventory.", "Sending more goods to distributors than they need at year-end to inflate sales.", "Stuffing cash into pockets.", "Hiring too many staff."], "ans": 1, "exp": "A classic revenue recognition fraud to meet targets."}, {"q": "Scenario: The auditor finds multiple journal entries with \"Round Numbers\" (e.g., $1,000,000) posted at 11:00 PM on the last day of the year. Question: This is an indicator of:", "options": ["Efficient closing process.", "Management Override / Journal Entry Fraud.", "Automated system entries.", "Bank reconciliation."], "ans": 1, "exp": "Fraudsters often use manual entries with round numbers at unusual times to manipulate results.\n\ud83d\udfe0 Section 3: Auditor's Responsibility & Procedures"}, {"q": "Scenario: The primary responsibility for the prevention and detection of fraud rests with:", "options": ["The External Auditor.", "The Internal Auditor.", "Those Charged with Governance (TCWG) and Management.", "The Police."], "ans": 2, "exp": "ISA 240 clearly states management is responsible. The auditor is responsible for obtaining reasonable assurance that FS are free from material misstatement."}, {"q": "Scenario: An auditor performs the audit in accordance with ISAs but fails to detect a sophisticated fraud involving collusion and forged documents. Question: Is the auditor liable?", "options": ["Yes, the auditor must detect all fraud.", "No, if the auditor exercised professional skepticism and performed proper procedures (audit is not a guarantee).", "Yes, because users relied on the report.", "No, because fraud is impossible to find."], "ans": 1, "exp": "Due to inherent limitations (collusion, forgery), an auditor cannot guarantee fraud detection. If they followed standards, they are generally not liable."}, {"q": "Scenario: \"Professional Skepticism\" means:", "options": ["Assuming management is dishonest.", "Assuming management is honest.", "A questioning mind and critical assessment of audit evidence (Trust but Verify).", "Accusing everyone of fraud."], "ans": 2, "exp": "You don't assume dishonesty, but you don't blindly accept honesty either. You check everything."}, {"q": "Scenario: When testing Journal Entries (JET) for fraud, which characteristic is LEAST suspicious?", "options": ["Entries made to unrelated, unusual, or seldom-used accounts.", "Entries made by individuals who normally do not make journal entries.", "Entries recorded at the end of the period with little or no explanation.", "Automated monthly depreciation entries calculated by the system."], "ans": 3, "exp": "Routine, automated entries (like depreciation) are low risk. Manual, unusual, or late entries are high risk."}, {"q": "Scenario: If the auditor identifies a fraud, what is the first step?", "options": ["Call the police.", "Resign.", "Communicate the matter to the appropriate level of management (usually one level above the fraudster).", "Note it in the working papers and ignore."], "ans": 2, "exp": "You must report it to management first (unless management is involved, then TCWG)."}, {"q": "Scenario: What if the auditor suspects that Management (CEO/CFO) is involved in the fraud?", "options": ["Report to the CEO.", "Report to Those Charged with Governance (Audit Committee/Board).", "Report to the shareholders immediately.", "Confront the CEO."], "ans": 1, "exp": "If the top brass is involved, you must go to the people who oversee them (Governance)."}, {"q": "Scenario: When is the auditor required to report fraud to an outside regulatory authority?", "options": ["Always.", "Never (Confidentiality).", "When legal or regulatory requirements override the duty of confidentiality (e.g., Money Laundering laws).", "Only if the fraud is > $1 million."], "ans": 2, "exp": "Confidentiality is overridden if the law requires reporting (e.g., to a Central Bank or SEC)."}, {"q": "Scenario: Which audit procedure is most effective for detecting \"Ghost Employees\"?", "options": ["Reconciling the total payroll expense.", "Surprise Pay-out (Auditor witnesses the distribution of pay envelopes).", "Checking the math of tax deductions.", "Reading the employment contracts."], "ans": 1, "exp": "Seeing the physical person collect the cash is the only way to prove they exist.\n\ud83d\udfe3 Section 4: Risk Assessment & Response"}, {"q": "Scenario: During the planning stage, the audit team discusses how and where the entity's financial statements might be susceptible to fraud. Question: This discussion is:", "options": ["Optional.", "Mandatory under ISA 240.", "Only required for listed companies.", "Waste of time."], "ans": 1, "exp": "The \"Fraud Discussion\" (Brainstorming) among the engagement team is a mandatory planning procedure."}, {"q": "Scenario: The auditor identifies a fraud risk in Revenue Recognition. Question: ISA 240 requires the auditor to:", "options": ["Assume there is a risk of fraud in revenue recognition unless rebutted.", "Assume revenue is always correct.", "Only test revenue if control risk is high.", "Rely on management representation."], "ans": 0, "exp": "Revenue is a \"Presumed Fraud Risk\". If the auditor thinks it doesn't apply, they must document why."}, {"q": "Scenario: Management overrides controls to post a journal entry: Debit Receivables, Credit Revenue. Question: This entry helps to:", "options": ["Understate profit.", "Overstate profit and assets.", "Hide cash theft.", "Reduce tax."], "ans": 1, "exp": "Increasing revenue and assets (receivables) artificially boosts the financial position."}, {"q": "Scenario: The auditor finds that the company\u2019s accounting estimates (e.g., warranty provision) have changed drastically to turn a loss into a profit. Question: This indicates:", "options": ["Better estimation techniques.", "Management Bias / Fraudulent Reporting.", "Error.", "Conservative accounting."], "ans": 1, "exp": "Changing estimates purely to achieve a desired result (Profit) is Management Bias."}, {"q": "Scenario: What is the \"Unpredictability Element\" in audit procedures?", "options": ["Being late for the audit.", "Changing the nature, timing, and extent of procedures (e.g., testing a new location or account) so the client can't predict what will be tested.", "Not telling the client the fee.", "Acting strange."], "ans": 1, "exp": "To catch fraud, you must do things the client doesn't expect (e.g., visiting a branch they didn't think you'd visit).\n\ud83d\udfe4 Section 5: Written Representations & Withdrawal"}, {"q": "Scenario: The auditor asks management for a Written Representation stating that \"They have disclosed all known frauds to the auditor.\" Question: If management refuses to provide this:", "options": ["Qualify the report.", "It is a scope limitation (Disclaimer or Withdrawal).", "Rely on other evidence.", "Charge a penalty."], "ans": 1, "exp": "This representation is mandatory. Refusal casts doubt on management's integrity and creates a pervasive scope limitation."}, {"q": "Scenario: Under what circumstances should an auditor consider withdrawing from the engagement?", "options": ["If the fraud is immaterial.", "If the entity questions the auditor's competence.", "If management\u2019s integrity is doubtful, and the risk is too high to continue.", "If the audit fee is paid late."], "ans": 2, "exp": "If you can't trust management (Integrity issue), you can't do an audit. Withdrawal is appropriate."}, {"q": "Scenario: An auditor withdraws due to fraud. The incoming auditor asks, \"Why did you leave?\" Question: Can the auditor reply?", "options": ["No, Confidentiality.", "Yes, if the client gives permission (Professional clearance).", "Yes, immediately tell everything without permission.", "Ignore the request."], "ans": 1, "exp": "You need client permission to discuss confidential matters. If the client refuses permission, that itself is a red flag for the new auditor."}, {"q": "Scenario: Which of the following is NOT a fraud risk factor related to \"Incentive\"?", "options": ["High degree of competition.", "Operating losses making bankruptcy imminent.", "Large amounts of cash on hand (Opportunity).", "Need to obtain additional debt financing."], "ans": 2, "exp": "Cash on hand is an Opportunity (easy to steal), not an Incentive (pressure)."}, {"q": "Scenario: \"Teeming and Lading\" is primarily a fraud involving:", "options": ["Fixed Assets.", "Cash Receipts / Receivables.", "Inventory.", "Payroll."], "ans": 1, "exp": "It involves delaying the recording of cash receipts.\n\u26ab Section 6: Advanced & Tricky Scenarios"}, {"q": "Scenario: The auditor reviews the \"Whistle-blower Hotline\" logs. Question: This is a procedure to:", "options": ["Identify potential fraud reported by employees.", "Check telephone costs.", "Test internal controls over phones.", "Hire new staff."], "ans": 0, "exp": "Whistle-blowing is a key detection mechanism for fraud."}, {"q": "Scenario: An auditor finds that the Gross Profit Margin has increased significantly, while sales volume has dropped and competitors are lowering prices. Question: This inconsistency suggests:", "options": ["Fraud (Fictitious Revenue or Understated Cost).", "Brilliant management.", "Lower costs.", "Inflation."], "ans": 0, "exp": "It defies economic logic. If sales drop and prices drop, margin should drop. A rise suggests manipulation."}, {"q": "Scenario: Supplier kickbacks (Bribery). Question: The auditor can detect this by:", "options": ["Counting inventory.", "Comparing prices paid to market prices (Benchmarking).", "Checking sales invoices.", "Asking the supplier."], "ans": 1, "exp": "If you pay $100 for a $50 item, someone is likely getting a kickback. Price comparison reveals this."}, {"q": "Scenario: A \"Lifestyle Audit\" of employees (checking if they live beyond their means) is useful for detecting:", "options": ["Financial Reporting Fraud.", "Misappropriation of Assets (Theft).", "Errors.", "Going Concern."], "ans": 1, "exp": "If a clerk earning $20k drives a Ferrari, he is likely stealing assets."}, {"q": "Scenario: Altered documents (e.g., using correction fluid or Photoshop on invoices). Question: This is a strong indicator of:", "options": ["Error.", "Fraud.", "Cost saving.", "Recycling."], "ans": 1, "exp": "Intentional alteration of evidence is fraud."}, {"q": "Scenario: The auditor finds that \"Petty Cash\" is replenished without reviewing the vouchers. Question: This is:", "options": ["A Fraud Risk Factor (Opportunity due to weak control).", "A Fraud.", "Acceptable practice.", "Efficient."], "ans": 0, "exp": "It's not definitely fraud yet, but the opportunity is huge."}, {"q": "Scenario: Auditors are required to make inquiries of \"Internal Audit\" regarding fraud. Question: Why?", "options": ["Because Internal Audit is lazy.", "Because Internal Audit monitors controls daily and may have specific knowledge of suspected fraud.", "To give them work.", "To test their competence."], "ans": 1, "exp": "Internal auditors are the eyes and ears inside the company."}, {"q": "Scenario: Related Party Transactions are often used for fraud because:", "options": ["They are tax-free.", "They are complex and can be used to move money off-balance sheet or inflate revenue.", "They are easy to audit.", "They are always cash."], "ans": 1, "exp": "Enron and others used related parties to hide debt and fake profits."}, {"q": "Scenario: If an auditor finds an \"Immaterial\" fraud committed by a low-level employee (e.g., $50 theft). Question:", "options": ["Report to Management (appropriate level).", "Report to Shareholders.", "Resign.", "Ignore."], "ans": 0, "exp": "Even immaterial fraud must be reported to management. It doesn't require resignation or shareholder reporting unless it's systemic."}, {"q": "Scenario: The best defense for an auditor accused of failing to detect fraud is:", "options": ["\"I trusted the client.\"", "\"I performed my audit in accordance with ISAs and exercised professional skepticism.\"", "\"Fraud is not my job.\"", "\"The fee was too low.\""], "ans": 1, "exp": "Compliance with standards (ISAs) is the auditor's shield.\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Definition & Identification"}, {"q": "Scenario: Mr. A is a director of XYZ Ltd. He is also the sole owner of ABC Trading. Question: Is ABC Trading a related party to XYZ Ltd?", "options": ["No, because they are separate legal entities.", "Yes, because they are under common control (Mr. A controls both).", "Only if they do business together.", "No, unless Mr. A is the CEO."], "ans": 1, "exp": "Companies under common control (same director/owner) are related parties regardless of transactions."}, {"q": "Scenario: The Marketing Manager of a company (who is not a director) has a brother who owns a printing press. The company buys all its stationery from that press. Question: Is the printing press a related party?", "options": ["No, marketing managers are not Key Management Personnel (KMP).", "Yes, close family members of KMP are related parties.", "Yes, if the Marketing Manager is considered \"Key Management Personnel\" (decision maker).", "Only if the purchases are material."], "ans": 2, "exp": "Related parties include KMP and their close family. If the Marketing Manager has authority/responsibility for planning/directing (i.e., is KMP), then his brother's company is related."}, {"q": "Scenario: A company holds 25% shares in another entity (Associate). Question: Are they related parties?", "options": ["No, you need >50% for control.", "Yes, because 25% gives \"Significant Influence\".", "Yes, but only if they share directors.", "No, unless they consolidate."], "ans": 1, "exp": "Significant influence (usually >20%) makes an entity an Associate, which is a related party."}, {"q": "Scenario: Two companies have a common director, but he is an independent non-executive director in both and has no shares in either. Question: Are the companies related parties solely because of him?", "options": ["Yes, common directorship always creates a relationship.", "No, if he does not control or significantly influence the policies of both.", "Yes, under Company Law.", "No, directors are never related parties."], "ans": 1, "exp": "Mere common directorship usually doesn't create a related party relationship between two companies unless the director exercises control or significant influence over both."}, {"q": "Scenario: The company\u2019s \"Pension Fund\" for employees. Question: Is the fund a related party?", "options": ["No, it belongs to employees.", "Yes, post-employment benefit plans for employees are related parties.", "Only if the company manages it.", "No."], "ans": 1, "exp": "Benefit plans for employees of the reporting entity are defined as related parties."}, {"q": "Scenario: A major customer contributes 90% of the company's revenue. Question: Is this customer a related party by virtue of economic dependence?", "options": ["Yes, definitely.", "No, economic dependence alone does not make a party \"Related\" (unless they can influence management policy).", "Yes, if they demand discounts.", "Yes, under ISA 550."], "ans": 1, "exp": "A customer, supplier, or bank is NOT a related party just because the company depends on them financially."}, {"q": "Scenario: Mr. X owns 100% of Company A and 100% of Company B. Company A sells goods to Company B. Question:", "options": ["No relationship.", "Company A and B are related parties (Fellow Subsidiaries / Common Control).", "Only Mr. X is related.", "Ignore."], "ans": 1, "exp": "Entities under common control are related to each other."}, {"q": "Scenario: The wife of the CEO owns a consulting firm that provides services to the company. Question:", "options": ["Not related.", "Related Party (Close family member of KMP).", "Related only if fee is high.", "Related only if CEO approves."], "ans": 1, "exp": "Close family members of KMP (Spouse, Children) are related parties.\n\ud83d\udd35 Section 2: Risks & Arms Length"}, {"q": "Scenario: Why are Related Party Transactions (RPT) considered high risk?", "options": ["They are illegal.", "They may not be conducted at \"Arm's Length\" (Market Terms).", "They are always cash based.", "They are tax-free."], "ans": 1, "exp": "The risk is that RPTs might happen at fake prices (too high or too low) to shift profit or assets, unlike transactions with independent third parties."}, {"q": "Scenario: \"Arm's Length Transaction\" means:", "options": ["A transaction with a friend.", "A transaction conducted on such terms and conditions as between a willing buyer and a willing seller who are unrelated.", "A transaction at cost price.", "A transaction with a bank."], "ans": 1, "exp": "Arm's Length = Fair Market Value terms, as if the parties were strangers."}, {"q": "Scenario: The company sells a car worth $50,000 to the Director's son for $5,000. Question: This is an example of:", "options": ["Arm's Length Transaction.", "Fraud / Non-Arm's Length Transaction.", "Employee Benefit.", "Depreciation."], "ans": 1, "exp": "Selling way below market value transfers wealth to the related party. It's a significant risk."}, {"q": "Scenario: The company borrows money from a Director at 0% interest when the market rate is 15%. Question: How should this be treated?", "options": ["It's illegal.", "It must be disclosed as a Related Party Transaction with \"terms not at arm's length\".", "The auditor should force them to pay interest.", "Ignore."], "ans": 1, "exp": "Such favorable terms must be disclosed so users know the company is getting a subsidy from the director."}, {"q": "Scenario: An auditor finds a complex transaction involving multiple shell companies owned by the Chairman. Question: The risk is:", "options": ["Money Laundering / Fraudulent Financial Reporting.", "Tax saving.", "Efficiency.", "Consolidation."], "ans": 0, "exp": "Complex RPT structures are often used to hide the substance of transactions or launder money."}, {"q": "Scenario: The company sells goods to a related party but never collects the payment. The receivable sits there for 2 years. Question: This effectively becomes:", "options": ["A Gift / Bad Debt.", "A Loan to the related party (Hidden funding).", "A Sale.", "Equity."], "ans": 1, "exp": "Not collecting debt is a way of transferring cash to the related party disguised as \"Sales\".\n\ud83d\udfe0 Section 3: Audit Procedures"}, {"q": "Scenario: What is the first procedure an auditor performs regarding related parties?", "options": ["Check invoices.", "Inquire of management to obtain a list of all related parties and any changes.", "Search Google.", "Check bank statements."], "ans": 1, "exp": "You can't find RPTs if you don't know who the Related Parties are. Getting the list is Step 1."}, {"q": "Scenario: To identify undisclosed related parties, the auditor should review:", "options": ["Shareholder Register / Minutes of Board Meetings.", "Sales Invoices.", "Gate pass.", "Petty cash."], "ans": 0, "exp": "Shareholder registers reveal owners. Board minutes reveal directors' interests and approvals of significant contracts."}, {"q": "Scenario: The auditor notices a significant transaction with a new customer \"ABC Ltd\" that has the same address as the CFO\u2019s house. Question: What should the auditor do?", "options": ["Investigate if ABC Ltd is a related party (undisclosed).", "Assume coincidence.", "Ignore.", "Check sales price."], "ans": 0, "exp": "Matching addresses is a common technique to find hidden related parties."}, {"q": "Scenario: During the audit, the auditor finds a transaction with a related party that was NOT on the list provided by management. Question: What is the immediate action?", "options": ["Resign.", "Inquire why it was omitted and request a new list; perform further procedures to find others.", "Qualify the report.", "Ignore."], "ans": 1, "exp": "If management missed one, they might have missed more. The auditor must reassess the risk and ask \"Why?\"."}, {"q": "Scenario: How does an auditor verify the \"Arm's Length\" assertion of a transaction?", "options": ["Ask the Director.", "Compare the price/terms to similar transactions with unrelated third parties.", "Check the invoice math.", "Check the date."], "ans": 1, "exp": "Benchmarking against third-party data is the only way to prove a price is fair."}, {"q": "Scenario: The auditor asks for \"Conflict of Interest\" forms filled by directors annually. Question: This helps in:", "options": ["Identifying Related Parties.", "Calculating tax.", "Checking attendance.", "Paying dividends."], "ans": 0, "exp": "Directors must declare their interests in other companies annually. This is a key source for the RP list."}, {"q": "Scenario: A company has huge sales to a related party at year-end. Question: The auditor should check:", "options": ["If the goods were actually shipped (Existence) and if the sale has commercial substance.", "The font on the invoice.", "The bank balance.", "The related party's website."], "ans": 0, "exp": "Large year-end RPTs are often used for \"Channel Stuffing\" (fake sales)."}, {"q": "Scenario: Written Representations for Related Parties. Question: The auditor must obtain a written representation that:", "options": ["Management has disclosed all related parties and transactions.", "Management likes the auditor.", "Management is profitable.", "The related parties are honest."], "ans": 0, "exp": "This confirms management's responsibility for identifying and disclosing RPs.\n\ud83d\udfe3 Section 4: Accounting & Reporting (IAS 24)"}, {"q": "Scenario: Which standard governs the Accounting and Disclosure of Related Parties?", "options": ["ISA 550.", "IAS 24.", "IFRS 15.", "IAS 16."], "ans": 1, "exp": "IAS 24 is the accounting standard. ISA 550 is the auditing standard."}, {"q": "Scenario: If a Related Party Transaction is material and NOT disclosed in the notes. Question: What audit opinion?", "options": ["Unmodified.", "Qualified or Adverse (Disclosure Misstatement).", "EOM.", "Disclaimer."], "ans": 1, "exp": "Failure to disclose material RPTs makes the FS misleading."}, {"q": "Scenario: Management discloses that \"All related party transactions were at Arm's Length\". Question: The auditor cannot verify this assertion due to lack of market data (unique items).", "options": ["Management must remove the statement \"at Arm's Length\". If they refuse, Qualify.", "Accept it.", "Disclaim opinion.", "EOM."], "ans": 0, "exp": "Management cannot claim \"Arm's Length\" unless it can be substantiated. If unproven, it's misleading."}, {"q": "Scenario: Are transactions between a Parent and its Subsidiary disclosed in the Consolidated Financial Statements?", "options": ["Yes.", "No, they are eliminated on consolidation.", "Only if material.", "Only loans."], "ans": 1, "exp": "Intra-group transactions (Parent <-> Sub) are cancelled out in group accounts. They are only disclosed in Individual accounts."}, {"q": "Scenario: Key Management Personnel (KMP) compensation (Salaries/Bonuses). Question: Must this be disclosed?", "options": ["Yes, in total or by category.", "No, it's private.", "Only if they are Directors.", "Only if > $1m."], "ans": 0, "exp": "IAS 24 mandates disclosure of KMP compensation."}, {"q": "Scenario: A company rents a building from the CEO. The rent is $10,000/month. Question: What must be disclosed?", "options": ["The Name of the RP (CEO), Nature of Relationship, Amount of Transaction, and Outstanding Balance.", "Only the Amount.", "Nothing.", "Only the Name."], "ans": 0, "exp": "Full disclosure is required to understand the effect on FS.\n\ud83d\udfe4 Section 5: Advanced Scenarios"}, {"q": "Scenario: The auditor reviews \"Life Insurance Policies\" purchased by the company. Question: Why?", "options": ["To see who the beneficiaries are (might be undisclosed related parties).", "To check expense.", "To get insurance.", "To check cash."], "ans": 0, "exp": "If the company buys insurance for \"Mr. X\", Mr. X is likely a related party."}, {"q": "Scenario: Significant transactions outside the normal course of business (e.g., selling the HQ building). Question: The auditor should be alert for:", "options": ["Related Party involvement.", "Depreciation.", "Color of the building.", "Tax."], "ans": 0, "exp": "Unusual, large, one-off deals are often done with related parties."}, {"q": "Scenario: \"Dominant Influence\". A single individual controls the whole company and makes all decisions. Question: What is the risk?", "options": ["Efficiency.", "Fraud Risk / Management Override.", "Slow decisions.", "Low profit."], "ans": 1, "exp": "A dominant personality can easily override controls and hide RPTs."}, {"q": "Scenario: The auditor performs a \"Bank Confirmation\". Question: Can this help find RPTs?", "options": ["No.", "Yes, it might show guarantees given to/from related parties.", "Only cash balance.", "Only loans."], "ans": 1, "exp": "Guarantees are often given for related parties."}, {"q": "Scenario: The auditor checks \"Lawyer's Invoices\". Question: Why?", "options": ["To see if the company set up special purpose vehicles (SPVs) or trusts (potential RPs).", "To check fees.", "To check lawsuits.", "A and C."], "ans": 0, "exp": "Lawyers set up the structures (Shell companies) used for RPTs."}, {"q": "Scenario: Which of the following is NOT necessarily a related party?", "options": ["A Subsidiary.", "A Director.", "A Bank providing a massive loan.", "The Father of the CEO."], "ans": 2, "exp": "Providers of finance (Banks) are not RPs by virtue of their dealings."}, {"q": "Scenario: Management refuses to give the list of related parties. Question:", "options": ["Scope Limitation (Disclaimer/Withdrawal).", "Qualified.", "Unmodified.", "EOM."], "ans": 0, "exp": "If you can't identify RPs, you can't audit the FS. Pervasive limitation."}, {"q": "Scenario: A \"Whistleblower\" hotline report mentions the CEO is buying land from his cousin using company funds. Question:", "options": ["Investigate immediately.", "Ignore (Anonymous).", "Ask CEO.", "Check land price only."], "ans": 0, "exp": "Specific leads on RPT fraud must be investigated."}, {"q": "Scenario: \"Circular Trading\" (Company A sells to B, B sells to C, C sells to", "options": [". Question: A) Creating fake revenue using related parties.", "Good logistics.", "Tax saving.", "Normal business."], "ans": 0, "exp": "Circular transactions are a classic fraud sign involving RPs."}, {"q": "Scenario: Transfer Pricing. Company sells to a subsidiary in a low-tax country at a very low price. Question:", "options": ["Tax Fraud / Regulatory Risk.", "Good strategy.", "No audit issue.", "Arm's length."], "ans": 0, "exp": "While it saves tax, it might breach Transfer Pricing laws (Non-compliance with L&R)."}, {"q": "Scenario: Materiality for Related Party Transactions. Question:", "options": ["Only quantitative (Amount).", "Often lower than overall materiality due to \"Nature\" (Qualitative).", "Higher.", "Irrelevant."], "ans": 1, "exp": "RPTs are sensitive. Even small amounts (e.g., fraud by Director) matter to users."}, {"q": "Scenario: The auditor reviews \"Shareholder Records\". Question: To identify:", "options": ["Principal shareholders (Related Parties).", "Dividends.", "Share price.", "Voting rights."], "ans": 0, "exp": "Major shareholders often have control/influence.\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Concept & Responsibility"}, {"q": "Scenario: The auditor has completed all substantive procedures. Before signing the report, he requests a \"Written Representation Letter\" (MRL). Question: Who is the appropriate person to sign this letter?", "options": ["The Internal Auditor.", "The Chairman of the Board (Non-Executive).", "Those with appropriate knowledge and responsibility for financial statements (e.g., CEO & CFO).", "The Company Secretary."], "ans": 2, "exp": "The letter must be signed by top management (CEO/CFO) who are responsible for the preparation of FS and have knowledge of the business.*"}, {"q": "Scenario: An auditor finds a material error in the inventory count. Management corrects it. The auditor still asks for a representation regarding inventory. Question: Why?", "options": ["To blame management later.", "To confirm that management believes the corrected balance is now accurate and no other errors exist.", "Because the auditor is unsure.", "To reduce the audit fee."], "ans": 1, "exp": "Representations confirm management's belief that the FS are free from material misstatement and that uncorrected misstatements are immaterial.*"}, {"q": "Scenario: Management offers to give an \"Oral Representation\" regarding a lawsuit instead of a written one. Question: Is this acceptable?", "options": ["Yes, if documented in working papers.", "No, ISA 580 specifically requires Written representations for key matters.", "Yes, if the lawyer also agrees.", "Only for private companies."], "ans": 1, "exp": "\"Oral\" evidence is weak and can be denied later. For significant matters, written confirmation is mandatory.*"}, {"q": "Scenario: Which of the following is NOT a mandatory Written Representation?", "options": ["That management has provided all relevant information to the auditor.", "That management has fulfilled its responsibility for preparing FS.", "That the company will make a profit next year.", "That all transactions have been recorded."], "ans": 2, "exp": "Auditors do not ask for guarantees about future profits. They ask about responsibilities and estimates, not future outcomes.*"}, {"q": "Scenario: The auditor relies solely on the Management Representation Letter to verify the valuation of a complex property. Question: Is this appropriate?", "options": ["Yes, management knows best.", "No, Written Representations do NOT provide sufficient appropriate audit evidence on their own.", "Yes, if the CEO is honest.", "Only if the amount is immaterial."], "ans": 1, "exp": "MRL is \"Supportive Evidence\". It complements other procedures but cannot replace them.*\n\ud83d\udd35 Section 2: Dating & Period Covered"}, {"q": "Scenario: The Auditor's Report is dated 15 March. Management provides the Written Representation Letter dated 10 March. Question: Is this acceptable?", "options": ["Yes, it is before the report date.", "No, the letter must cover the entire period up to the Auditor's Report. Events between 10th and 15th are uncovered.", "Yes, 5 days gap is standard.", "No, it must be dated after the report."], "ans": 1, "exp": "The date of the MRL should be as near as practicable to, but not after, the date of the auditor's report (15 March) to cover all subsequent events.*"}, {"q": "Scenario: The Auditor's Report is dated 15 March. The Representation Letter is dated 20 March. Question:", "options": ["Acceptable.", "Not acceptable. The auditor cannot sign the report (15th) before obtaining the evidence (20th).", "It means the auditor did extra work.", "Valid for next year."], "ans": 1, "exp": "You cannot finalize the opinion (15th) if a key piece of evidence (MRL) arrives later (20th).*"}, {"q": "Scenario: The audit covers the year ended 31 December 2023. The MRL is received in March 2024. Question: What period should the representations cover?", "options": ["Only March 2024.", "The financial year 2023 only.", "The financial year 2023 and the subsequent period up to the report date.", "Only 31 Dec 2023."], "ans": 2, "exp": "Representations (like Subsequent Events) must cover the gap between year-end and the report date.*"}, {"q": "Scenario: Management changed during the year. The current CEO joined in November (Year-end is December). He refuses to sign for the period before November. Question:", "options": ["Accept his refusal.", "Require him to sign for the whole year (he is responsible for the FS as a whole).", "Ask the old CEO to sign.", "Disclaim opinion."], "ans": 1, "exp": "The current management is responsible for the Financial Statements of the whole year. They can inquire of old staff, but they must sign.*\n\ud83d\udfe0 Section 3: Inconsistencies & Reliability"}, {"q": "Scenario: Management states in the MRL: \"There are no lawsuits.\" The auditor's review of Legal Expense shows payments to lawyers for a \"Pending Case regarding Pollution\". Question: What should the auditor do?", "options": ["Rely on MRL (Management is top authority).", "Investigate the inconsistency and question management's integrity.", "Ignore the legal expense.", "Qualify the report immediately."], "ans": 1, "exp": "Contradictory evidence (Expense vs MRL) casts doubt on management's honesty. The auditor must investigate why they lied.*"}, {"q": "Scenario: If the auditor concludes that the Written Representations are unreliable (e.g., Management lies frequently). Question: What is the impact on the Audit Opinion?", "options": ["Qualified Opinion.", "Disclaimer of Opinion.", "Adverse Opinion.", "Unmodified."], "ans": 1, "exp": "If the written representation (a core evidence of responsibilities) is unreliable, the auditor cannot trust anything. This is a Pervasive Scope Limitation -> Disclaimer.*"}, {"q": "Scenario: Management refuses to provide the representation that \"They have disclosed all allegations of fraud.\" Question:", "options": ["It is a minor issue.", "It suggests they might be hiding fraud. Scope Limitation -> Disclaimer.", "Qualify the report (\"Except for\").", "Report to police."], "ans": 1, "exp": "Refusal to confirm fraud disclosure is a huge red flag. You cannot give an opinion if you suspect hidden fraud.*"}, {"q": "Scenario: The auditor asks for a specific representation regarding the \"recoverability of a major debtor\". Management refuses, saying \"You check it yourself.\" Question:", "options": ["Auditor should check receipts. If valid, no need for representation.", "Refusal to provide any requested representation is a scope limitation.", "Auditor should withdraw.", "Auditor should sign anyway."], "ans": 0, "exp": "For specific assertions (like one debtor), if the auditor has other strong evidence (cash receipt), the lack of rep might not be pervasive. However, usually, auditors insist on it.*\n\ud83d\udfe3 Section 4: Specific Representation Items"}, {"q": "Scenario: Which of the following requires a Specific Written Representation?", "options": ["The useful life of every single chair.", "The outcome of a material uncertain lawsuit (Judgemental area).", "The petty cash balance ($50).", "The bank address."], "ans": 1, "exp": "MRL is crucial for areas involving significant Judgment and Estimates (like lawsuits) where other evidence is limited.*"}, {"q": "Scenario: Going Concern. Management has a plan to sell a factory to survive. Question: The auditor asks for a representation regarding:", "options": ["The Feasibility of the plan.", "The Intent and Ability to carry out the plan.", "The profit of the factory.", "The buyer's name."], "ans": 1, "exp": "Auditor verifies the market (feasibility) but needs MRL to confirm Management's Intent to sell.*"}, {"q": "Scenario: Related Party Transactions (RPT). Question: Why is MRL critical here?", "options": ["Because RPTs are illegal.", "Because RPTs are hard to identify if management doesn't disclose them.", "Because banks require it.", "It is not critical."], "ans": 1, "exp": "The completeness of RPTs depends heavily on management disclosure. The auditor needs written confirmation that \"You told us everything.\"*"}, {"q": "Scenario: Subsequent Events. Question: The MRL confirms that:", "options": ["No events occurred.", "All events requiring adjustment or disclosure have been adjusted or disclosed.", "The future is bright.", "The auditor is responsible."], "ans": 1, "exp": "Confirmation of completeness of subsequent events handling.*"}, {"q": "Scenario: Uncorrected Misstatements. Question: Management must represent that:", "options": ["There are no errors.", "The effect of uncorrected misstatements is immaterial, individually and in aggregate.", "They will correct them next year.", "The auditor is wrong."], "ans": 1, "exp": "Management acknowledges they know about the small errors but believe they don't matter (Immaterial).*"}, {"q": "Scenario: The auditor finds a \"Significant Deficiency\" in internal control. Question: Does the MRL usually cover internal controls?", "options": ["Yes, acknowledging management's responsibility for design and maintenance of internal control.", "No, controls are auditor's job.", "Only if fraud happened.", "Only for listed companies."], "ans": 0, "exp": "The MRL confirms management accepts its role in setting up controls.*"}, {"q": "Scenario: Estimates. The auditor asks management to confirm that:", "options": ["Their estimates are 100% accurate.", "The significant assumptions used in making accounting estimates are reasonable.", "They guessed the numbers.", "The auditor calculated them."], "ans": 1, "exp": "Estimates are never 100% accurate. The rep confirms the assumptions are reasonable.*\n\ud83d\udfe4 Section 5: Refusal & Withdrawal"}, {"q": "Scenario: Management provides the MRL but modifies the wording to say \"To the best of our knowledge, except for the fraud by the CFO...\" Question:", "options": ["Reject the letter.", "Accept the modification and investigate the exception (the fraud).", "Resign immediately.", "Ignore the exception."], "ans": 1, "exp": "Honest modifications are helpful. The auditor must now focus heavily on the CFO fraud impact.*"}, {"q": "Scenario: If management refuses to provide the \"General Responsibilities\" representation (that they prepared the FS). Question:", "options": ["Qualified Opinion.", "Disclaimer of Opinion.", "Unmodified.", "Adverse."], "ans": 1, "exp": "If they won't even admit they made the FS, the foundation of the audit collapses. Disclaimer is mandatory.*"}, {"q": "Scenario: The auditor doubts the integrity of management so much that even a Written Representation wouldn't be trusted. Question:", "options": ["Get a lawyer to sign.", "Withdraw from the engagement.", "Disclaimer.", "Increase fees."], "ans": 1, "exp": "If integrity is gone, the audit is impossible. Withdrawal is the best professional route.*"}, {"q": "Scenario: A subsidiary's management refuses to sign an MRL for the Group Auditor. Question:", "options": ["Group Auditor asks Parent Management to sign for the whole group.", "Group Auditor ignores the subsidiary.", "Group Auditor sues subsidiary.", "Group Auditor qualifies the opinion."], "ans": 0, "exp": "Parent management is responsible for the Consolidated FS. They sign for the group (though they usually get back-to-back reps from the subsidiary).*"}, {"q": "Scenario: Is the MRL a substitute for other audit procedures?", "options": ["Yes, it saves time.", "No, it is complementary.", "Yes, for small clients.", "Yes, for liabilities."], "ans": 1, "exp": "NEVER a substitute. (Standard Rule).*"}, {"q": "Scenario: If the MRL is not provided, the auditor is required to:", "options": ["Issue a clean report.", "Discuss the matter with management, re-evaluate integrity, and take appropriate action (Disclaimer).", "Call the police.", "Sign the rep letter himself."], "ans": 1, "exp": "Step 1 is always \"Talk\". Step 2 is \"Re-evaluate Integrity\". Step 3 is \"Modify Opinion\".*"}, {"q": "Scenario: Can an auditor draft the MRL for the client?", "options": ["No, never.", "Yes, usually the auditor drafts it and asks management to review and sign on their letterhead.", "Only if the client pays extra.", "Only if the client is illiterate."], "ans": 1, "exp": "Practical convention: Auditor drafts it (since they know the standards), Client prints on letterhead and signs.*"}, {"q": "Scenario: \"Scope Limitation\" created by management refusal to sign MRL results in:", "options": ["Qualified or Disclaimer.", "Disclaimer only (Usually).", "Adverse.", "Unmodified."], "ans": 1, "exp": "Refusal to sign MRL is usually considered so fundamental that a Disclaimer is required.*"}, {"q": "Scenario: The auditor wants confirmation that \"All laws and regulations have been complied with.\" Question:", "options": ["Check legal expense.", "Ask for Written Representation.", "Ask the police.", "A and B."], "ans": 3, "exp": "Both procedures are used. MRL confirms management isn't hiding any breaches.*"}, {"q": "Scenario: The date of MRL is after the Audit Report date. Question:", "options": ["Invalid. The auditor cannot rely on evidence obtained after the opinion is formed.", "Valid.", "Better.", "Required."], "ans": 0, "exp": "Evidence must be in hand before signing the report.*\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Leadership & Responsibilities"}, {"q": "Scenario: Who has the ultimate responsibility for the quality of an individual audit engagement?", "options": ["The Senior Manager.", "The Engagement Quality Control Reviewer (EQCR).", "The Engagement Partner.", "The Audit Firm's CEO."], "ans": 2, "exp": "ISA 220 states that the Engagement Partner takes responsibility for the overall quality on each audit engagement they lead.*"}, {"q": "Scenario: An audit junior made a mistake because he was not supervised properly. Question: Who is held accountable for this failure in quality?", "options": ["The Junior.", "The HR Manager.", "The Engagement Partner.", "The Client."], "ans": 2, "exp": "The Engagement Partner is responsible for direction, supervision, and performance of the audit team.*"}, {"q": "Scenario: The audit firm prioritizes commercial considerations (fees/profit) over the quality of work performed. Question: This violates the leadership principle that:", "options": ["Quality is essential in performing audit engagements.", "Profit is the main goal.", "Clients are always right.", "Efficiency is key."], "ans": 0, "exp": "The \"Tone at the Top\" must demonstrate that quality comes before commercial gain.*"}, {"q": "Scenario: The Engagement Partner realizes the audit team does not have enough time or resources to complete the audit properly. Question: What should the Partner do?", "options": ["Rush the audit.", "Request more resources/time or consider withdrawing.", "Sign the report anyway.", "Ask the client to do the work."], "ans": 1, "exp": "The Partner must be satisfied that the engagement team has the appropriate competence and capabilities (including time) to perform the audit.*\n\ud83d\udd35 Section 2: Acceptance & Continuance"}, {"q": "Scenario: Before accepting a new client, the firm investigates the integrity of the client\u2019s owners (e.g., checking blacklists, news, fraud cases). Question: If the owners are found to be involved in money laundering, the firm should:", "options": ["Accept the client but charge higher fees.", "Decline the engagement.", "Accept but audit carefully.", "Report to the police but accept."], "ans": 1, "exp": "Firms should only accept clients where they have considered the integrity of the client and have no reason to conclude that the client lacks integrity.*"}, {"q": "Scenario: During the audit, the Partner receives information that would have caused the firm to decline the engagement if known earlier (e.g., major fraud history). Question: What is the immediate action?", "options": ["Withdraw immediately.", "Communicate the matter promptly to the firm and legal counsel to determine the action (e.g., withdrawal).", "Ignore it until next year.", "Finish the audit quickly."], "ans": 1, "exp": "When new information surfaces, the firm/partner must re-evaluate the acceptance decision and take legal advice on whether to continue or withdraw.*"}, {"q": "Scenario: The engagement letter is usually signed:", "options": ["After the audit report is issued.", "Before the audit work begins, once client acceptance procedures are complete.", "During the final review.", "When the fee is paid."], "ans": 1, "exp": "The engagement letter confirms the terms and acceptance, so it must be signed before work starts.*\n\ud83d\udfe0 Section 3: Engagement Quality Control Review (EQCR)"}, {"q": "Scenario: For which audits is an Engagement Quality Control Review (EQCR) mandatory?", "options": ["All audits.", "Audits of Listed Entities.", "Audits of private companies.", "Audits of charities."], "ans": 1, "exp": "ISA 220 requires an EQCR for all audits of financial statements of listed entities.*"}, {"q": "Scenario: Who appoints the EQCR?", "options": ["The Client.", "The Engagement Partner.", "The Firm (Quality Control Function).", "The Shareholders."], "ans": 2, "exp": "The EQCR must be objective, so the Firm appoints them, not the Partner (who is being reviewed).*"}, {"q": "Scenario: The Engagement Partner and the EQCR have a disagreement regarding a significant accounting judgment. Question: Can the Partner sign the audit report?", "options": ["Yes, the Partner is the boss.", "No, the report cannot be dated/signed until the EQCR provides \"Sign-off\" (completion of review).", "Yes, if they note the disagreement.", "Yes, if the client agrees."], "ans": 1, "exp": "The audit report cannot be dated until the EQCR is complete and any differences of opinion are resolved.*"}, {"q": "Scenario: The EQCR evaluates:", "options": ["Every single working paper.", "Significant judgments made and conclusions reached in formulating the report.", "The audit fee.", "The staff attendance."], "ans": 1, "exp": "The EQCR focuses on high-level judgments (e.g., Materiality, Going Concern, Modified Opinions), not detailed ticking of every voucher.*"}, {"q": "Scenario: Can the Engagement Partner consult the EQCR on difficult matters during the audit?", "options": ["No, that compromises independence.", "Yes, consultation is allowed, but the EQCR must maintain objectivity to perform the review later.", "No, the EQCR only comes at the end.", "Yes, the EQCR becomes part of the team."], "ans": 1, "exp": "Consultation is good, but the EQCR shouldn't make the decisions, otherwise, they can't \"review\" them objectively later.*\n\ud83d\udfe3 Section 4: Performance & Monitoring"}, {"q": "Scenario: \"Direction, Supervision, and Performance\" includes:", "options": ["Telling the team what to do, checking their work, and resolving issues.", "Paying the team.", "Hiring the team.", "Buying laptops."], "ans": 0, "exp": "This is the core management role of the Partner/Manager during the audit.*"}, {"q": "Scenario: A Junior Auditor finds a complex issue. He does not document it because he is afraid. Question: This is a failure of:", "options": ["Client Integrity.", "Direction and Supervision (Culture of Openness).", "EQCR.", "Ethics."], "ans": 1, "exp": "The Partner must create an environment where team members feel safe to raise difficult questions without fear.*"}, {"q": "Scenario: Reviews of audit work should be performed by:", "options": ["A team member of equal experience.", "A team member more experienced than the person who did the work.", "The client.", "A junior."], "ans": 1, "exp": "The reviewer must be senior/more experienced to effectively evaluate the work.*"}, {"q": "Scenario: The firm\u2019s \"Monitoring\" process involves inspecting a selection of completed audits periodically. Question: If deficiencies are found, what happens?", "options": ["The firm ignores them.", "Remedial action is taken (training, disciplinary action, or improving manuals).", "The client is sued.", "The fees are refunded."], "ans": 1, "exp": "Monitoring ensures the system of quality control is working. Failures lead to internal improvements/corrections.*"}, {"q": "Scenario: Differences of Opinion between the engagement team and the consultant/EQCR. Question:", "options": ["The Partner decides alone.", "The firm must have a policy to resolve such differences, and the report is not issued until resolved.", "The client decides.", "The majority votes."], "ans": 1, "exp": "Unresolved disputes on technical matters stop the report issuance.*"}, {"q": "Scenario: Documentation of Consultation. Question: If the team consults an expert on a complex tax issue, they must:", "options": ["Remember the advice.", "Document the nature of the consultation and the resulting decision.", "Ignore the advice if they dislike it.", "Pay the expert cash."], "ans": 1, "exp": "Everything must be documented. \"If it's not documented, it's not done.\"*"}, {"q": "Scenario: Independence requirements. Question: The Engagement Partner must:", "options": ["Assume everyone is independent.", "Obtain relevant information from the firm and team to identify/evaluate threats to independence.", "Ask the client if they feel independent.", "Only check financial interests."], "ans": 1, "exp": "The Partner must actively check for threats (e.g., family ties, shares) within the team.*"}, {"q": "Scenario: The final \"Assembly of Audit Files\" (Archiving) should happen:", "options": ["Within 60 days after the report date.", "Before the report date.", "Whenever the partner has time.", "Never."], "ans": 0, "exp": "ISQC 1 / ISA 230 requires final file assembly (locking the file) usually within 60 days to prevent tampering later.*\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Nature & Assurance Level"}, {"q": "Scenario: A client asks you to perform a \"Review Engagement\" instead of an Audit. Question: What level of assurance will you express in the final report?", "options": ["Absolute Assurance.", "Reasonable Assurance (Positive Form).", "Limited Assurance (Negative Form).", "No Assurance."], "ans": 2, "exp": "A review engagement provides Limited Assurance, which is lower than the Reasonable Assurance provided in an audit.*"}, {"q": "Scenario: In a Review Engagement, the conclusion is expressed as:", "options": ["\"In our opinion, the financial statements give a true and fair view...\"", "\"Based on our review, nothing has come to our attention that causes us to believe...\"", "\"We certify that the financial statements are correct...\"", "\"We do not express an opinion...\""], "ans": 1, "exp": "This is the standard wording for Negative Assurance. The auditor says, \"I didn't find anything wrong,\" rather than \"Everything is definitely right.\"*"}, {"q": "Scenario: Which of the following procedures is primarily used in a Review Engagement?", "options": ["Physical Stock Count.", "External Confirmations from Banks/Debtors.", "Inquiry and Analytical Procedures.", "Testing Internal Controls."], "ans": 2, "exp": "Unlike an audit, a review relies mainly on Inquiry (asking questions) and Analytical Procedures (checking trends/ratios).*"}, {"q": "Scenario: The practitioner is performing a review. He identifies a significant fluctuation in Gross Profit Margin. Question: What should he do first?", "options": ["Perform detailed test of details (vouching invoices).", "Inquire of management about the reason.", "Issue a qualified conclusion.", "Withdraw."], "ans": 1, "exp": "In a review, you start with inquiry. If the answer is plausible/reasonable, you might stop there. You only do detailed testing if the answer is unsatisfactory.*"}, {"q": "Scenario: Is the practitioner required to obtain an understanding of internal controls in a Review Engagement?", "options": ["Yes, extensive testing of controls is required.", "No, it is strictly prohibited.", "Yes, but only to the extent necessary to plan the review (Limited Understanding).", "Only if the client asks."], "ans": 2, "exp": "The practitioner needs a basic understanding of the entity and its environment (including systems) to identify where misstatements are likely, but does not test controls like in an audit.*"}, {"q": "Scenario: A practitioner is engaged to review the financial statements. He suspects fraud. Question: Can he perform additional procedures (like inspection or confirmation)?", "options": ["No, review engagements are limited to inquiry/analytics only.", "Yes, if he becomes aware of a matter that causes him to believe the FS are misstated, he must perform additional procedures.", "No, he must withdraw immediately.", "Yes, but he cannot charge for it."], "ans": 1, "exp": "While the standard procedures are Inquiry/Analytics, if a red flag (\"matter\") appears, the practitioner has a duty to investigate it further to clear the doubt.*\n\ud83d\udd35 Section 2: Procedures (Inquiry & Analytics)"}, {"q": "Scenario: Which of the following is typically NOT performed in a Review Engagement?", "options": ["Calculating the Current Ratio and comparing it to last year.", "Asking management about subsequent events.", "Sending positive confirmation requests to all 50 major debtors.", "Reading the minutes of board meetings."], "ans": 2, "exp": "External confirmations are substantive audit procedures. In a review, we usually rely on management's word and internal records unless suspicious.*"}, {"q": "Scenario: The practitioner asks management: \"Have all related party transactions been disclosed?\" Question: This is an example of:", "options": ["Analytical Procedure.", "Inquiry.", "Observation.", "Re-performance."], "ans": 1, "exp": "Inquiry is seeking information from knowledgeable persons.*"}, {"q": "Scenario: Materiality in a Review Engagement. Question:", "options": ["Is not required.", "Is the same concept as in an audit (Misstatements are material if they influence decisions).", "Is always higher than audit materiality.", "Is always lower."], "ans": 1, "exp": "The concept of materiality (user decision influence) remains the same, regardless of whether it's an audit or a review.*"}, {"q": "Scenario: The practitioner compares the current year's payroll expense with the prior year and adjusts for headcount changes. Question: This is:", "options": ["A Test of Detail.", "An Analytical Procedure.", "A Test of Control.", "An Inquiry."], "ans": 1, "exp": "Analyzing plausible relationships (Payroll vs Headcount) is an Analytical Procedure.*"}, {"q": "Scenario: Does the practitioner need to attend the physical inventory count in a Review Engagement?", "options": ["Yes, always.", "No, unless it is the only way to obtain limited assurance due to a specific risk.", "Yes, if inventory is material.", "Only if the client pays extra."], "ans": 1, "exp": "Attendance at stock counts is a core Audit procedure. In a Review, it is generally not performed unless there's a specific reason to doubt the inventory figure significantly.*"}, {"q": "Scenario: The practitioner obtains a Written Representation Letter from management in a Review Engagement. Question: Is this required?", "options": ["No, only for audits.", "Yes, ISRE 2400 requires written representations (similar to ISA 580).", "Only for public companies.", "Only if misstatements are found."], "ans": 1, "exp": "The practitioner must obtain written confirmation from management regarding their responsibilities and disclosures, just like in an audit.*\n\ud83d\udfe0 Section 3: Reporting & Conclusions"}, {"q": "Scenario: The practitioner finds a material misstatement in the financial statements. Management refuses to correct it. The effect is not pervasive. Question: What type of conclusion?", "options": ["Unmodified Conclusion.", "Qualified Conclusion (\"Except for\").", "Adverse Conclusion.", "Disclaimer of Conclusion."], "ans": 1, "exp": "Material but not pervasive error = Qualified Conclusion. The wording would be \"Based on our review, except for the effects of the matter...\"*"}, {"q": "Scenario: The practitioner finds a material and pervasive misstatement (e.g., Financial Statements are fundamentally misleading). Question: What type of conclusion?", "options": ["Qualified Conclusion.", "Adverse Conclusion.", "Disclaimer of Conclusion.", "Withdraw."], "ans": 1, "exp": "Pervasive misstatement = Adverse Conclusion (\"The financial statements do not give a true and fair view\").*"}, {"q": "Scenario: Management prevents the practitioner from asking questions about a material subsidiary (Scope Limitation). The effect is material but not pervasive. Question:", "options": ["Qualified Conclusion.", "Adverse Conclusion.", "Disclaimer of Conclusion.", "Unmodified."], "ans": 0, "exp": "Scope limitation (inability to complete review procedures) leads to a Qualified Conclusion if not pervasive.*"}, {"q": "Scenario: A Pervasive Scope Limitation exists (e.g., records destroyed). The practitioner cannot complete the review. Question:", "options": ["Disclaimer of Conclusion.", "Adverse Conclusion.", "Withdraw (or Disclaimer if withdrawal not possible).", "Qualified Conclusion."], "ans": 2, "exp": "In a Review, if you can't do the work (Pervasive Scope Limitation), you typically Withdraw. If withdrawal isn't legally possible, you Disclaim.*"}, {"q": "Scenario: The title of the report for a review engagement is usually:", "options": ["Independent Auditor's Report.", "Independent Practitioner's Review Report.", "Management Report.", "Internal Audit Report."], "ans": 1, "exp": "The term \"Auditor\" is reserved for Audits. For reviews, we use \"Practitioner\".*"}, {"q": "Scenario: Does the Review Report include an \"Emphasis of Matter\" (EOM) paragraph?", "options": ["No, never.", "Yes, if necessary to draw users' attention to a matter correctly disclosed (same principles as ISA 706).", "Only for fraud.", "Only for banks."], "ans": 1, "exp": "Yes, EOM and Other Matter paragraphs can be used in Review Reports under the same logic as Audit Reports.*\n\ud83d\udfe3 Section 4: General Concepts & Ethics"}, {"q": "Scenario: The practitioner is not independent of the client. Question: Can he perform a Review Engagement?", "options": ["Yes, if disclosed.", "No, Independence is required for all Assurance Engagements (Audit & Review).", "Yes, review is low level.", "Yes, if fees are low."], "ans": 1, "exp": "Review is an Assurance Engagement. Independence is mandatory.*"}, {"q": "Scenario: Which standard applies to Review Engagements?", "options": ["ISA 2400.", "ISRE 2400.", "ISRS 4400.", "ISAE 3000."], "ans": 1, "exp": "ISRE = International Standard on Review Engagements.*"}, {"q": "Scenario: \"Going Concern\" in a Review Engagement. Question: Does the practitioner need to consider Going Concern?", "options": ["No, that's for audits.", "Yes, he must inquire about management's assessment and consider any uncertainties.", "Only if the company is bankrupt.", "Only if disclosed."], "ans": 1, "exp": "Going concern is fundamental to FS preparation. The practitioner must inquire and check if the basis is appropriate.*"}, {"q": "Scenario: The practitioner is engaged to review Interim Financial Information (e.g., half-yearly). Question: Which standard applies?", "options": ["ISRE 2400.", "ISRE 2410 (Review by the Independent Auditor of the Entity).", "ISA 500.", "ISRS 4400."], "ans": 1, "exp": "If the reviewer is also the statutory auditor, ISRE 2410 applies. If a separate practitioner does the review, ISRE 2400 applies.*"}, {"q": "Scenario: A practitioner was hired to audit, but the client asks to downgrade to a review because they can't find invoices. Question:", "options": ["Accept immediately.", "Accept only if there is a \"Reasonable Justification\" (Lower fee is not justification).", "Reject always.", "Report to SECP."], "ans": 1, "exp": "Downgrading due to scope limitation (missing invoices) is usually NOT acceptable. There must be a valid business reason.*"}, {"q": "Scenario: Which creates \"Limited Assurance\"?", "options": ["High Risk + Low Testing.", "The nature of procedures (Inquiry/Analytics) + Limited Evidence.", "Management's signature.", "Low Fees."], "ans": 1, "exp": "The limited nature of the work (no vouching/testing) results in limited assurance.*"}, {"q": "Scenario: Can a practitioner rely on the work of another practitioner (e.g., for a subsidiary) in a Review?", "options": ["No.", "Yes, similar to using component auditors in an audit.", "Yes, but he must audit the subsidiary himself.", "Only if the subsidiary is immaterial."], "ans": 1, "exp": "Group reviews can involve other practitioners.*\n\ud83d\udfe4 Section 5: Tricky Scenarios"}, {"q": "Scenario: Management asks: \"Since you are only doing a review, can you ignore the Related Party disclosures?\" Question:", "options": ["Yes, reviews are less strict.", "No, the Financial Statements must still comply with the applicable framework (e.g., IFRS). Missing disclosure is a misstatement.", "Yes, if immaterial.", "Yes, if management signs."], "ans": 1, "exp": "\"Limited Assurance\" refers to the auditor's work, not the quality of the Financial Statements. The FS must still be perfect (comply with IFRS).*"}, {"q": "Scenario: The practitioner concludes: \"Nothing has come to our attention... except for the Inventory which is overstated by $1m.\" Question: Is this valid wording?", "options": ["Yes, this is a Qualified Conclusion.", "No, you cannot mention specific errors in negative assurance.", "No, this is an Adverse conclusion.", "No, this is a Disclaimer."], "ans": 0, "exp": "This is the correct format for a Qualified Conclusion in a review.*"}, {"q": "Scenario: Difference between \"Agreed Upon Procedures\" (AUP) and \"Review\". Question:", "options": ["Review gives Limited Assurance; AUP gives No Assurance.", "AUP gives Limited Assurance.", "Both give Reasonable Assurance.", "Review is strictly for banks."], "ans": 0, "exp": "AUP (ISRS 4400) provides just facts (findings), no assurance opinion. Review provides Limited Assurance.*"}, {"q": "Scenario: The practitioner uses the work of an Expert (e.g., for property valuation) in a Review. Question:", "options": ["Not allowed.", "Allowed, he evaluates the expert's competence and objectivity.", "He must become an expert himself.", "He must ignore the valuation."], "ans": 1, "exp": "Use of experts is allowed if necessary to form a conclusion.*"}, {"q": "Scenario: Acceptance of Engagement. Question: The practitioner should NOT accept a review engagement if:", "options": ["He has no knowledge of the industry.", "There is a limitation on scope imposed by management before acceptance that will result in a Disclaimer.", "The fee is low.", "The client is small."], "ans": 1, "exp": "Never accept an engagement if you know beforehand you won't be able to give an opinion (Disclaimer).*\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Strategy & Planning Activities"}, {"q": "Scenario: The auditor is appointed for a new client. Before starting detailed testing, the partner discusses \"What, When, and How\" the audit will be conducted (e.g., timing, resources, scope). Question: This document is called:", "options": ["Audit Plan.", "Overall Audit Strategy.", "Engagement Letter.", "Audit Program."], "ans": 1, "exp": "The Strategy sets the scope, timing, and direction. The \"Plan\" is more detailed (nature, timing, and extent of procedures).*"}, {"q": "Scenario: During the planning phase, the auditor identifies that the client uses a complex automated revenue system (e.g., Telecom). Question: How does this affect the audit strategy?", "options": ["The auditor will plan to rely more on substantive testing.", "The auditor will plan to involve IT Experts and test General IT Controls (GITCs).", "The auditor will ignore the system.", "The auditor will outsource the audit."], "ans": 1, "exp": "High-tech environments require IT expertise and control testing as part of the strategy.*"}, {"q": "Scenario: The auditor decides to perform an \"Interim Audit\" in November (Year-end is December). Question: Which procedure is arguably least effective to perform at an interim date?", "options": ["Testing Internal Controls.", "Risk Assessment Procedures.", "Confirming Year-End Bank Balances.", "Analytical Procedures on 9-month data."], "ans": 2, "exp": "You cannot confirm year-end balances before the year-end. This must be done after 31 Dec. Controls and Analytics can be done at interim.*"}, {"q": "Scenario: The auditor sets Materiality at the planning stage based on \"Budgeted Profit\". At year-end, the \"Actual Profit\" is significantly lower. Question: What should the auditor do?", "options": ["Ignore the change.", "Revise Materiality downwards and potentially increase audit testing (lower threshold finds more errors).", "Revise Materiality upwards.", "Withdraw."], "ans": 1, "exp": "If profit drops, materiality drops. A lower materiality means smaller errors become significant, so the auditor might need to test more items.*"}, {"q": "Scenario: Why does the auditor need to understand the \"Applicable Financial Reporting Framework\" (FRF) during planning?", "options": ["To help management prepare accounts.", "To determine if the financial statements are prepared in accordance with the correct rules (e.g., IFRS vs Local GAAP).", "To calculate tax.", "To set the fees."], "ans": 1, "exp": "You can't audit if you don't know the rules (FRF) the company is supposed to follow.*\n\ud83d\udd35 Section 2: Interim vs Final Audit"}, {"q": "Scenario: The auditor tests internal controls in October (Interim Audit) and finds them effective. Question: What must the auditor do for the remaining period (Nov-Dec)?", "options": ["Nothing, controls are effective.", "Perform \"Roll-forward\" procedures to ensure controls remained effective during the remaining period.", "Retest the whole year.", "Assume controls failed."], "ans": 1, "exp": "You cannot assume controls worked in Dec just because they worked in Oct. You must verify the gap (Roll-forward).*"}, {"q": "Scenario: A client has tight reporting deadlines (needs audit done by 15 Jan). Question: How does this affect planning?", "options": ["The auditor should refuse the client.", "The auditor should plan to perform significant work at an \"Interim Audit\" (before year-end) to reduce year-end pressure.", "The auditor should work 24 hours a day.", "The auditor should skip procedures."], "ans": 1, "exp": "Interim audits are the standard strategy for tight deadlines.*"}, {"q": "Scenario: Which of the following is a benefit of planning?", "options": ["It guarantees no fraud will occur.", "It helps organize the engagement to be performed effectively and efficiently (e.g., assigning right team members to right risks).", "It increases the fee.", "It reduces client responsibility."], "ans": 1, "exp": "Planning is about efficiency, resource allocation, and focusing on high-risk areas.*"}, {"q": "Scenario: The auditor learns that the client has a subsidiary in the USA. Question: How does this impact the audit strategy?", "options": ["No impact.", "The auditor must plan for group reporting, currency translation (IAS 21), and coordination with US component auditors.", "The auditor should exclude the US branch.", "The auditor should travel immediately."], "ans": 1, "exp": "Location of components adds complexity (Forex, Regulation, Group Audit) that must be strategized early.*"}, {"q": "Scenario: \"Preliminary Analytical Procedures\" performed at the planning stage help to:", "options": ["Detect all frauds.", "Identify unusual transactions or trends that indicate high-risk areas (e.g., Revenue up, Cash down).", "Replace substantive testing.", "Verify assets."], "ans": 1, "exp": "Planning analytics are used to spot \"odd\" things that need attention during the audit (Risk Identification).*\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Nature & Purpose"}, {"q": "Scenario: An auditor performed a complex inventory observation but did not document the details in the working papers, assuming \"I can explain it if anyone asks.\" Question: According to ISA 230, if it is not documented:", "options": ["It is assumed to be done if the auditor is honest.", "It is considered \"Not Done.\"", "The auditor can provide an oral explanation later to prove it.", "Management can confirm it."], "ans": 1, "exp": "\"Not documented = Not done.\" Oral explanations alone are not sufficient to support the work performed.*"}, {"q": "Scenario: The \"Experienced Auditor\" principle states that audit documentation should be sufficient to enable an experienced auditor, having no previous connection with the audit, to understand:", "options": ["The name of the client only.", "The nature, timing, and extent of procedures, the results, and significant matters.", "Every single conversation held with the client.", "The audit fee."], "ans": 1, "exp": "Documentation must be self-explanatory so that another competent auditor can understand the work without needing the original auditor to explain it.*"}, {"q": "Scenario: Which of the following is NOT a primary purpose of audit documentation?", "options": ["To assist the team to plan and perform the audit.", "To provide evidence for the audit opinion.", "To provide a list of errors to the tax authorities.", "To enable the team to be accountable for its work."], "ans": 2, "exp": "While tax authorities might ask for info, the primary purpose of audit documentation is internal quality, evidence, and accountability, not tax reporting.*"}, {"q": "Scenario: The auditor keeps copies of the client\u2019s original contracts in the audit file. Question:", "options": ["This is prohibited; originals must be kept by the client.", "Copies (or scans) are acceptable as audit documentation.", "The auditor must keep the originals.", "The auditor should memorize the contracts."], "ans": 1, "exp": "Auditors usually keep copies/scans. Originals belong to the client.*\n\ud83d\udd35 Section 2: Form, Content & Extent"}, {"q": "Scenario: When documenting the \"Nature, Timing, and Extent\" of procedures, the auditor must record:", "options": ["Who performed the work and the date it was completed.", "Who reviewed the work and the date of review.", "Identifying characteristics of specific items tested (e.g., Invoice numbers).", "All of the above."], "ans": 3, "exp": "ISA 230 requires documenting the \"Who, When, and What\" (specific items tested).*"}, {"q": "Scenario: The auditor departs from a relevant requirement of an ISA due to specific circumstances. Question: What must be documented?", "options": ["Nothing, if the partner agrees.", "The reason for the departure and how alternative procedures achieved the objective.", "A disclaimer of opinion.", "An apology letter."], "ans": 1, "exp": "Departures are rare. If they happen, you must justify why and prove you achieved the goal differently.*"}, {"q": "Scenario: During the audit, the team creates several drafts of the financial statements and preliminary notes that are now superseded. Question: Should these drafts be kept in the final audit file?", "options": ["Yes, keep everything.", "No, superseded drafts and preliminary notes should generally be discarded to avoid confusion.", "Yes, to show hard work.", "Only if the client asks."], "ans": 1, "exp": "The final file should contain the final conclusions. Superseded drafts are usually deleted/discarded.*"}, {"q": "Scenario: An auditor finds a contradiction between a piece of evidence and the final conclusion. Question:", "options": ["Delete the contradictory evidence.", "Document how the contradiction was addressed or resolved.", "Ignore it.", "Resign."], "ans": 1, "exp": "You cannot hide bad evidence. You must document how you resolved the inconsistency (e.g., \"We found X, but Y proved X was wrong because...\").*\n\ud83d\udfe0 Section 3: Assembly & Retention"}, {"q": "Scenario: The Auditor's Report is dated 31 March. By what date must the final audit file be assembled (Assembly Deadline)?", "options": ["31 March (Same day).", "30 April (30 days).", "30 May (60 days).", "31 December (End of year)."], "ans": 2, "exp": "ISQC 1 and ISA 230 typically require assembly within 60 days after the audit report date.*"}, {"q": "Scenario: After the assembly period (60 days) has ended, the auditor realizes he forgot to include a summary sheet that was already prepared. Question: Can he add it?", "options": ["No, the file is frozen.", "Yes, this is an administrative change. He must document when and by whom it was added.", "Yes, but he must change the audit report date.", "No, he must delete the file."], "ans": 1, "exp": "You can make \"administrative\" changes (sorting, adding missed papers that existed) but NOT \"new audit procedures\" after the assembly date.*"}, {"q": "Scenario: How long must the audit firm retain the audit documentation?", "options": ["1 year.", "3 years.", "5 years (or longer if local law requires).", "Forever."], "ans": 2, "exp": "ISQC 1 mandates a retention period of no shorter than 5 years from the date of the auditor\u2019s report.*"}, {"q": "Scenario: A junior auditor wants to delete a working paper after the retention period starts but before the 5 years are up. Question:", "options": ["Allowed if the partner says so.", "Prohibited. Documentation must not be deleted or discarded before the end of the retention period.", "Allowed if the client left.", "Allowed if the file is full."], "ans": 1, "exp": "Once the file is finalized, nothing should be deleted until the retention period (5+ years) expires.*\n\ud83d\udfe3 Section 4: Ownership & Confidentiality"}, {"q": "Scenario: The client demands that the auditor hand over all working papers because \"We paid the audit fee, so we own them.\" Question: Who owns the working papers?", "options": ["The Client.", "The Auditor.", "The Government.", "Joint ownership."], "ans": 1, "exp": "Audit documentation is the property of the Auditor. The client pays for the Opinion, not the papers.*"}, {"q": "Scenario: Can the auditor show the working papers to the client?", "options": ["Never.", "Yes, at the auditor's discretion, provided it doesn't undermine the independence or validity of the audit (e.g., showing sampling selection).", "Yes, the client has a legal right to see everything.", "Only if the police ask."], "ans": 1, "exp": "The auditor can show parts (e.g., to explain an adjustment), but shouldn't show things that would help the client cheat next time (like predictable sampling patterns).*"}, {"q": "Scenario: A regulator (e.g., SECP/ICAP) demands access to the working papers for a Quality Assurance review. Question: Can the auditor refuse due to \"Client Confidentiality\"?", "options": ["Yes.", "No, legal/regulatory duty overrides confidentiality.", "Only if the client agrees.", "Only if the fee is refunded."], "ans": 1, "exp": "Auditors must provide access to regulators for quality reviews; confidentiality does not apply here.*\n\ud83d\udfe4 Section 5: Specific Situations"}, {"q": "Scenario: The auditor discovers a material misstatement after the audit report has been issued (Subsequent Event). He performs new procedures. Question: What must be documented regarding these new procedures?", "options": ["Nothing, the audit is over.", "The new procedures, the evidence obtained, the conclusions, AND who made the changes and when (Date/Person).", "Just replace the old pages.", "Write a new report only."], "ans": 1, "exp": "For exceptional changes after the report date, you must document the \"Why, Who, and When\" and the specific impact.*"}, {"q": "Scenario: The auditor uses a checklist to ensure all ISAs are followed. Question: Is a completed checklist considered audit documentation?", "options": ["No, only memos count.", "Yes, checklists are valid evidence of compliance.", "Only if typed.", "No."], "ans": 1, "exp": "Checklists, programs, and memos are all valid forms of documentation.*"}, {"q": "Scenario: \"Oral explanations\" by the auditor. Question:", "options": ["Can be used to clarify or explain information contained in the audit documentation, but cannot replace missing documentation.", "Are sufficient evidence on their own.", "Are not allowed.", "Must be recorded on video."], "ans": 0, "exp": "If the paper says \"Tested Invoice #5\", the auditor can orally explain how he tested it. But if the paper is blank, he can't orally say \"I tested Invoice #5\".*"}, {"q": "Scenario: An auditor takes a photo of a physical inventory count sheet with his phone and uploads it to the audit file. Question:", "options": ["Not allowed, must be scanned.", "Allowed, electronic media is a valid form of documentation.", "Not allowed, must be paper.", "Allowed only if printed."], "ans": 1, "exp": "Documentation can be on paper, electronic, or other media.*"}, {"q": "Scenario: Scanning original documents. Question: If the auditor scans a purchase invoice and saves it electronically, can he destroy the paper copy (if he owns it)?", "options": ["Yes, if the scanned copy is a faithful reproduction and indexing is preserved.", "No, never.", "Only if the client agrees.", "Only for tax invoices."], "ans": 0, "exp": "Electronic storage is permitted if it accurately reflects the original.*\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Preconditions for an Audit"}, {"q": "Scenario: Before accepting a new audit engagement, the auditor must establish whether the \"Preconditions for an Audit\" are present. Question: Which of the following is NOT a precondition?", "options": ["Management accepts responsibility for preparing the Financial Statements.", "Management agrees to provide the auditor with access to all relevant information.", "Management guarantees that the company will be profitable.", "The Financial Reporting Framework (e.g., IFRS) used is acceptable."], "ans": 2, "exp": "The auditor needs the framework and cooperation, not a guarantee of profit.*"}, {"q": "Scenario: Management refuses to include a statement in the engagement letter acknowledging their responsibility for \"Internal Control\". Question: What should the auditor do?", "options": ["Accept the engagement but audit controls more strictly.", "Decline the engagement (unless law prescribes otherwise).", "Accept but issue a Disclaimer.", "Charge a higher fee."], "ans": 1, "exp": "If management refuses to acknowledge their fundamental responsibilities (Preconditions), the auditor cannot accept the engagement.*"}, {"q": "Scenario: The auditor determines that the \"Financial Reporting Framework\" (FRF) chosen by management is unacceptable (e.g., they use \"Cash Basis\" for a large listed company). Question:", "options": ["Accept and issue an Adverse Opinion.", "Decline the engagement.", "Accept and fix the accounts.", "Accept if management pays extra."], "ans": 1, "exp": "If the framework is unacceptable, the financial statements will be misleading. The auditor should not accept the engagement at all.*"}, {"q": "Scenario: Management limits the scope of the auditor\u2019s work before the engagement begins (e.g., \"You cannot audit our foreign branch\"). The auditor believes this will result in a Disclaimer of Opinion. Question:", "options": ["Accept and issue a Disclaimer.", "Decline the engagement.", "Accept and ignore the branch.", "Report to the police."], "ans": 1, "exp": "An auditor should not accept an engagement where the scope is so limited by management at the start that they know they can't give an opinion.*\n\ud83d\udd35 Section 2: Engagement Letter Terms"}, {"q": "Scenario: When should the Audit Engagement Letter be agreed upon and signed?", "options": ["After the audit report is issued.", "Before the audit work commences.", "During the final review.", "When the invoice is sent."], "ans": 1, "exp": "It is a contract. You must agree on the terms before starting the work to avoid misunderstandings.*"}, {"q": "Scenario: The engagement letter includes the \"Objective and Scope of the audit\". Question: Does it also include the \"Auditor's Opinion\"?", "options": ["Yes, it predicts the opinion.", "No, it states the expected form of the report, but warns that the actual opinion may differ.", "Yes, it guarantees a clean opinion.", "No."], "ans": 1, "exp": "The letter sets expectations (e.g., \"We will issue a report under ISA 700\"), but clarifies that the final opinion depends on findings.*"}, {"q": "Scenario: Who signs the Engagement Letter?", "options": ["The Auditor and the Shareholders.", "The Auditor and Management (usually CEO/CFO or Audit Committee).", "The Government.", "The Internal Auditor."], "ans": 1, "exp": "It is a contract between the Auditor and the Management/TCWG.*"}, {"q": "Scenario: Why is it important to define \"Management's Responsibility\" in the letter?", "options": ["To protect the auditor from liability if management commits fraud or fails to prepare accounts.", "To make management work harder.", "To reduce the audit fee.", "It is a formality."], "ans": 0, "exp": "It clarifies that \"Preparation\" is their job and \"Auditing\" is the auditor's job, preventing the Expectation Gap.*\n\ud83d\udfe0 Section 3: Recurring Audits"}, {"q": "Scenario: For a recurring audit (auditing the same client next year), is a new engagement letter required every year?", "options": ["Yes, mandatory every year.", "No, not mandatory every year unless circumstances require revision.", "No, once signed, it is valid forever without change.", "Only if the fee changes."], "ans": 1, "exp": "ISA 210 says you don't need a new letter every year, but you should remind the client of the terms. A new letter is needed only if terms change.*"}, {"q": "Scenario: Which factor would make it appropriate to send a new engagement letter for a recurring audit?", "options": ["A recent change in Senior Management.", "A significant change in ownership.", "A change in legal or regulatory requirements.", "All of the above."], "ans": 3, "exp": "Significant changes in management, ownership, or laws mean the old agreement might be misunderstood or invalid.*"}, {"q": "Scenario: The client has misunderstood the objective of the audit (e.g., they think the auditor will find 100% of frauds). Question: What should the auditor do for the next year's audit?", "options": ["Ignore it.", "Send a new engagement letter to clarify the objective and scope.", "Resign.", "Charge for fraud investigation."], "ans": 1, "exp": "If there is a misunderstanding, the auditor must revise/remind the terms to correct it.*\n\ud83d\udfe3 Section 4: Change in Terms"}, {"q": "Scenario: During the audit, the client asks to change the engagement from an Audit to a Review (lower assurance) because they cannot find the invoices. Question:", "options": ["Accept, because the client is king.", "Reject, because there is no \"Reasonable Justification\" (Missing evidence is not a valid reason).", "Accept, but charge the same fee.", "Reject and sue the client."], "ans": 1, "exp": "You cannot downgrade to a review just to avoid a qualified opinion/disclaimer. That is not a reasonable justification.*"}, {"q": "Scenario: The client asks to change to a Review engagement because the bank requirement changed (Bank no longer needs an Audit, just a Review). Question:", "options": ["Accept, this is a \"Reasonable Justification\".", "Reject.", "Accept, but mention the original audit work in the report.", "Resign."], "ans": 0, "exp": "A change in business requirements (Bank's need) is a valid reason to change the engagement terms.*"}, {"q": "Scenario: If the auditor agrees to change the engagement to a Review, the final report should:", "options": ["Mention the original audit procedures performed.", "NOT mention the original audit engagement or procedures (to avoid confusing users).", "Be a disclaimer.", "Be an audit report."], "ans": 1, "exp": "The report should reflect the new engagement (Review) only. Mentioning the abandoned audit might mislead users into thinking substantial audit work was done.*"}, {"q": "Scenario: If the auditor is unable to agree to a change in terms (because it's unreasonable) and management forbids continuing the original audit. Question:", "options": ["Continue the audit anyway.", "Withdraw from the engagement and consider reporting to regulators.", "Issue a Review report.", "Issue a clean opinion."], "ans": 1, "exp": "If you can't go down (unreasonable request) and can't go forward (management blockage), you must get out (Withdraw).*\n\ud83d\udfe4 Section 5: Specific Scenarios"}, {"q": "Scenario: Component Auditor. The parent company's auditor is also the auditor of the subsidiary. Question: Do they need to send a separate engagement letter to the subsidiary?", "options": ["No, one letter to the Parent covers everything.", "It depends on factors like who appoints the auditor, legal requirements, and degree of independence. Usually, a separate letter is preferred.", "Yes, always mandatory.", "No, never."], "ans": 1, "exp": "If the subsidiary is a separate legal entity with its own board, a separate letter is usually sent unless specific group terms apply.*"}, {"q": "Scenario: Financial Reporting Standards change significantly (e.g., introduction of IFRS). Question:", "options": ["No need for new letter.", "Send a new engagement letter to acknowledge the new framework responsibility.", "Resign.", "Ignore."], "ans": 1, "exp": "A change in the \"Preconditions\" (Framework) requires re-agreeing the terms.*"}, {"q": "Scenario: The auditor accepts an engagement assuming it's a \"General Purpose\" audit. Later, he finds it's a \"Special Purpose\" audit. Question:", "options": ["Continue as is.", "Discuss with management and issue a new Engagement Letter reflecting the correct scope.", "Withdraw.", "Charge double."], "ans": 1, "exp": "The terms (Objective/Scope) were wrong. They must be corrected formally.*"}, {"q": "Scenario: Can the engagement letter limit the auditor's liability (e.g., \"We are not liable for more than $1m\")?", "options": ["Yes, always.", "No, usually prohibited by Companies Act or Ethics (Indemnification).", "Yes, if the client agrees.", "Yes, for private companies only."], "ans": 1, "exp": "In many jurisdictions (like Pakistan/UK), auditors cannot cap their liability for negligence in the engagement letter. It's void.*"}, {"q": "Scenario: The purpose of the \"Expected form and content of any reports\" section in the letter is:", "options": ["To guarantee a clean report.", "To inform the client what the output will look like (e.g., \"Auditor's Report on FS\"), while noting it might change.", "To list all the errors.", "To invoice the client."], "ans": 1, "exp": "It sets the deliverable expectation.*\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Internal vs. External Audit"}, {"q": "Scenario: The primary objective of the Internal Auditor is to:", "options": ["Express an opinion on the financial statements to shareholders.", "Detect all frauds.", "Evaluate and improve the effectiveness of risk management, control, and governance processes.", "Prepare the tax return."], "ans": 2, "exp": "Internal audit focuses on improving the company's operations and controls for management, whereas external audit focuses on the financial opinion for shareholders.*"}, {"q": "Scenario: To whom does the Internal Auditor typically report to ensure maximum independence?", "options": ["The CFO.", "The CEO.", "The Audit Committee (Board of Directors).", "The External Auditor."], "ans": 2, "exp": "Reporting to the Audit Committee allows the Internal Auditor to report on management's failures without fear of the CEO/CFO.*"}, {"q": "Scenario: Which of the following functions is NOT a typical role of Internal Audit?", "options": ["Monitoring Internal Controls.", "Examination of Financial and Operating information.", "Expressing an independent audit opinion on the annual financial statements.", "Review of compliance with laws and regulations."], "ans": 2, "exp": "Expressing the independent opinion on FS is the exclusive role of the External Auditor.*"}, {"q": "Scenario: The External Auditor wants to use the work of the Internal Audit function. What is the first thing he must evaluate?", "options": ["The size of the internal audit department.", "The objectivity, competence, and systematic approach of the internal audit function.", "The salary of the internal auditors.", "The software they use."], "ans": 1, "exp": "ISA 610 requires evaluating Objectivity (Independence), Competence (Skills), and Systematic Approach (Quality Control) before relying on them.*\n\ud83d\udd35 Section 2: Using the Work of Internal Audit"}, {"q": "Scenario: The Internal Audit department reports directly to the CFO (who is also responsible for the accounts being audited). Question: Can the External Auditor rely on their work?", "options": ["Yes, because they are competent.", "No, because their Objectivity is compromised (Self-Review threat).", "Yes, if they promise to be honest.", "Only for payroll."], "ans": 1, "exp": "Reporting to the person you are auditing (CFO) destroys objectivity. The external auditor cannot rely on such work for high-risk areas.*"}, {"q": "Scenario: The External Auditor decides to use the Internal Auditor's work on \"Inventory Count Observation\". Question: Who remains responsible for the audit opinion?", "options": ["The Internal Auditor.", "The External Auditor (Sole Responsibility).", "Joint Responsibility.", "Management."], "ans": 1, "exp": "The external auditor has sole responsibility for the audit opinion, regardless of how much internal audit work is used.*"}, {"q": "Scenario: Before using specific work of the internal auditors, the external auditor must:", "options": ["Re-perform some of the body of work to ensure it is adequate.", "Trust it blindly.", "Ask the CEO if it's good.", "Copy it into the file."], "ans": 0, "exp": "ISA 610 requires the external auditor to re-perform a sample of the internal auditor's work to validate its quality.*"}, {"q": "Scenario: Can the external auditor use the internal auditor's work to determine \"Materiality\"?", "options": ["Yes, they know the business better.", "No, setting Materiality is a significant judgment that must be made by the external auditor.", "Yes, if approved by the Board.", "Only for Performance Materiality."], "ans": 1, "exp": "High-judgment decisions (Materiality, Risk Assessment, Opinion) cannot be outsourced. The external auditor must make them.*"}, {"q": "Scenario: The Internal Auditors are highly competent but they do not document their work properly (No systematic approach). Question: Can the external auditor use their work?", "options": ["Yes, competence is enough.", "No, a \"Systematic and Disciplined Approach\" (including documentation) is a mandatory requirement.", "Yes, based on oral discussions.", "Only for small amounts."], "ans": 1, "exp": "Without a systematic approach and documentation, the work is not reliable for external audit purposes.*\n\ud83d\udfe0 Section 3: Direct Assistance"}, {"q": "Scenario: \"Direct Assistance\" means:", "options": ["The internal auditor performs work under the direction, supervision, and review of the external auditor.", "The external auditor uses reports already prepared by internal audit.", "The internal auditor prepares the financial statements.", "The external auditor hires the internal auditor."], "ans": 0, "exp": "Direct assistance is when the internal auditor acts like a staff member of the external audit team for a specific task.*"}, {"q": "Scenario: Is \"Direct Assistance\" allowed in all jurisdictions?", "options": ["Yes, global standard.", "No, some countries (like UK) prohibit it. The auditor must check local laws.", "No, it is banned by ISA 610.", "Only in USA."], "ans": 1, "exp": "ISA 610 allows it, but many local regulators forbid it to protect independence. The auditor must check if it's legally permitted.*"}, {"q": "Scenario: Can the External Auditor ask the Internal Auditor to perform \"Direct Assistance\" on a high-risk area involving significant judgment (e.g., Valuation of Intangibles)?", "options": ["Yes, if supervised.", "No, direct assistance cannot be used for significant judgments or high-risk areas.", "Yes, if they are experts.", "Only if the fee is reduced."], "ans": 1, "exp": "Direct assistance is restricted to low-risk, mechanical tasks (e.g., casting, testing simple controls). High judgment areas must be done by the external auditor.*"}, {"q": "Scenario: Before using internal auditors for Direct Assistance, the external auditor must obtain:", "options": ["A written agreement from Management (not to intervene) and from the Internal Auditors (to keep confidentiality).", "A fee reduction.", "Permission from the government.", "A copy of their CV."], "ans": 0, "exp": "Written agreements are needed to ensure the internal auditors can work freely without management interference.*"}, {"q": "Scenario: If the internal auditor is providing Direct Assistance, who reviews their work?", "options": ["The Internal Audit Manager.", "The External Auditor.", "The CFO.", "No one."], "ans": 1, "exp": "Since they are working for the external auditor, the external auditor must direct, supervise, and review their work.*\n\ud83d\udfe3 Section 4: General Concepts"}, {"q": "Scenario: The Internal Audit function identifies a significant deficiency in internal control. Question: They fix it and don't tell the External Auditor.", "options": ["Good practice.", "Bad practice. They should communicate significant issues to the External Auditor.", "Irrelevant.", "Illegal."], "ans": 1, "exp": "Open communication is key. Hiding deficiencies might lead the external auditor to rely on bad controls.*"}, {"q": "Scenario: Which factor decreases the external auditor's ability to rely on internal audit?", "options": ["The internal auditors are members of a professional body (e.g., CIA, ACCA).", "The internal auditors act as \"Management\" (e.g., approving transactions).", "The internal audit department is large.", "They report to the Audit Committee."], "ans": 1, "exp": "If internal auditors make management decisions (approving transactions), they lose objectivity (Self-Review). You cannot rely on them.*"}, {"q": "Scenario: When using the work of internal auditors, the external auditor should document:", "options": ["The evaluation of their competence and objectivity.", "The nature and extent of the work used.", "The review procedures performed on their work.", "All of the above."], "ans": 3, "exp": "Full documentation of the \"Why\" (Competence) and \"How\" (Review) is required.*"}, {"q": "Scenario: Can the external auditor use internal audit work to reduce the scope of substantive procedures?", "options": ["Yes, if the internal audit work confirms controls are strong.", "No, never.", "Yes, they can eliminate substantive procedures entirely.", "Only for banks."], "ans": 0, "exp": "Effective controls tested by internal audit allow the external auditor to reduce (but not eliminate) substantive testing.*"}, {"q": "Scenario: The internal auditor is the son of the CFO. Question: Can the external auditor use his work?", "options": ["Yes, if he is smart.", "No, significant threat to Objectivity (Familiarity/Intimidation).", "Yes, for cash counts.", "Yes, for payroll."], "ans": 1, "exp": "Close family relationships with management compromise objectivity.*"}, {"q": "Scenario: The external auditor plans to use internal audit work. When should this be coordinated?", "options": ["At the end of the audit.", "At the planning stage.", "During the reporting stage.", "Never."], "ans": 1, "exp": "Coordination at the planning stage ensures efficiency and avoids duplication of work.*\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: IT Controls (General vs. Application)"}, {"q": "Scenario: The auditor finds that the client's system automatically checks if the \"Invoice Date\" is in the current accounting period. Question: This is an example of:", "options": ["General IT Control (GITC).", "Application Control.", "Manual Control.", "Physical Control."], "ans": 1, "exp": "Application controls apply to specific transactions (like checking invoice dates) within a software application.*"}, {"q": "Scenario: The company has a policy that all employees must change their passwords every 90 days. Question: This is an example of:", "options": ["Application Control.", "General IT Control (GIT", ". C) Output Control.", "Batch Control."], "ans": 1, "exp": "GITCs (like password policies) apply to the overall IT environment and support the effective functioning of application controls.*"}, {"q": "Scenario: Which of the following is NOT a General IT Control (GITC)?", "options": ["Data center and network operations.", "Program change controls.", "Access security (e.g., Firewall).", "A \"Range Check\" preventing salaries > $10,000."], "ans": 3, "exp": "A \"Range Check\" is an Application Control (Input Validation) specific to payroll processing. The others affect the whole system.*"}, {"q": "Scenario: If General IT Controls (GITCs) are weak (e.g., anyone can change the program code). Question: Can the auditor rely on Application Controls?", "options": ["Yes, if the application controls are automated.", "No, because weak GITCs undermine the reliability of application controls (someone could turn them off).", "Yes, if the math is correct.", "Only for revenue."], "ans": 1, "exp": "Strong GITCs are the foundation. If the foundation is weak (e.g., unauthorized changes possible), the application controls cannot be trusted.*"}, {"q": "Scenario: To ensure that \"Only authorized goods are paid for,\" the system matches the Purchase Order (PO), Goods Received Note (GRN), and Invoice. Question: This automated \"Three-Way Match\" is:", "options": ["A Preventive Application Control.", "A Detective GITC.", "A Manual Control.", "A Corrective Control."], "ans": 0, "exp": "The system prevents payment if the documents don't match.*"}, {"q": "Scenario: \"Segregation of Duties\" in an IT environment usually means separating:", "options": ["The CEO and CFO.", "Programmers (who write code) and Operators (who run the system / live environment).", "Hardware and Software.", "Input and Output."], "ans": 1, "exp": "If a programmer can also operate the live system, they can insert fraudulent code and run it without detection.*\n\ud83d\udd35 Section 2: Input, Processing & Output Controls"}, {"q": "Scenario: When entering a Customer ID, the system displays the \"Customer Name\" for the operator to verify. Question: This control is called:", "options": ["Check Digit.", "Sequence Check.", "Check Sum.", "Validity Check (or Feedback Check)."], "ans": 3, "exp": "The system validates the ID by providing feedback (Name) to ensure the user entered the right code.*"}, {"q": "Scenario: A \"Batch Total\" of invoice values is calculated manually ($50,000) and compared to the system-generated total after data entry. Question: This is designed to detect:", "options": ["Unauthorized access.", "Incomplete or inaccurate processing of the batch.", "Virus attacks.", "Hardware failure."], "ans": 1, "exp": "If the totals don't match, it means a document was missed (Completeness) or entered wrong (Accuracy).*"}, {"q": "Scenario: The system refuses to process a sales order if the \"Quantity\" field contains letters instead of numbers. Question: This is a:", "options": ["Limit Check.", "Format Check (or Character Check).", "Range Check.", "Existence Check."], "ans": 1, "exp": "Ensuring the data is in the correct format (Numeric vs Alpha).*"}, {"q": "Scenario: \"Sequence Check\" (e.g., looking for gaps in invoice numbers 101, 102, 104...). Question: This primarily addresses the assertion of:", "options": ["Valuation.", "Completeness.", "Rights.", "Accuracy."], "ans": 1, "exp": "Missing numbers in a sequence suggest missing transactions (Completeness).*"}, {"q": "Scenario: \"Limit Check\" vs \"Range Check\". Question: A system ensures that \"Hours Worked\" cannot be less than 0 or more than 24 per day. This is:", "options": ["A Limit Check.", "A Range Check.", "A Sign Check.", "A Batch Check."], "ans": 1, "exp": "A Range Check has both an upper and lower limit. A Limit Check usually has only one (e.g., Credit Limit).*"}, {"q": "Scenario: An \"Exception Report\" is generated for all overtime payments exceeding $1,000. Question: For this control to be effective, who must review it?", "options": ["The computer.", "An appropriate manager who takes action.", "The filing clerk.", "No one."], "ans": 1, "exp": "Producing a report is useless if management doesn't review and resolve the exceptions.*\n\ud83d\udfe0 Section 3: CAATs (Computer Assisted Audit Techniques)"}, {"q": "Scenario: The auditor uses \"Audit Software\" (GAS) to extract all invoices over $10,000 from the client's database. Question: This is an example of:", "options": ["Test Data.", "Substantive Procedures using CAATs.", "Compliance Testing.", "Manual Audit."], "ans": 1, "exp": "Using software to analyze actual client data for substantive evidence.*"}, {"q": "Scenario: The auditor enters a \"Fake Transaction\" (e.g., a sale to a customer over credit limit) into the client's system to see if the system blocks it. Question: This technique is called:", "options": ["Audit Software.", "Test Data.", "Parallel Simulation.", "Embedded Audit Facility."], "ans": 1, "exp": "Test Data involves putting auditor's dummy data into the client's system to test controls.*"}, {"q": "Scenario: What is a major risk when using \"Test Data\" in a live environment?", "options": ["It is too expensive.", "The fake data might corrupt the client\u2019s real records (e.g., creating a fake debt).", "The computer might break.", "It takes too long."], "ans": 1, "exp": "The auditor must ensure \"Test Data\" is reversed or kept separate so it doesn't mess up the client's actual books.*"}, {"q": "Scenario: \"Parallel Simulation\". Question: The auditor writes a program to calculate depreciation and compares the result with the client's system calculation. This verifies:", "options": ["Existence.", "The accuracy of the client's software processing.", "Physical controls.", "Access controls."], "ans": 1, "exp": "Re-performing the calculation independently proves the client's system is working correctly.*"}, {"q": "Scenario: When is it most appropriate to use CAATs?", "options": ["When the volume of transactions is huge (e.g., Telecom/Banks).", "When there are only 5 invoices.", "When the auditor doesn't know how to use computers.", "When the system is manual."], "ans": 0, "exp": "CAATs are efficient for analyzing massive datasets that are impossible to check manually.*"}, {"q": "Scenario: \"Embedded Audit Facility\" (SCARF). Question: This involves:", "options": ["Visiting the client daily.", "Installing audit code inside the client's system to monitor transactions continuously.", "Checking emails.", "Hacking."], "ans": 1, "exp": "Code embedded in the live system to flag risky transactions in real-time.*\n\ud83d\udfe3 Section 4: IT Risks & Environment"}, {"q": "Scenario: The client uses a \"Real-Time Processing\" system (updates immediately). Question: What is a specific audit challenge compared to Batch Processing?", "options": ["The audit trail might be electronic only (no paper).", "It is slower.", "It is less accurate.", "It is cheaper."], "ans": 0, "exp": "Real-time systems often lack a paper trail, forcing the auditor to rely on electronic evidence and system controls.*"}, {"q": "Scenario: \"Master Files\" (Standing Data) vs \"Transaction Files\". Question: Which of the following is Master Data?", "options": ["Sales Invoice #123.", "Employee Pay Rate / Customer Credit Limit.", "Purchase Order #999.", "Journal Entry."], "ans": 1, "exp": "Master data (Standing data) is permanent info used to process transactions. Changing it (e.g., increasing pay rate) is a high fraud risk.*"}, {"q": "Scenario: If \"Master Data\" is corrupted (e.g., wrong prices in the system). Question:", "options": ["Only one invoice will be wrong.", "Every transaction processed using that data will be wrong (Systematic Error).", "The computer will stop.", "No impact."], "ans": 1, "exp": "This is why IT errors are dangerous\u2014they replicate automatically across thousands of transactions.*"}, {"q": "Scenario: \"Disaster Recovery Plan\" (DRP). Question: This is a control to ensure:", "options": ["Prevention of fraud.", "Continuity of operations in case of system failure/fire (Availability).", "Accuracy of math.", "Hiring of staff."], "ans": 1, "exp": "DRP ensures the business can survive IT failures.*"}, {"q": "Scenario: Physical Access Controls for the Server Room. Question: Which is appropriate?", "options": ["Open door policy.", "Swipe cards, biometric locks, and logs of entry.", "Only the cleaner has keys.", "Keeping servers in the canteen."], "ans": 1, "exp": "Servers hold all data; physical access must be strictly restricted.*"}, {"q": "Scenario: \"Phishing\" and \"Hacking\" are risks related to:", "options": ["Processing integrity.", "Cyber Security / Access Security.", "Input accuracy.", "Output distribution."], "ans": 1, "exp": "These attacks aim to gain unauthorized access to data.*"}, {"q": "Scenario: An auditor wants to test if the \"Backups\" are working. Question:", "options": ["Ask the IT manager.", "Observe a \"Restoration Test\" (Try to recover a file from backup).", "Look at the backup tape.", "Assume it works."], "ans": 1, "exp": "Having a backup tape means nothing if you can't restore data from it. Testing restoration is key.*\n\ud83d\udfe4 Section 5: Advanced Scenarios"}, {"q": "Scenario: \"Cloud Computing\" audit risk. Question: The client stores data on the Cloud (Third Party).", "options": ["The auditor ignores it.", "The auditor must consider the controls at the Third Party Service Organization (SOC Report).", "It is safer, so no audit needed.", "The auditor visits the cloud."], "ans": 1, "exp": "When data is outsourced (Cloud), the auditor needs assurance on the provider's controls (ISA 402).*"}, {"q": "Scenario: Using \"Live Data\" for testing vs \"Dead/Copy Data\". Question: Why do auditors prefer testing on a Copy of the database?", "options": ["It is faster.", "To avoid accidentally corrupting the client's live system.", "Live data is boring.", "Copy data has more errors."], "ans": 1, "exp": "Safety first. Messing with live data is risky.*"}, {"q": "Scenario: \"Check Digit\". Question: An account number is 12345. The last digit '5' is calculated mathematically from '1234'. If a user types 12435, the math won't work.", "options": ["This detects transposition errors.", "This detects authorized access.", "This is a General Control.", "This is an Output Control."], "ans": 0, "exp": "Check digits are classic controls for spotting typing errors (transpositions).*"}, {"q": "Scenario: The client uses an \"Off-the-Shelf\" accounting package (e.g., QuickBooks) vs \"Custom Developed\" software. Question: Which has higher risk of programming bugs?", "options": ["Off-the-Shelf (Tested by millions).", "Custom Developed (Unique, less tested).", "Both equal.", "Neither."], "ans": 1, "exp": "Custom software is riskier because it hasn't been widely tested like commercial packages.*"}, {"q": "Scenario: The auditor is reviewing the \"System Log\" (Audit Trail). Question: This log records:", "options": ["Who logged in, what time, and what actions they took.", "The electricity usage.", "Future plans.", "Employee salaries."], "ans": 0, "exp": "System logs provide the \"Detective\" trail to investigate unauthorized activities.*\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Definition & Need for an Expert"}, {"q": "Scenario: The auditor is auditing a mining company. The financial statements include a significant estimate for \"Restoration Provisions\" (cleaning up the mine). Question: The auditor does not have engineering knowledge to verify the cost. What should he do?", "options": ["Rely on management's estimate.", "Qualify the report.", "Determine the need for an Auditor's Expert (e.g., an Engineer).", "Ignore the provision."], "ans": 2, "exp": "When the auditor lacks necessary expertise in a field other than accounting/auditing (like engineering), he must determine the need for an expert.*"}, {"q": "Scenario: An \"Auditor's Expert\" is defined as:", "options": ["An individual or organization possessing expertise in accounting or auditing.", "An individual or organization possessing expertise in a field other than accounting or auditing, whose work is used by the auditor.", "A member of the engagement team with IT skills.", "The Engagement Partner."], "ans": 1, "exp": "Experts specialize in fields other than accounting/auditing (e.g., lawyers, actuaries, valuers). Accounting specialists are part of the audit team, not \"experts\" under ISA 620.*"}, {"q": "Scenario: The client hires an actuary to calculate the \"Pension Liability\". The auditor uses this report. Question: This actuary is considered:", "options": ["An Auditor's Expert.", "Management's Expert.", "An Internal Auditor.", "A Related Party."], "ans": 1, "exp": "An expert hired by management to prepare the FS is a \"Management's Expert\" (ISA 500). An \"Auditor's Expert\" is hired by the auditor to obtain evidence (ISA 620).*"}, {"q": "Scenario: Which of the following areas typically requires an Auditor's Expert?", "options": ["Calculating Depreciation using the straight-line method.", "Valuation of complex financial instruments or antiques.", "Bank Reconciliation.", "Verifying Payroll calculations."], "ans": 1, "exp": "Valuation of specialized items (antiques/complex derivatives) requires skills beyond standard auditing.*"}, {"q": "Scenario: The auditor has a tax specialist within his own firm (an employee) who assists with complex tax assets. Question: This person is considered:", "options": ["An Auditor\u2019s External Expert.", "An Auditor\u2019s Internal Expert.", "Management\u2019s Expert.", "Not an expert."], "ans": 1, "exp": "An expert who is a partner/staff of the audit firm is an \"Internal Expert\". One hired from outside is an \"External Expert\".*\n\ud83d\udd35 Section 2: Evaluating the Expert"}, {"q": "Scenario: Before using the work of an Auditor's Expert, the auditor must evaluate:", "options": ["The expert\u2019s bank balance.", "The expert\u2019s Competence, Capabilities, and Objectivity.", "The expert\u2019s political views.", "The expert\u2019s age."], "ans": 1, "exp": "ISA 620 mandates evaluating Competence (skills), Capabilities (resources/time), and Objectivity (independence).*"}, {"q": "Scenario: The auditor hires an External Valuer who is the brother of the Client\u2019s CFO. Question:", "options": ["This affects Competence.", "This affects Objectivity (Independence threat).", "This is acceptable.", "This affects Capabilities."], "ans": 1, "exp": "Close relationships with the client compromise the expert's Objectivity. The auditor likely cannot rely on them.*"}, {"q": "Scenario: How can an auditor evaluate the \"Competence\" of an external expert?", "options": ["Check their professional certification (e.g., Member of Actuarial Society).", "Check their reputation and experience in the industry.", "Look at their published papers or books.", "All of the above."], "ans": 3, "exp": "Credentials, experience, and reputation are all valid indicators of competence.*"}, {"q": "Scenario: \"Capabilities\" refers to:", "options": ["The expert's intelligence.", "The ability to perform the work (e.g., having enough staff, time, and resources).", "The expert's honesty.", "The expert's location."], "ans": 1, "exp": "Even a competent expert is useless if they don't have the time or resources (Capabilities) to do the job.*"}, {"q": "Scenario: Does the auditor need to inquire about \"Objectivity\" for an Internal Expert (firm employee)?", "options": ["No, they are already subject to the firm's quality control and independence rules.", "Yes, always.", "Only if they are new.", "Only if the client asks."], "ans": 0, "exp": "Internal experts are bound by the firm's ethical rules (ISA 220). The auditor relies on the firm's system. For External experts, specific inquiry is needed.*\n\ud83d\udfe0 Section 3: Agreement & Procedures"}, {"q": "Scenario: The auditor must agree on terms with the Auditor's Expert. This agreement should be:", "options": ["Verbal.", "In writing (Engagement Letter).", "Implied.", "Optional."], "ans": 1, "exp": "To avoid misunderstandings, the agreement (scope, objectives, confidentiality, roles) should be in writing.*"}, {"q": "Scenario: The agreement with the expert must cover:", "options": ["The nature, scope, and objectives of the work.", "The respective roles and responsibilities.", "Confidentiality requirements.", "All of the above."], "ans": 3, "exp": "These are the core elements of the engagement agreement with an expert.*"}, {"q": "Scenario: Can the auditor share confidential client information with the Auditor's Expert?", "options": ["No, never.", "Yes, but the expert must be bound by confidentiality (usually via the agreement).", "Only if the client approves in writing.", "Only if the expert is internal."], "ans": 1, "exp": "The expert needs data to do their job. Confidentiality clauses ensure they protect it.*"}, {"q": "Scenario: The expert produces a report. Question: What is the auditor's responsibility regarding this report?", "options": ["File it and accept it as true.", "Evaluate the adequacy of the expert's work for the auditor's purposes.", "Copy it into the audit report.", "Send it to the shareholders."], "ans": 1, "exp": "The auditor cannot blindly trust the expert. They must evaluate if the assumptions, methods, and data used are reasonable.*"}, {"q": "Scenario: How does the auditor test the \"Source Data\" used by the expert (e.g., the list of assets given to the valuer)?", "options": ["The auditor relies on the expert to check it.", "The auditor checks the completeness and accuracy of the source data provided to the expert.", "The auditor ignores it.", "The auditor asks management."], "ans": 1, "exp": "The expert is not an auditor. The auditor must verify that the raw data given to the expert (e.g., \"List of 50 properties\") matches the company records.*"}, {"q": "Scenario: The expert uses a valuation method that is significantly different from industry standards. Question:", "options": ["Accept it, they are the expert.", "Challenge the expert and ask for justification.", "Withdraw.", "Ignore."], "ans": 1, "exp": "The auditor must evaluate the \"Relevance and Reasonableness\" of assumptions and methods. Significant deviations must be questioned.*"}, {"q": "Scenario: If the expert's work is not adequate and the issue cannot be resolved (e.g., expert refuses to redo it). Question:", "options": ["Rely on it anyway.", "Perform additional audit procedures yourself or hire another expert.", "Issue a clean opinion.", "Sue the expert."], "ans": 1, "exp": "If the evidence is bad, you must find other evidence (another expert) or qualify the opinion.*\n\ud83d\udfe3 Section 4: Reporting & Responsibility"}, {"q": "Scenario: Who is responsible for the Audit Opinion when an expert is used?", "options": ["The Auditor only (Sole Responsibility).", "The Expert only.", "Joint Responsibility.", "Management."], "ans": 0, "exp": "The use of an expert does NOT reduce the auditor's responsibility. The opinion is solely the auditor's.*"}, {"q": "Scenario: The auditor issues an Unmodified Opinion. Question: Can the auditor refer to the Expert in the audit report?", "options": ["Yes, to show they did a good job.", "No, the auditor should not refer to the expert in an unmodified report (unless law requires it).", "Yes, if the expert is famous.", "Yes, in the Key Audit Matters section only."], "ans": 1, "exp": "Referring to an expert in a clean report might suggest a division of responsibility. It is generally prohibited unless required by law.*"}, {"q": "Scenario: The auditor issues a Modified Opinion (e.g., Qualified) because of the expert's findings (e.g., Valuer found a huge impairment). Question: Can the auditor refer to the expert in the report?", "options": ["No.", "Yes, if it is relevant to understanding the modification.", "Yes, but the auditor must blame the expert.", "Only if the expert pays."], "ans": 1, "exp": "In a modified report, referring to the expert helps explain the reason for the modification. However, the auditor must confirm that this does not reduce their responsibility.*"}, {"q": "Scenario: If the auditor refers to the expert in the report (due to modification), what must be stated?", "options": ["That the expert is liable.", "That the reference does not reduce the auditor's responsibility for the opinion.", "The expert's phone number.", "The expert's fee."], "ans": 1, "exp": "It is crucial to clarify that the \"Buck stops with the Auditor.\"*"}, {"q": "Scenario: An auditor blindly accepts an expert\u2019s report which contains obvious errors (e.g., mathematical mistakes). Question:", "options": ["The auditor is negligent.", "The auditor is protected because he is not an expert.", "The expert is liable.", "No one is liable."], "ans": 0, "exp": "The auditor must perform \"Work on the Expert's Work\" (check math, logic). Blind reliance is negligence.*\n\ud83d\udfe4 Section 5: Management's Expert (ISA 500)"}, {"q": "Scenario: Management hires an expert to value inventory. The auditor wants to rely on this valuation. Question: Which ISA applies?", "options": ["ISA 620.", "ISA 500 (Audit Evidence).", "ISA 210.", "ISA 240."], "ans": 1, "exp": "Using the work of a Management's Expert falls under ISA 500. ISA 620 is for Auditor's Expert.*"}, {"q": "Scenario: When using a Management's Expert, the auditor must:", "options": ["Evaluate Competence, Capabilities, and Objectivity.", "Obtain an understanding of their work.", "Evaluate the appropriateness of their work.", "All of the above."], "ans": 3, "exp": "The steps are similar to ISA 620: Is the management's guy competent? Is his work good?*"}, {"q": "Scenario: Management's Expert acts as an advocate for the client (e.g., trying to minimize tax). Question:", "options": ["This is a threat to Objectivity. The auditor must be cautious.", "This is fine.", "The auditor cannot use their work.", "The auditor should ignore it."], "ans": 0, "exp": "Management experts are less independent than Auditor's experts. The risk of bias is higher.*\n\u26ab Section 6: Tricky Scenarios"}, {"q": "Scenario: The auditor hires an expert to count inventory (simple counting). Question: Is this an \"Auditor's Expert\" under ISA 620?", "options": ["Yes.", "No, because counting does not require specialized expertise in a field other than accounting/auditing.", "Yes, if they are expensive.", "Yes, if the inventory is gold."], "ans": 1, "exp": "ISA 620 applies to fields other than accounting/auditing. Simple counting is part of standard auditing, so it's just \"Staff\", not \"Expert\".*"}, {"q": "Scenario: The expert assumes a 10% growth rate for valuation, but the historical growth is only 2%. Question: The auditor should:", "options": ["Accept it.", "Challenge the assumption as unreasonable.", "Qualify.", "Resign."], "ans": 1, "exp": "Evaluating \"Reasonableness of Assumptions\" is a key auditor duty.*"}, {"q": "Scenario: Independence of an External Auditor's Expert. Question:", "options": ["They must be independent of the client.", "They must be independent of the auditor.", "They don't need to be independent.", "They must be independent of both."], "ans": 0, "exp": "The expert helps the auditor audit the client. Therefore, the expert must not be connected to the client.*"}, {"q": "Scenario: If an expert is required but the client refuses to pay for one. Question:", "options": ["The auditor performs the work himself (if competent) or qualifies the opinion (Scope Limitation).", "The auditor pays from his own pocket.", "The auditor ignores the area.", "The auditor uses management's guess."], "ans": 0, "exp": "Inability to get expert evidence when needed is a Scope Limitation.*"}, {"q": "Scenario: Before starting, the auditor discusses confidentiality with the expert. The expert refuses to sign a confidentiality agreement. Question:", "options": ["Proceed anyway.", "Do not hire that expert.", "Hire them but don't give data.", "Ask client."], "ans": 1, "exp": "You cannot expose client data to someone who won't promise to keep it secret.*\n\ud83e\udde0 \n\ud83d\udfe2 Section 1: Appointment of Auditors"}, {"q": "Scenario: A new company \"Tech Solutions Ltd\" was incorporated on 1 January 2024. The directors appointed the first auditor on 1 March 2024. Question: Is this appointment valid?", "options": ["No, the first auditor must be appointed by shareholders.", "Yes, the Board of Directors appoints the first auditor within 90 days of incorporation.", "No, the appointment must be within 30 days.", "No, the SECP appoints the first auditor."], "ans": 1, "exp": "The first auditor is appointed by the Board within 90 days of incorporation. If they fail, the SECP appoints.*"}, {"q": "Scenario: The tenure of the First Auditor of a company expires at:", "options": ["The end of the financial year.", "The conclusion of the First Annual General Meeting (AGM).", "After 1 year.", "When the directors decide."], "ans": 1, "exp": "The first auditor holds office until the conclusion of the first AGM.*"}, {"q": "Scenario: At an AGM, the shareholders appointed Mr. A as the auditor. However, Mr. A did not give his Consent in writing. Question:", "options": ["The appointment is valid.", "The appointment is void because written consent is mandatory.", "The appointment is valid if he accepts later.", "The SECP will decide."], "ans": 1, "exp": "A written consent from the auditor is a mandatory precondition for appointment.*"}, {"q": "Scenario: \"Casual Vacancy\" (e.g., auditor dies). Who fills it?", "options": ["The Shareholders at an EGM.", "The Directors, within 30 days.", "The SECP.", "The surviving partners automatically."], "ans": 1, "exp": "The Board of Directors has the power to fill a casual vacancy. The surviving partners can continue acting, but if a vacancy needs filling, the Board does it.*"}, {"q": "Scenario: If the Board fails to appoint the first auditor within 90 days, who has the power to appoint?", "options": ["The Shareholders.", "The Commission (SECP).", "The Court.", "The Institute of Chartered Accountants of Pakistan (ICAP)."], "ans": 1, "exp": "If the company fails to appoint, the SECP steps in.*\n\ud83d\udd35 Section 2: Qualification & Disqualification"}, {"q": "Scenario: Mr. X is a Chartered Accountant. His spouse holds shares in \"ABC Ltd\". Question: Can Mr. X be appointed as the auditor of ABC Ltd?", "options": ["Yes, if he discloses the interest.", "No, unless the spouse sells the shares within 90 days of appointment.", "Yes, spouses are separate legal persons.", "No, strictly prohibited."], "ans": 1, "exp": "A person is disqualified if their spouse holds shares, unless the shares are disclosed at the time of appointment and disposed of within 90 days.*"}, {"q": "Scenario: Mr. Y owes Rs. 1 million to a credit card company (Bank) which is an audit client. Question: Is he disqualified?", "options": ["Yes, indebtedness > Rs. 500,000 disqualifies him.", "No, credit card debt up to Rs. 1 million (or as prescribed) is exempted if in the ordinary course of business.", "Yes, all debts disqualify.", "No, limits don't apply to banks."], "ans": 1, "exp": "Ordinary course business debts (like utilities/credit cards) have exemptions/limits. Indebtedness generally disqualifies, but credit cards have a specific threshold.*"}, {"q": "Scenario: A \"Private Company\" with paid-up capital of Rs. 1 million wants to appoint a Cost and Management Accountant (CM", "options": ["as its external auditor. Question: A) Allowed, if capital is < Rs. 3 million.", "Not allowed, only CAs can audit.", "Allowed for all private companies.", "Prohibited."], "ans": 0, "exp": "For private companies with paid-up capital less than Rs. 3 million, a CMA can be the auditor. For larger/public companies, it must be a CA.*"}, {"q": "Scenario: Mr. Z provided a \"Guarantee\" for a loan taken by the Director of the company. Question: Is Mr. Z disqualified from being the auditor?", "options": ["Yes, giving a guarantee for the company's officer disqualifies him.", "No, only taking a loan disqualifies.", "Yes, but only if the loan is > 1 million.", "No."], "ans": 0, "exp": "A person who has given a guarantee for the company or its officers is disqualified.*"}, {"q": "Scenario: An auditor is disqualified during his tenure (e.g., buys shares). Question: What happens?", "options": ["He can finish the current audit.", "He immediately vacates the office (Automatic Vacation).", "He must inform SECP.", "He pays a fine."], "ans": 1, "exp": "Disqualification results in immediate vacation of office.*\n\ud83d\udfe0 Section 3: Removal & Change of Auditor"}, {"q": "Scenario: The Directors want to remove the auditor before the expiry of his term because he is asking too many questions. Question: Can they do it?", "options": ["Yes, Directors can remove the auditor anytime.", "No, only Shareholders can remove an auditor before term expiry, via a Special Resolution.", "Yes, with SECP permission.", "No, once appointed, he stays for 5 years."], "ans": 1, "exp": "Removal before term requires a Special Resolution by members (Shareholders) to protect auditor independence.*"}, {"q": "Scenario: A shareholder wants to propose a new auditor at the AGM to replace the retiring auditor. Question: Notice of such a proposal must be sent to the company at least:", "options": ["14 days before AGM.", "7 days before AGM.", "21 days before AGM.", "30 days before AGM."], "ans": 1, "exp": "Notice for a change of auditor must be given by a shareholder holding at least 10% shares, 7 days before the meeting.*"}, {"q": "Scenario: If a new auditor is proposed, the retiring auditor has the right to:", "options": ["Stop the meeting.", "Make a written representation to be read at the AGM.", "Demand compensation.", "Sue the shareholder."], "ans": 1, "exp": "The retiring auditor has the right to defend themselves via a representation read out to members.*\n\ud83d\udfe3 Section 4: Powers & Duties"}, {"q": "Scenario: The auditor wants to inspect the books of a \"Foreign Branch\" of the company. Question:", "options": ["Not allowed.", "Allowed, the auditor has a right of access to all books and vouchers, wherever kept.", "Only if the branch manager agrees.", "Only if the SECP permits."], "ans": 1, "exp": "The auditor has a statutory right of access to all books at all times.*"}, {"q": "Scenario: The auditor is required to report if \"Zakat\" has been deducted. Question: This requirement comes from:", "options": ["IFRS.", "Companies Act 2017 / Zakat and Ushr Ordinance.", "ISA 700.", "Code of Ethics."], "ans": 1, "exp": "It is a specific local law requirement in Pakistan to report on Zakat deduction.*"}, {"q": "Scenario: Can the auditor attend the General Meeting (AGM)?", "options": ["No, it's for shareholders.", "Yes, the auditor is entitled to receive notice and attend any general meeting.", "Only if invited.", "Only if reporting fraud."], "ans": 1, "exp": "Auditors have a right to attend general meetings concerning them (FS presentation).*\n\ud83d\udfe4 Section 5: Specific Prohibitions"}, {"q": "Scenario: Can a \"Body Corporate\" (e.g., a Pvt Ltd company) be appointed as an auditor?", "options": ["Yes.", "No, only individuals or partnership firms can be auditors.", "Yes, if SECP allows.", "Yes, in UK but not Pakistan."], "ans": 1, "exp": "Body corporates are disqualified from being auditors to ensure personal liability.*"}, {"q": "Scenario: An employee of the company acts as the auditor. Question:", "options": ["Allowed.", "Disqualified (Officer or Employee is disqualified).", "Allowed if unpaid.", "Allowed for subsidiaries."], "ans": 1, "exp": "Employees lack independence.*"}, {"q": "Scenario: A person who is a partner of an employee of the company. Question:", "options": ["Allowed.", "Disqualified.", "Allowed if disclosed.", "Allowed if the employee is junior."], "ans": 1, "exp": "Being a partner of an employee/officer disqualifies you.*"}, {"q": "Scenario: Audit of a Listed Company. Question: Who signs the report?", "options": ["Any partner.", "The Engagement Partner (with his name) and the Firm's name.", "The Manager.", "The CEO."], "ans": 1, "exp": "For listed companies, the report must state the name of the engagement partner and the firm.*"}];